window.PACTO.acts["reg-2018-1240"]={"label": "REGOLAMENTO (UE) 2018/1240 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2018/1240", "file": "ext-reg-2018-1240.html", "external": true, "version": "consolidato 2025-11-18", "eurlex": "https://eur-lex.europa.eu/eli/reg/2018/1240/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente regolamento istituisce un sistema europeo di informazione e autorizzazione ai viaggi (ETIAS) per i cittadini di paesi terzi esenti dall’obbligo di possedere un visto al momento dell’attraversamento delle frontiere esterne («obbligo di visto») che permette di valutare se la presenza di tali cittadini di paesi terzi nel territorio degli Stati membri rappresenti un rischio per la sicurezza, di immigrazione illegale o un alto rischio epidemico. A questo scopo sono introdotte un’autorizzazione ai viaggi e le condizioni e procedure per il suo rilascio o rifiuto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il presente regolamento definisce le condizioni alle quali le autorità designate degli Stati membri ed Europol possono consultare i dati conservati nel sistema centrale ETIAS a fini di prevenzione, accertamento e indagine di reati di terrorismo o altri reati gravi di loro competenza.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Conservando i dati di identità e i dati del documento di viaggio nell'archivio comune di dati di identità (CIR) istituito dall'articolo 17, paragrafo 1, del regolamento (UE) 2019/817 (\n<span class=\"superscript\">1</span>\n), ETIAS concorre ad agevolare e contribuire alla corretta identificazione delle persone registrate nell'ETIAS alle condizioni e per gli obiettivi di cui all'articolo 20 di tale regolamento.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "2": {"label": "Articolo 2", "heading": "Ambito di applicazione", "anchor": "art_2", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il presente regolamento si applica alle categorie seguenti di cittadini di paesi terzi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i cittadini dei paesi terzi elencati nell’allegato II del regolamento (CE) n. 539/2001 (\n<span class=\"superscript\">2</span>\n) del Consiglio che sono esenti dall’obbligo di visto per soggiorni previsti sul territorio degli Stati membri la cui durata non sia superiore a 90 giorni su un periodo di 180 giorni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le persone che sono esenti dall’obbligo di visto in virtù dell’articolo 4, paragrafo 2, del regolamento (CE) n. 539/2001 per soggiorni previsti sul territorio degli Stati membri la cui durata non sia superiore a 90 giorni su un periodo di 180 giorni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i cittadini di paesi terzi che sono esenti dall’obbligo di visto e che soddisfano le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono familiari di un cittadino dell’Unione ai quali si applica la direttiva 2004/38/CE o di un cittadino di paese terzo che gode di un diritto di libera circolazione equivalente a quello dei cittadini dell’Unione in virtù di un accordo concluso tra l’Unione e i suoi Stati membri, da una parte, e un paese terzo, dall’altra; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non sono titolari della carta di soggiorno ai sensi della direttiva 2004/38/CE o di un permesso di soggiorno ai sensi del regolamento (CE) n. 1030/2002.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il presente regolamento non si applica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a rifugiati, apolidi e altre persone che non possiedono la cittadinanza di alcun paese che risiedono in uno Stato membro e sono titolari di un documento di viaggio rilasciato da tale Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai cittadini di paesi terzi familiari di un cittadino dell’Unione ai quali si applica la direttiva 2004/38/CE e che sono titolari della carta di soggiorno di cui alla medesima direttiva;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai cittadini di paesi terzi familiari di un cittadino di paese terzo che gode di un diritto di libera circolazione equivalente a quello dei cittadini dell’Unione in virtù di un accordo concluso tra l’Unione e i suoi Stati membri, da una parte, e un paese terzo, dall’altra, e che sono titolari della carta di soggiorno di cui alla direttiva 2004/38/CE o di un permesso di soggiorno ai sensi del regolamento (CE) n. 1030/2002;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai titolari del permesso di soggiorno di cui all’articolo 2, punto 16, del regolamento (UE) 2016/399;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai titolari di visto uniforme;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai titolari di visto nazionale per soggiorno di lunga durata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai cittadini di Andorra, Monaco e San Marino e ai titolari di un passaporto rilasciato dallo Stato della Città del Vaticano o dalla Santa Sede;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai cittadini di paesi terzi titolari di un lasciapassare per traffico frontaliero locale rilasciato dagli Stati membri in virtù del regolamento (CE) n. 1931/2006 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">3</span>\n), allorché esercitano il loro diritto nell’ambito di un regime di traffico frontaliero locale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle persone o alle categorie di persone di cui all’articolo 4, paragrafo 1, lettere da a) a f), del regolamento (CE) n. 539/2001;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai cittadini di paesi terzi titolari di passaporti diplomatici o di servizio esenti dall’obbligo del visto in virtù di un accordo internazionale concluso tra l’Unione e un paese terzo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle persone sottoposte all’obbligo di visto a norma dell’articolo 4, paragrafo 3, del regolamento (CE) n. 539/2001;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai cittadini di paesi terzi che esercitano il diritto alla mobilità ai sensi della direttiva 2014/66/UE (\n<span class=\"superscript\">4</span>\n) o della direttiva (UE) 2016/801 (\n<span class=\"superscript\">5</span>\n).</p>\n</div>\n</div>\n</div>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Definizioni", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini del presente regolamento si intende per:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">1)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«frontiere esterne» : le frontiere esterne quali definite all’articolo 2, punto 2, del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">2)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«contrasto» : la prevenzione, l’accertamento o l’indagine di reati di terrorismo o di altri reati gravi;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">3)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«verifica in seconda linea» : una verifica in seconda linea quale definita all’articolo 2, punto 13, del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">4)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«autorità di frontiera» : la guardia di frontiera incaricata, conformemente al diritto nazionale, di effettuare verifiche di frontiera ai sensi dell’articolo 2, punto 11, del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">5)</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">«autorizzazione ai viaggi» : </p>\n<p class=\"norm\">una decisione adottata in virtù del presente regolamento affinché i cittadini di paesi terzi di cui all’articolo 2, paragrafo 1, del presente regolamento, soddisfino la condizione d’ingresso di cui all’articolo 6, paragrafo 1, lettera b), del regolamento (UE) 2016/399 e che attesta che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non sono stati individuati indicazioni concrete o fondati motivi basati su indicazioni concrete per ritenere che la presenza della persona nel territorio degli Stati membri presenti o presenterà un rischio per la sicurezza, di immigrazione illegale o un alto rischio epidemico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non sono stati individuati indicazioni concrete o fondati motivi basati su indicazioni concrete per ritenere che la presenza della persona nel territorio degli Stati membri presenti o presenterà un rischio per la sicurezza, di immigrazione illegale o un alto rischio epidemico, anche se persistono dubbi sull’esistenza di motivi sufficienti per rifiutare l’autorizzazione ai viaggi, conformemente all’articolo 36, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso in cui siano state individuate indicazioni concrete per ritenere che la presenza della persona nel territorio degli Stati membri presenti o presenterà un rischio per la sicurezza, di immigrazione illegale o un alto rischio epidemico, la validità territoriale dell’autorizzazione è stata limitata conformemente all’articolo 44; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso in cui siano state individuate indicazioni concrete per ritenere che la presenza della persona nel territorio degli Stati membri presenti o presenterà un rischio per la sicurezza, il viaggiatore è oggetto di una segnalazione nel SIS relativa a persone da sottoporre a controllo discreto o controllo specifico oppure di una segnalazione nel SIS relativa a persone ricercate per l’arresto a fini di consegna sulla base di un mandato d’arresto europeo o ricercate per l’arresto a fini di estradizione, a sostegno degli obiettivi del SIS di cui all’articolo 4, lettera e);</p>\n</div>\n</div>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">6)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«rischio per la sicurezza» : un rischio di minaccia per l’ordine pubblico, la sicurezza interna o le relazioni internazionali di uno degli Stati membri;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">7)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«rischio di immigrazione illegale» : il rischio che un cittadino di paese terzo non soddisfi le condizioni d’ingresso e di soggiorno di cui all’articolo 6 del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">8)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«alto rischio epidemico» : qualunque malattia con potenziale epidemico ai sensi dei regolamenti sanitari internazionali dell’Organizzazione mondiale della sanità (OMS) o del Centro europeo per la prevenzione e il controllo delle malattie (ECDC), nonché altre malattie infettive o parassitarie contagiose, sempreché siano oggetto di disposizioni di protezione che si applicano ai cittadini degli Stati membri;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">9)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«richiedente» : il cittadino di paese terzo di cui all’articolo 2 che ha presentato una domanda di autorizzazione ai viaggi;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">10)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«documento di viaggio» : il passaporto o altro documento equivalente che autorizza il titolare ad attraversare le frontiere esterne e sul quale può essere apposto un visto;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">11)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«soggiorno di breve durata» : il soggiorno nel territorio degli Stati membri ai sensi dell’articolo 6, paragrafo 1, del regolamento (UE) 2016/399;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">12)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«soggiornante fuoritermine» : il cittadino di paese terzo che non soddisfa o non soddisfa più le condizioni relative alla durata del soggiorno di breve durata nel territorio degli Stati membri;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">13)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«applicazione per dispositivi mobili» : un’applicazione software concepita per funzionare su dispositivi mobili quali smartphone e tablet;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">14)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«riscontro positivo» : la corrispondenza constatata confrontando i dati personali del fascicolo di domanda registrati nel sistema centrale ETIAS con gli indicatori di rischio specifici di cui all’articolo 33 oppure con i dati personali presenti in una cartella, un fascicolo o una segnalazione presente nel sistema centrale ETIAS, in un altro sistema d’informazione dell’UE o in una banca dati elencata all’articolo 20, paragrafo 2 («sistemi d’informazione UE»), nei dati Europol o in una banca dati Interpol interrogati dal sistema centrale ETIAS;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">15)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«reati di terrorismo» : i reati che corrispondono o sono equivalenti a quelli di cui alla direttiva (UE) 2017/541;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">16)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«reati gravi» : i reati che corrispondono o sono equivalenti a quelli di cui all’articolo 2, paragrafo 2, della decisione quadro 2002/584/GAI, se punibili a norma del diritto nazionale con una pena detentiva o una misura di sicurezza privativa della libertà personale per un periodo massimo di almeno tre anni;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">17)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«dati Europol» : i dati personali trattati da Europol per la finalità di cui all’articolo 18, paragrafo 2, lettera a), del regolamento (UE) 2016/794;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">18)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«firmato elettronicamente» : la conferma dell’accordo tramite barratura dell’apposita casella nel modulo di domanda o nella richiesta di consenso;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">19)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«minore» : il cittadino di paese terzo o l’apolide di età inferiore ai diciotto anni;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">20)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«consolato» : la rappresentanza diplomatica o consolare di uno Stato membro quale definita dalla convenzione di Vienna sulle relazioni consolari del 24 aprile 1963;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">21)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«autorità designata» : l’autorità designata da uno Stato membro ai sensi dell’articolo 50, responsabile della prevenzione, dell’accertamento o dell’indagine di reati di terrorismo o altri reati gravi;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">22)</p>\n</td>\n<td valign=\"top\">\n<p class=\"normal\">«autorità competente in materia di immigrazione» : </p>\n<p class=\"norm\">l’autorità competente responsabile, conformemente alla legislazione nazionale, di uno o più dei compiti seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verificare all’interno del territorio degli Stati membri se siano soddisfatte le condizioni di ingresso o di soggiorno nel territorio degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esaminare le condizioni di residenza dei cittadini di paesi terzi nel territorio degli Stati membri e adottare le relative decisioni - nella misura in cui tale autorità non costituisca un’«autorità accertante» ai sensi dell’articolo 2, lettera f), della direttiva 2013/32/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">6</span>\n) – nonché, se del caso, fornire consulenza conformemente al regolamento (CE) n. 377/2004 del Consiglio (\n<span class=\"superscript\">7</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il ritorno dei cittadini di paesi terzi in un paese terzo di origine o di transito;</p>\n</div>\n</div>\n</td>\n</tr>\n</table>\n<p class=\"modref\">\n▼M1\n</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">23)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«CIR» : l'archivio comune di dati di identità istituito dall'articolo 17, paragrafo 1, del regolamento (UE) 2019/817;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">24)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«ESP» : il portale di ricerca europeo istituito dall'articolo 6, paragrafo 1, del regolamento (UE) 2019/817;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">25)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«sistema centrale ETIAS» : il sistema centrale di cui all'articolo 6, paragrafo 2, lettera a), unitamente al CIR, nella misura in cui questo contiene i dati di cui all'articolo 6, paragrafo 2 <span class=\"italics\">bis</span>;</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">26)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«dati di identità» : i dati di cui all'articolo 17, paragrafo 2, lettere a) b) e c);</p>\n</td>\n</tr>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">27)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«dati del documento di viaggio» : i dati di cui all'articolo 17, paragrafo 2, lettere d) ed e), e il codice a tre lettere del paese di rilascio del documento di viaggio di cui all'articolo 19, paragrafo 3, lettera c);</p>\n</td>\n</tr>\n</table>\n<p class=\"modref\">\n▼M2\n</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"5%\"/>\n<col width=\"95%\"/>\n<tr>\n<td valign=\"top\">\n<p class=\"dlist-term\">28)</p>\n</td>\n<td valign=\"top\">\n<p class=\"dlist-definition\">«altri sistemi d’informazione dell’UE» : il sistema di ingressi/uscite (EES), istituito dal regolamento (UE) 2017/2226, il sistema di informazione visti (VIS), istituito dal regolamento (CE) n. 767/2008 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">8</span>\n), il sistema d’informazione Schengen (SIS), istituito dai regolamenti (UE) 2018/1860 (\n<span class=\"superscript\">9</span>\n), (UE) 2018/1861 (\n<span class=\"superscript\">10</span>\n) e (UE) 2018/1862 (\n<span class=\"superscript\">11</span>\n) del Parlamento europeo e del Consiglio, Eurodac, istituito dal regolamento (UE) n. 603/2013 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">12</span>\n) e il sistema europeo di informazione sui casellari giudiziali riguardo ai cittadini di paesi terzi (sistema ECRIS-TCN), istituito dal regolamento (UE) 2019/816 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">13</span>\n).</p>\n</td>\n</tr>\n</table>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nella misura in cui i dati personali siano trattati dall’Agenzia europea della guardia di frontiera e costiera e da eu-LISA, i termini definiti all’articolo 2 del regolamento (CE) n. 45/2001 hanno lo stesso significato nel presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nella misura in cui i dati personali siano trattati dalle autorità degli Stati membri per le finalità di cui all’articolo 4, lettere da a) a e), del presente regolamento, i termini definiti all’articolo 4 del regolamento (UE) 2016/679 hanno lo stesso significato nel presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nella misura in cui i dati personali siano trattati dalle autorità degli Stati membri per le finalità di cui all’articolo 4, lettera f), del presente regolamento, i termini definiti all’articolo 3 della direttiva (UE) 2016/680 hanno lo stesso significato nel presente regolamento.</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Obiettivi dell’ETIAS", "anchor": "art_4", "frags": [[null, "<p class=\"norm\">Assistendo le autorità competenti degli Stati membri, l’ETIAS:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contribuisce a un elevato livello di sicurezza permettendo una valutazione approfondita del rischio per la sicurezza presentato dai richiedenti prima del loro arrivo ai valichi di frontiera esterni, onde determinare se vi siano indicazioni concrete o fondati motivi basati su indicazioni concrete per concludere che la presenza di una persona nel territorio degli Stati membri presenta un rischio per la sicurezza;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contribuisce a prevenire l’immigrazione illegale svolgendo una valutazione del rischio di immigrazione illegale presentato dai richiedenti prima del loro arrivo ai valichi di frontiera esterni;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contribuisce a proteggere la salute pubblica valutando se il richiedente presenti un alto rischio epidemico ai sensi dell’articolo 3, paragrafo 1, punto 8), prima del suo arrivo ai valichi di frontiera esterni;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rafforza l’efficacia delle verifiche di frontiera;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostiene gli obiettivi del SIS relativi alle segnalazioni di cittadini di paesi terzi ai fini del rifiuto d’ingresso e soggiorno, segnalazioni di persone ricercate per l’arresto o a fini di consegna o di estradizione, segnalazioni di persone scomparse, segnalazioni di persone ricercate nell’ambito di un procedimento giudiziario, segnalazioni di persone da sottoporre a controllo discreto o controllo specifico e segnalazioni di cittadini di paesi terzi oggetto di una decisione di rimpatrio;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e bis) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostiene gli obiettivi dell’EES;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contribuisce alla prevenzione, all’accertamento e all’indagine di reati di terrorismo o altri reati gravi;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contribuisce alla corretta identificazione delle persone.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "5": {"label": "Articolo 5", "heading": "Struttura generale dell’ETIAS", "anchor": "art_5", "frags": [[null, "<p class=\"norm\">L’ETIAS consta degli elementi seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il sistema d’informazione ETIAS di cui all’articolo 6;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’unità centrale ETIAS di cui all’articolo 7;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le unità nazionali ETIAS di cui all’articolo 8.</p>\n</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Istituzione e architettura tecnica del sistema d’informazione ETIAS", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia europea per la gestione operativa dei sistemi IT su larga scala nello spazio di libertà, sicurezza e giustizia («eu-LISA») sviluppa il sistema d’informazione ETIAS e provvede alla sua gestione tecnica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il sistema d’informazione ETIAS è composto da:</p>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un sistema centrale, compreso l'elenco di controllo ETIAS di cui all'articolo 34;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a <span class=\"italics\">bis</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il CIR;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’interfaccia uniforme nazionale (NUI) in ciascuno Stato membro, basata su specifiche tecniche comuni e identica in tutti gli Stati membri, che consente la connessione del sistema centrale ETIAS alle infrastrutture nazionali di frontiera e ai punti di accesso centrale negli Stati membri di cui all’articolo 50, paragrafo 2, in maniera sicura;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’infrastruttura di comunicazione tra il sistema centrale ETIAS e le NUI sicura e criptata;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un'infrastruttura di comunicazione sicura tra il sistema centrale e le infrastrutture centrali dell'ESP e del CIR;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d bis) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un canale di comunicazione sicuro tra il sistema centrale ETIAS e il sistema centrale dell’EES;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un sito web pubblico e un’applicazione per dispositivi mobili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un servizio di posta elettronica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un servizio di account sicuro che permette ai richiedenti di fornire le informazioni o i documenti aggiuntivi richiesti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">uno strumento di verifica per i richiedenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">uno strumento che permette ai richiedenti di prestare o revocare il consenso a un ulteriore periodo di conservazione del loro fascicolo di domanda;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">uno strumento che consente a Europol e agli Stati membri di valutare il potenziale impatto dell’introduzione di nuovi dati nell’elenco di controllo ETIAS sulla parte di domande trattate manualmente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un portale per i vettori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un servizio web sicuro che permette al sistema centrale ETIAS di comunicare con il sito web pubblico, l’applicazione per dispositivi mobili, il servizio di posta elettronica, il servizio di account sicuro, il portale per i vettori, lo strumento di verifica per i richiedenti, lo strumento di consenso per i richiedenti, l’intermediario di servizi di pagamento e i le banche dati di Interpol;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un software che consente all’unità centrale ETIAS e alle unità nazionali ETIAS di trattare le domande e di gestire la consultazione con altre unità nazionali ETIAS di cui all’articolo 28 e quella con Europol di cui all’articolo 29;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un archivio centrale di dati ai fini dell’elaborazione di relazioni e statistiche.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Il CIR contiene i dati di identità e i dati del documento di viaggio. I rimanenti dati sono conservati nel sistema centrale.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il sistema centrale ETIAS, le NUI, il servizio web, il portale per i vettori e l’infrastruttura di comunicazione dell’ETIAS condividono e riutilizzano, nella massima misura tecnicamente possibile, i componenti hardware e software, rispettivamente, del sistema centrale dell’EES, delle interfacce uniformi dell’EES, del servizio web dell’EES e dell’infrastruttura di comunicazione dell’EES di cui al regolamento (UE) 2017/2226.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti delegati conformemente all’articolo 89 per definire i requisiti del servizio di account sicuro di cui al paragrafo 2, lettera g) del presente articolo.</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Unità centrale ETIAS", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È istituita un’unità centrale ETIAS nell’ambito dell’Agenzia europea della guardia di frontiera e costiera.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’unità centrale ETIAS è operativa 24 ore al giorno, sette giorni su sette. Essa svolge i compiti seguenti:</p>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">laddove dal trattamento automatizzato della domanda emerga un riscontro positivo, verifica a norma dell’articolo 22, se i dati personali del richiedente corrispondono ai dati personali della persona per cui è emerso tale riscontro positivo nel sistema centrale ETIAS, in uno dei sistemi d’informazione UE consultati, nei dati Europol, in una delle banche dati Interpol di cui all’articolo 12, o agli indicatori di rischio specifici di cui all’articolo 33 oggetto di consultazione e, nel caso in cui una corrispondenza sia confermata o a seguito di tale verifica persistano dubbi, avvia il trattamento manuale della domanda di cui all’articolo 26;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvede affinché i dati da essa inseriti nei fascicoli di domanda siano aggiornati in conformità delle pertinenti disposizioni degli articoli 55 e 64;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">definisce, stabilisce, valuta preliminarmente, attua, valuta a posteriori, rivede ed elimina gli indicatori di rischio specifici di cui all’articolo 33 previa consultazione della commissione di esame ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvede affinché le verifiche effettuate in conformità dell’articolo 22 e i relativi risultati siano registrati nei fascicoli di domanda;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">svolge verifiche regolari del trattamento delle domande e dell’attuazione dell’articolo 33, con particolare riguardo all’impatto sui diritti fondamentali, segnatamente il rispetto della vita privata e la protezione dei dati personali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indica, se del caso, lo Stato membro competente per il trattamento manuale delle domande ai sensi dell’articolo 25, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in presenza di problemi tecnici o circostanze impreviste, facilita se necessario le consultazioni tra gli Stati membri di cui all’articolo 28 e tra lo Stato membro competente ed Europol di cui all’articolo 29;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informa i vettori in caso di guasto del sistema d’informazione ETIAS ai sensi dell’articolo 46, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informa le unità nazionali ETIAS degli Stati membri in caso di guasto del sistema d’informazione ETIAS ai sensi dell’articolo 48, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tratta le richieste di consultazione dei dati nel sistema centrale ETIAS da parte di Europol ai sensi dell’articolo 53;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornisce al pubblico tutte le informazioni utili in merito alle domande di autorizzazione ai viaggi ai sensi dell’articolo 71;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coopera con la Commissione riguardo alla campagna d’informazione di cui all’articolo 72;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornisce sostegno per iscritto ai viaggiatori che hanno riscontrato problemi nella compilazione del modulo di domanda e che hanno richiesto assistenza avvalendosi a tal fine di un modulo di contatto standard; aggiorna un elenco di domande frequenti e relative risposte reso disponibile online;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicura un seguito e riferisce periodicamente alla Commissione in merito alle segnalazioni di abusi commessi da un intermediario commerciale di cui all’articolo 15, paragrafo 5.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’unità centrale ETIAS pubblica una relazione annuale di attività. Tale relazione include:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">statistiche su:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numero di autorizzazioni ai viaggi emesse automaticamente dal sistema centrale ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numero di domande verificate dall’unità centrale ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numero di domande trattate manualmente per Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numero di domande respinte per paese e motivo del rigetto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rispetto dei termini di cui all’articolo 22, paragrafo 6, e agli articoli 27, 30 e 32;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni generali sul funzionamento dell’unità centrale ETIAS, sulle sue attività di cui al presente articolo e informazioni sulle tendenze e sulle sfide attuali che incidono sull’esercizio dei suoi compiti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La relazione annuale di attività è trasmessa al Parlamento europeo, al Consiglio e alla Commissione entro il 31 marzo dell’anno successivo.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’unità centrale ETIAS presenta relazioni periodiche alla Commissione e ad eu-LISA in merito ai falsi riscontri positivi di cui all’articolo 22, paragrafo 4, generati durante le verifiche automatizzate ai sensi dell’articolo 20, paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "8": {"label": "Articolo 8", "heading": "Unità nazionali ETIAS", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro designa un’autorità competente come unità nazionale ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Spetta alle unità nazionali ETIAS:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esaminare le domande di autorizzazione ai viaggi e decidere in merito, qualora dal trattamento automatizzato della domanda emerga un riscontro positivo e l’unità centrale ETIAS abbia avviato il trattamento manuale della domanda;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedere affinché i compiti eseguiti ai sensi della lettera a) e i relativi risultati siano registrati nei fascicoli di domanda;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedere affinché i dati da esse inseriti nei fascicoli di domanda siano aggiornati in conformità delle pertinenti disposizioni degli articoli 55 e 64;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decidere di rilasciare autorizzazioni ai viaggi con validità territoriale limitata ai sensi dell’articolo 44;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedere al coordinamento con altre unità nazionali ETIAS ed Europol riguardo alle richieste di consultazione di cui agli articoli 28 e 29;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informare i richiedenti sulla procedura da seguire in caso di ricorso ai sensi dell’articolo 37, paragrafo 3;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">annullare e revocare un’autorizzazione ai viaggi ai sensi degli articoli 40 e 4.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri forniscono alle unità nazionali ETIAS risorse adeguate per svolgere i loro compiti in conformità dei termini stabiliti nel presente regolamento.</div>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Commissione di esame ETIAS", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È istituita, nell’ambito dell’Agenzia europea della guardia di frontiera e costiera, una commissione di esame ETIAS con funzione consultiva. Essa è composta da un rappresentante di ciascuna unità nazionale ETIAS, dell’Agenzia europea della guardia di frontiera e costiera e di Europol.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La commissione di esame ETIAS è consultata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dall’unità centrale ETIAS sulla definizione, lo stabilimento, la valutazione preliminare, l’attuazione, la valutazione a posteriori, la revisione e l’eliminazione degli indicatori di rischio specifici di cui all’articolo 33;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dagli Stati membri sull’applicazione dell’elenco di controllo ETIAS di cui all’articolo 34;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">da Europol sull’applicazione dell’elenco di controllo ETIAS di cui all’articolo 34.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La commissione di esame ETIAS formula pareri, orientamenti, raccomandazioni e migliori prassi ai fini di cui al paragrafo 2. Quando formula raccomandazioni, la commissione di esame ETIAS tiene conto delle raccomandazioni formulate dalla commissione di orientamento sui diritti fondamentali dell’ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La commissione di esame ETIAS si riunisce ogniqualvolta necessario e almeno due volte all’anno. I costi e l’organizzazione delle riunioni sono a carico dell’Agenzia europea della guardia di frontiera e costiera.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La commissione di esame ETIAS può consultare la commissione di orientamento sui diritti fondamentali dell’ETIAS su questioni specifiche relative ai diritti fondamentali, in particolare per quanto concerne la vita privata, la protezione dei dati personali e la non discriminazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">In occasione della prima riunione la commissione di esame ETIAS adotta il regolamento interno a maggioranza semplice dei suoi membri.</div>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Commissione di orientamento sui diritti fondamentali dell’ETIAS", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È istituita la commissione di orientamento sui diritti fondamentali dell’ETIAS con funzione consultiva e di valutazione. Ferme restando le rispettive competenze e la loro indipendenza, essa è composta dal responsabile dei diritti fondamentali dell’Agenzia europea della guardia di frontiera e costiera, da un rappresentante del Forum consultivo sui diritti fondamentali dell’Agenzia europea della guardia di frontiera e costiera, da un rappresentante del Garante europeo della protezione dei dati, da un rappresentante del comitato europeo per la protezione dei dati istituito dal regolamento (UE) 2016/679 e da un rappresentante dell’Agenzia dell’Unione europea per i diritti fondamentali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La commissione di orientamento sui diritti fondamentali dell’ETIAS effettua valutazioni periodiche e formula raccomandazioni per la commissione di esame ETIAS sull’impatto sui diritti fondamentali del trattamento delle domande e dell’attuazione dell’articolo 33, in particolare per quanto concerne la vita privata, la protezione dei dati personali e la non discriminazione.</div>\n</div>"], [null, "<p class=\"norm\">La commissione di orientamento sui diritti fondamentali dell’ETIAS coadiuva inoltre la commissione di esame ETIAS nell’esecuzione dei suoi compiti quando quest’ultima la consulta su questioni specifiche relative ai diritti fondamentali, in particolare per quanto concerne la vita privata, la protezione dei dati personali e la non discriminazione.</p>"], [null, "<p class=\"norm\">La commissione di orientamento sui diritti fondamentali dell’ETIAS ha accesso alle verifiche di cui all’articolo 7, paragrafo 2, lettera e).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La commissione di orientamento sui diritti fondamentali dell’ETIAS si riunisce a ogniqualvolta necessario e almeno due volte all’anno. I costi e l’organizzazione delle sue riunioni sono a carico dell’Agenzia europea della guardia di frontiera e costiera. Le sue riunioni si svolgono nei locali dell’Agenzia europea della guardia di frontiera e costiera. Il segretariato delle sue riunioni è assicurato dall’Agenzia europea della guardia di frontiera e costiera. In occasione della sua prima riunione, la commissione di orientamento sui diritti fondamentali dell’ETIAS adotta il regolamento interno a maggioranza semplice dei suoi membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Un rappresentante della commissione di orientamento sui diritti fondamentali dell’ETIAS è invitato a partecipare alle riunioni della commissione di esame ETIAS con funzione consultiva. I membri della commissione di orientamento sui diritti fondamentali dell’ETIAS hanno accesso alle informazioni e ai fascicoli della commissione di esame ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La commissione di orientamento sui diritti fondamentali dell’ETIAS redige una relazione annuale. La relazione deve essere messa a disposizione del pubblico.</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Interoperabilità con gli altri sistemi d’informazione dell’UE e i dati Europol", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È assicurata l’interoperabilità tra il sistema d’informazione ETIAS, da un lato, e gli altri sistemi d’informazione dell’UE e i dati Europol, dall’altro, al fine di consentire le verifiche automatizzate di cui all’articolo 20, all’articolo 23, all’articolo 24, paragrafo 6, lettera c), punto ii), all’articolo 41 e all’articolo 54, paragrafo 1, lettera b), del presente regolamento. Tale interoperabilità sfrutta il portale di ricerca europeo («ESP») istituito dall’articolo 6 del regolamento (UE) 2019/817 e dall’articolo 6 del regolamento (UE) 2019/818 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">14</span>\n), a decorrere dalla data di cui all’articolo 72, paragrafo 1 <span class=\"italics\">ter</span>, del regolamento (UE) 2019/817 e di cui all’articolo 68, paragrafo 1 <span class=\"italics\">ter</span>, del regolamento (UE) 2019/818.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al fine di procedere alle verifiche di cui all’articolo 20, paragrafo 2, lettera i), le verifiche automatizzate a norma dell’articolo 20, dell’articolo 24, paragrafo 6, lettera c), punto ii), e dell’articolo 54, paragrafo 1, lettera b), consentono al sistema centrale ETIAS di interrogare il VIS con i seguenti dati forniti dai richiedenti ai sensi dell’articolo 17, paragrafo 2, lettere a), a <span class=\"italics\">bis</span>), c) e d):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome alla nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nome o nomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">luogo di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">paese di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attuale cittadinanza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altre cittadinanze eventuali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipo, numero e paese di rilascio del documento di viaggio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al fine di procedere alle verifiche di cui all’articolo 20, paragrafo 2, lettere g) e h), le verifiche automatizzate a norma dell’articolo 20, dell’articolo 24, paragrafo 6, lettera c), punto ii), dell’articolo 41 e dell’articolo 54, paragrafo 1, lettera b), consentono al sistema centrale ETIAS di interrogare l’EES con i seguenti dati forniti dai richiedenti ai sensi dell’articolo 17, paragrafo 2, lettere da a) a d):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome alla nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nome o nomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attuale cittadinanza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altri nomi eventuali (pseudonimi);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomi d’arte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">soprannomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altre cittadinanze eventuali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipo, numero e paese di rilascio del documento di viaggio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al fine di procedere alle verifiche di cui all’articolo 20, paragrafo 2, lettera c), lettera m), punto ii), e lettera o), e all’articolo 23 del presente regolamento, le verifiche automatizzate a norma dell’articolo 20, dell’articolo 23, dell’articolo 24, paragrafo 6, lettera c), punto ii), dell’articolo 41 e dell’articolo 54, paragrafo 1, lettera b) consentono al sistema centrale ETIAS di interrogare il SIS, istituito dai regolamenti (UE) 2018/1860 e (UE) 2018/1861, con i dati seguenti forniti dai richiedenti ai sensi dell’articolo 17, paragrafo 2, lettere da a) a d) e lettera k), del presente regolamento:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome alla nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nome o nomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">luogo di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attuale cittadinanza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altri nomi eventuali (pseudonimi);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomi d’arte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">soprannomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altre cittadinanze eventuali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipo, numero e paese di rilascio del documento di viaggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i minori, cognome e nome o nomi della persona che esercita la responsabilità genitoriale o del tutore legale del richiedente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al fine di procedere alle verifiche di cui all’articolo 20, paragrafo 2, lettere a) e d), e lettera m), punto i), e all’articolo 23, paragrafo 1 del presente regolamento, le verifiche automatizzate a norma dell’articolo 20, dell’articolo 23, dell’articolo 24, paragrafo 6, lettera c), punto ii), dell’articolo 41 e dell’articolo 54, paragrafo 1, lettera b), consentono al sistema centrale ETIAS di interrogare il SIS, istituito dal regolamento (UE) 2018/1862, con i seguenti dati forniti dai richiedenti ai sensi dell’articolo 17, paragrafo 2, lettere da a) a d) e lettera k), del presente regolamento:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome alla nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nome o nomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">luogo di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attuale cittadinanza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altri nomi eventuali (pseudonimi);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomi d’arte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">soprannomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altre cittadinanze eventuali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipo, numero e paese di rilascio del documento di viaggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i minori, cognome e nome o nomi della persona che esercita la responsabilità genitoriale o del tutore legale del richiedente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al fine di procedere alle verifiche di cui all’articolo 20, paragrafo 2, lettera n), le verifiche automatizzate a norma dell’articolo 20, dell’articolo 24, paragrafo 6, lettera c), punto ii), e dell’articolo 54, paragrafo 1, lettera b) consentono al sistema centrale ETIAS di interrogare i dati ECRIS-TCN con i dati seguenti forniti dai richiedenti ai sensi dell’articolo 17, paragrafo 2, lettere da a) a d):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome alla nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nome o nomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">luogo di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e bis) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">paese di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attuale cittadinanza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altri nomi eventuali (pseudonimi);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nomi d’arte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">soprannomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altre cittadinanze eventuali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipo, numero e paese di rilascio del documento di viaggio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Al fine di procedere alle verifiche di cui all’articolo 20, paragrafo 2, lettera j), le verifiche automatizzate a norma dell’articolo 20, dell’articolo 24, paragrafo 6, lettera c), punto ii), e dell’articolo 54, paragrafo 1, lettera b) consentono al sistema centrale ETIAS di interrogare i dati Europol con i dati di cui all’articolo 17, paragrafo 2, lettere a), a <span class=\"italics\">bis</span>), b), c), d), f), g), (j), k) e m), e all’articolo 17, paragrafo 8.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Qualora dalle verifiche automatizzate a norma degli articoli 20 e 23 emerga un riscontro positivo, l’ESP fornisce all’unità centrale ETIAS un accesso temporaneo, in modalità di sola lettura, ai risultati di tali verifiche automatizzate. Nel caso delle verifiche automatizzate a norma dell’articolo 20, tale accesso è garantito nel fascicolo di domanda fino alla conclusione del trattamento manuale di cui all’articolo 22, paragrafo 2. In caso di corrispondenza tra i dati messi a disposizione e quelli del richiedente o di persistenza, a seguito delle verifiche automatizzate ai sensi degli articoli 20 e 23, di dubbi, il numero di riferimento univoco, nel sistema d’informazione dell’UE interrogato, della cartella dei dati per i quali è emerso il riscontro positivo è conservato nel fascicolo di domanda.</div>\n</div>"], [null, "<p class=\"norm\">Qualora dalle verifiche automatizzate a norma dell’articolo 20 emerga un riscontro positivo, tali verifiche automatizzate ricevono l’opportuna notifica a norma dell’articolo 21, paragrafo 1 <span class=\"italics\">bis</span>, del regolamento (UE) 2016/794.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Si ha un riscontro positivo qualora tutti i dati del fascicolo di domanda usati per l’interrogazione o alcuni di essi corrispondano in tutto o in parte ai dati contenuti in una cartella, un fascicolo o una segnalazione registrati negli altri sistemi d’informazione dell’UE consultati. La Commissione adotta atti delegati conformemente all’articolo 89 al fine di specificare le condizioni per la corrispondenza tra i dati contenuti in una cartella, un fascicolo o una segnalazione registrati negli altri sistemi d’informazione dell’UE consultati e in un fascicolo di domanda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1 del presente articolo, la Commissione stabilisce mediante atto di esecuzione le modalità tecniche per l’attuazione dell’articolo 24, paragrafo 6, lettera c), punto ii), e dell’articolo 54, paragrafo 1, lettera b), per quanto riguarda la conservazione dei dati. Tale atto di esecuzione è adottato secondo la procedura d’esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini dell’articolo 25, paragrafo 2, dell’articolo 28, paragrafo 8, e dell’articolo 29, paragrafo 9, nel registrare i dati relativi a un riscontro positivo nel fascicolo di domanda la provenienza dei dati è indicata dai dati seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il tipo di segnalazione, ad eccezione delle segnalazioni di cui all’articolo 23, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la fonte dei dati, vale a dire l’altro sistema d’informazione dell’UE da cui provengono i dati o i dati Europol, se del caso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di riferimento, nel sistema d’informazione dell’UE interrogato, della cartella per cui è emerso il riscontro positivo, lo Stato membro che ha inserito o fornito i dati per i quali è emerso il riscontro positivo; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se disponibili, la data e l’ora in cui i dati sono stati inseriti nell’altro sistema d’informazione dell’UE o nei dati Europol.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">I dati di cui al primo comma, lettere da a) a d), sono accessibili e visibili unicamente all’unità centrale ETIAS qualora il sistema centrale ETIAS non sia in grado di individuare lo Stato membro competente.</p>"]]}, "11b": {"label": "Articolo 11 ter", "heading": "Sostegno agli obiettivi dell’EES", "anchor": "art_11b", "frags": [[null, "<p class=\"norm\">Ai fini degli articoli 6, 14, 17 e 18 del regolamento (UE) 2017/2226, un processo automatizzato che utilizza il canale di comunicazione sicuro di cui all’articolo 6, paragrafo 2, lettera d <span class=\"italics\">bis</span>), del presente regolamento interroga e importa dal sistema centrale ETIAS le informazioni di cui all’articolo 47, paragrafo 2, del presente regolamento, il numero della domanda e la data di scadenza dell’autorizzazione ai viaggi ETIAS, e crea o aggiorna conseguentemente la cartella di ingresso/uscita o la cartella relativa al respingimento nell’EES.</p>"]]}, "11c": {"label": "Articolo 11 quater", "heading": "Interoperabilità tra l’ETIAS e l’EES ai fini della revoca di un’autorizzazione ai viaggi ETIAS su richiesta del richiedente", "anchor": "art_11c", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini dell’attuazione dell’articolo 41, paragrafo 8, un processo automatizzato che utilizza il canale di comunicazione sicuro di cui all’articolo 6, paragrafo 2, lettera d <span class=\"italics\">bis</span>), interroga il sistema centrale dell’EES per verificare che coloro che chiedono la revoca delle loro autorizzazioni ai viaggi non siano presenti nel territorio degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se l’esito della verifica nel sistema centrale dell’EES di cui al paragrafo 1 indica che il richiedente non è presente nel territorio degli Stati membri, la revoca ha effetto immediato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se l’esito della verifica di cui al paragrafo 1 de presente articolo indica che il richiedente è presente nel territorio degli Stati membri, si applica l’articolo 41, paragrafo 8. Il sistema centrale dell’EES registra che occorre trasmettere una notifica al sistema centrale ETIAS non appena è creata una cartella di ingresso/uscita ove si indichi che il richiedente la revoca dell’autorizzazione ai viaggi ha lasciato il territorio degli Stati membri.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Interrogazione delle banche dati Interpol", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il sistema centrale ETIAS interroga la banca dati Interpol sui documenti di viaggio rubati o smarriti (SLTD) e la banca dati Interpol sui documenti di viaggio associati a segnalazioni (TDAWN).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le interrogazioni e le verifiche sono effettuate in modo che nessuna informazione sia rivelata al titolare della segnalazione Interpol.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se l’attuazione del paragrafo 2 non è garantita, il sistema centrale ETIAS non interroga le banche dati di Interpol.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Accesso ai dati conservati nell’ETIAS", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’accesso al sistema d’informazione ETIAS è riservato esclusivamente al personale debitamente autorizzato dell’unità centrale ETIAS e delle unità nazionali ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’accesso delle autorità di frontiera al sistema centrale ETIAS conformemente all’articolo 47 è limitato all’interrogazione di quest’ultimo per verificare lo status dell’autorizzazione ai viaggi di un viaggiatore presente a un valico di frontiera esterno e ai dati di cui all’articolo 47, paragrafo 2, lettere a), c) e d). Inoltre le autorità di frontiera sono informate automaticamente degli indicatori di cui all’articolo 36, paragrafi 2 e 3, nonché dei relativi motivi.</div>\n</div>"], [null, "<p class=\"norm\">Qualora, eccezionalmente, sulla base di un indicatore, sia raccomandata una verifica in seconda linea alla frontiera, o siano necessarie ulteriori verifiche ai fini di una verifica in seconda linea, le autorità di frontiera accedono al sistema centrale ETIAS per ottenere le informazioni aggiuntive di cui all’articolo 39, paragrafo 1, lettera e), o all’articolo 44, paragrafo 6, lettera f).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’accesso dei vettori al sistema d’informazione ETIAS conformemente all’articolo 45 è limitato alla trasmissione di interrogazioni a quest’ultimo per verificare lo status dell’autorizzazione ai viaggi di un viaggiatore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’accesso delle autorità competenti in materia di immigrazione al sistema centrale ETIAS conformemente all’articolo 49 è limitato alla verifica dello status dell’autorizzazione ai viaggi di un viaggiatore presente sul territorio dello Stato membro e ad alcuni dati di cui a detto articolo.</div>\n</div>"], [null, "<p class=\"norm\">L’accesso delle autorità competenti in materia di immigrazione al sistema centrale ETIAS conformemente all’articolo 65, paragrafo 3, è limitato ai dati di cui a detto articolo.</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">L'accesso ai dati di identità e ai dati del documento di viaggio dell'ETIAS conservati nel CIR è riservato esclusivamente al personale debitamente autorizzato delle autorità nazionali di ciascuno Stato membro e al personale debitamente autorizzato delle agenzie dell'Unione che sono competenti per gli scopi di cui agli articoli 20 e 21 del regolamento (UE) 2019/817. Tale accesso è limitato conformemente alla misura in cui i dati siano necessari all'assolvimento dei propri compiti per tali scopi, e proporzionato agli obiettivi perseguiti.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro designa le autorità nazionali competenti di cui ai paragrafi 1, 2, 4 e 4 <span class=\"italics\">bis</span> del presente articolo e ne comunica senza indugio a eu-LISA l'elenco, in conformità dell'articolo 87, paragrafo 2. Tale elenco specifica lo scopo per cui il personale debitamente autorizzato di ciascuna autorità ha accesso ai dati conservati nel sistema d'informazione dell'ETIAS conformemente ai paragrafi 1, 2, 4 e 4 <span class=\"italics\">bis</span> del presente articolo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "14": {"label": "Articolo 14", "heading": "Non discriminazione e diritti fondamentali", "anchor": "art_14", "frags": [[null, "<p class=\"norm\">Il trattamento dei dati personali nell’ambito del sistema d’informazione ETIAS da parte di qualsiasi utente non dà luogo a discriminazioni nei confronti di cittadini di paesi terzi fondate sul sesso, sulla razza, sul colore della pelle, sull’origine etnica o sociale, sulle caratteristiche genetiche, sulla lingua, sulla religione o sulle convinzioni personali, sulle opinioni politiche o di qualsiasi altra natura, sull’appartenenza a una minoranza nazionale, sul patrimonio, sulla nascita, sulla disabilità, sull’età o sull’orientamento sessuale. Esso rispetta pienamente la dignità e l’integrità umana nonché i diritti fondamentali, compreso il diritto al rispetto della vita privata e alla protezione dei dati personali. È prestata particolare attenzione ai minori, alle persone anziane e alle persone con disabilità. L’interesse superiore del minore è considerato preminente.</p>"]]}, "15": {"label": "Articolo 15", "heading": "Modalità pratiche di presentazione della domanda", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I richiedenti presentano la domanda completando il modulo di domanda online tramite l’apposito sito Internet web pubblico o l’applicazione per dispositivi mobili con sufficiente anticipo rispetto al viaggio previsto oppure, se si trovano già sul territorio degli Stati membri, prima della scadenza della validità dell’autorizzazione ai viaggi che già possiedono.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I titolari di un’autorizzazione ai viaggi possono richiedere una nuova autorizzazione ai viaggi non prima di 120 giorni dalla scadenza dell’autorizzazione ai viaggi.</div>\n</div>"], [null, "<p class=\"norm inline-element\">120 giorni prima della scadenza dell’autorizzazione ai viaggi, il sistema centrale ETIAS informa automaticamente il titolare di tale autorizzazione ai viaggi, tramite il servizio di posta elettronica:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della data di scadenza dell’autorizzazione ai viaggi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della possibilità di richiedere una nuova autorizzazione ai viaggi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’obbligo di essere in possesso di un’autorizzazione ai viaggi valida per l’intera durata del soggiorno di breve durata nel territorio degli Stati membri.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Tutte le comunicazioni al richiedente ai fini della sua domanda di autorizzazione ai viaggi sono inviate all’indirizzo di posta elettronica fornito dal richiedente nel modulo di domanda di cui all’articolo 17, paragrafo 2, lettera g).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le domande possono essere presentate dal richiedente o da un terzo o un intermediario commerciale da esso autorizzato a presentare la domanda per suo conto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione, per mezzo di un atto di esecuzione, crea un modulo che consenta la segnalazione di abusi commessi da un intermediario commerciale di cui al paragrafo 4 del presente articolo. Tale modulo è reso accessibile tramite l’apposito sito web pubblico o l’applicazione per dispositivi mobili di cui al paragrafo 1 del presente articolo. Il modulo così completato è inviato all’unità centrale ETIAS, che adotta le misure opportune e relaziona periodicamente alla Commissione. L’atto di esecuzione è adottato conformemente alla procedura di esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Sito web pubblico e applicazione per dispositivi mobili", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il sito web pubblico e l’applicazione per dispositivi mobili permettono ai cittadini di paesi terzi soggetti all’obbligo dell’autorizzazione ai viaggi di presentare domanda di autorizzazione ai viaggi, fornire i dati richiesti nel modulo di domanda conformemente all’articolo 17 e pagare i diritti per l’autorizzazione ai viaggi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il sito web pubblico e l’applicazione per dispositivi mobili assicurano ai richiedenti la massima disponibilità e facilità di accesso e la gratuità del modulo di domanda. Deve essere prestata particolare attenzione all’accessibilità del sito web pubblico e dell’applicazione per dispositivi mobili per le persone con disabilità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il sito web pubblico e l’applicazione per dispositivi mobili sono disponibili in tutte le lingue ufficiali degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora la lingua o le lingue ufficiali dei paesi che figurano nell’elenco dell’allegato II del regolamento (CE) n. 539/2001 non corrispondano alle lingue di cui al paragrafo 3, eu-LISA mette a disposizione sul sito web pubblico e sull’applicazione per dispositivi mobili schede informative esplicative sull’ETIAS, sulla procedura di domanda e sull’uso del sito web pubblico e dell’applicazione per dispositivi mobili, nonché una guida passo per passo relativa alla domanda, in almeno una delle lingue ufficiali dei paesi in questione. Qualora in tali paesi vi siano più lingue ufficiali, le schede informative sono necessarie solo se nessuna di queste lingue corrisponde alle lingue di cui al paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il sito web pubblico e l’applicazione per dispositivi mobili indicano ai richiedenti le lingue utilizzabili per compilare il modulo di domanda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il sito web pubblico e l’applicazione per dispositivi mobili offrono ai richiedenti un servizio di account che permette loro di fornire informazioni o documenti aggiuntivi, se necessario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il sito web pubblico e l’applicazione mobile per dispositivi mobili informano i richiedenti in merito al loro diritto di ricorso ai sensi del presente regolamento nel caso in cui un’autorizzazione ai viaggi sia rifiutata, revocata o annullata. A tal fine contengono informazioni relative al diritto nazionale applicabile, all’autorità competente, alle modalità e ai termini per proporre ricorso, nonché informazioni sull’assistenza che può essere fornita dall’autorità nazionale per la protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Il sito web pubblico e l’applicazione per dispositivi mobili consentono ai richiedenti di indicare che lo scopo del soggiorno previsto è connesso a motivi umanitari o ad obblighi internazionali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il sito web pubblico contiene le informazioni di cui all’articolo 71.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante atti di esecuzione, norme dettagliate sul funzionamento del sito web pubblico e dell’applicazione per dispositivi mobili, nonché norme dettagliate sulla protezione e la sicurezza dei dati applicabili al sito web pubblico e all’applicazione per dispositivi mobili. Tali norme dettagliate sono basate sulla gestione dei rischi relativi alla sicurezza delle informazioni e sui principi di protezione dei dati fin dalla progettazione e per impostazione predefinita. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Modulo di domanda e dati personali del richiedente", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il richiedente presenta un modulo di domanda compilato e corredato di dichiarazione di autenticità, completezza, esattezza e affidabilità dei dati presentati e di dichiarazione di veridicità e affidabilità delle dichiarazioni rese. Il richiedente dichiara inoltre di aver compreso le condizioni d’ingresso di cui all’articolo 6 del regolamento (UE) 2016/399 e che può essere invitato a presentare i pertinenti documenti giustificativi all’atto di ciascun ingresso. I minori presentano un modulo di domanda firmato elettronicamente da una persona che esercita la responsabilità genitoriale in via permanente o temporanea o da un tutore legale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel modulo di domanda il richiedente fornisce i dati personali seguenti:</p>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome, nome o nomi, cognome alla nascita, data di nascita, luogo di nascita, sesso, attuale cittadinanza;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a <span class=\"italics\">bis</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">paese di nascita, nome o nomi dei genitori;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altri nomi eventuali (pseudonimi, nomi d’arte, soprannomi);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altre cittadinanze eventuali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipo, numero e paese di rilascio del documento di viaggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di rilascio e data di scadenza del documento di viaggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">domicilio del richiedente o, in mancanza, città e paese di residenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indirizzo di posta elettronica e, se disponibili, numeri di telefono;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">istruzione (primaria, secondaria, superiore o nessuna istruzione);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">occupazione attuale (gruppo di posizioni lavorative); qualora la domanda sia trattata manualmente in conformità della procedura di cui all’articolo 26, lo Stato membro responsabile può richiedere, in conformità dell’articolo 27, al richiedente di fornire informazioni aggiuntive relativamente alla qualifica professionale esatta e al datore di lavoro o, per gli studenti, il nome dell’istituto di insegnamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Stato membro di primo soggiorno previsto e, in via facoltativa, indirizzo del primo soggiorno previsto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i minori, cognome e nome o nomi, domicilio, indirizzo di posta elettronica e, se disponibile, numero di telefono della persona che esercita la responsabilità genitoriale o del tutore legale del richiedente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente si avvale dello status di familiare di cui all’articolo 2, paragrafo 1, lettera c):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il proprio status di familiare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome, nome o nomi, data di nascita, luogo di nascita, paese di nascita, cittadinanza attuale, domicilio, indirizzo di posta elettronica e, se disponibile, numero di telefono del familiare con cui ha vincoli di parentela;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i propri vincoli di parentela con tale familiare in conformità dell’articolo 2, paragrafo 2, della direttiva 2004/38/CE;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se la domanda è compilata da una persona diversa dal richiedente, cognome, nome o nomi, denominazione della ditta o dell’organizzazione se del caso, indirizzo di posta elettronica, indirizzo postale e numero di telefono, se disponibile, di tale persona; relazione con il richiedente e dichiarazione di rappresentanza firmata.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il richiedente sceglie l’attuale occupazione (gruppo di posizioni lavorative) da un elenco predefinito. La Commissione adotta atti delegati conformemente all’articolo 89 per stabilire tale elenco predefinito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Inoltre il richiedente risponde alle domande seguenti:</p>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se è stato condannato per i reati di terrorismo nei 25 anni precedenti o, per gli altri reati elencati nell’allegato, nei e, nei 15 anni precedenti e, in tali casi, quando e in quale paese;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se ha soggiornato in una specifica zona di guerra o di conflitto nei dieci anni precedenti e per quale motivo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se è stato oggetto di un provvedimento di espulsione dal territorio di uno Stato membro, o di qualsiasi paese terzo elencato nell’allegato II del regolamento (CE) n. 539/2011, ovvero di una decisione di rimpatrio nei dieci anni precedenti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti delegati in conformità dell’articolo 89 al fine di specificare il contenuto e il formato delle domande di cui al paragrafo 4 del presente articolo, consentendo ai richiedenti di fornire risposte chiare e precise.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Se risponde affermativamente a una delle domande di cui al paragrafo 4, il richiedente è tenuto a rispondere a una serie aggiuntiva di domande predefinite e contenute nel modulo di domanda selezionando le risposte da un elenco predefinito. La Commissione adotta atti delegati in conformità dell’articolo 89 al fine di stabilire il contenuto e il formato delle domande aggiuntive e l’elenco predefinito di risposte a tali domande.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I dati di cui ai paragrafi 2 e 4 sono inseriti dal richiedente in caratteri latini.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Al momento della presentazione del modulo di domanda, il sistema d’informazione ETIAS raccoglie l’indirizzo IP da cui è stato trasmesso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">La Commissione definisce, mediante atti di esecuzione, i requisiti concernenti il formato dei dati personali di cui ai paragrafi 2 e 4 del presente articolo da inserire nel modulo di domanda nonché i parametri e le verifiche da applicare per garantire la completezza della domanda e la coerenza di tali dati. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Diritti per l’autorizzazione ai viaggi", "anchor": "art_18", "frags": [[null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per ciascuna domanda di autorizzazione ai viaggi il richiedente paga diritti pari a 20 EUR.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I richiedenti di età inferiore a diciotto anni o superiore a settant’anni al momento della presentazione della domanda sono esentati dal pagamento dei diritti per l’autorizzazione ai viaggi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I diritti per l’autorizzazione ai viaggi sono riscossi in euro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti delegati in conformità dell’articolo 89 per stabilire metodi e processi di pagamento dei diritti per l’autorizzazione ai viaggi. Le variazioni dell’importo tengono conto di eventuali aumenti delle spese di cui all’articolo 85.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Ammissibilità e creazione del fascicolo di domanda", "anchor": "art_19", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Una volta trasmessa la domanda, il sistema d’informazione ETIAS verifica automaticamente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se i campi del modulo di domanda siano tutti compilati e contengano tutti gli elementi di cui all’articolo 17, paragrafi 2 e 4;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se siano stati riscossi i diritti per l’autorizzazione ai viaggi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se le condizioni di cui al paragrafo 1, lettere a) e b) sono soddisfatte, la domanda è ritenuta ammissibile. Il sistema centrale ETIAS crea quindi automaticamente e senza ritardo un fascicolo di domanda al quale assegna un numero di domanda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel creare il fascicolo di domanda, il sistema centrale ETIAS registra e conserva i dati seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di domanda;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sullo status con l’indicazione che è stata richiesta un’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati personali di cui all’articolo 17, paragrafo 2, e, se del caso, all’articolo 17, paragrafi 4 e 6, compreso il codice a tre lettere del paese che ha rilasciato il documento di viaggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati di cui all’articolo 17, paragrafo 8;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data e l’ora di trasmissione del modulo di domanda, l’indicazione dell’avvenuto pagamento dei diritti per l’autorizzazione ai viaggi e il numero di riferimento unico del pagamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Al momento della creazione del fascicolo di domanda, il sistema centrale ETIAS verifica se contiene già un altro fascicolo di domanda relativo allo stesso richiedente confrontando i dati di cui all’ <span>\n<span class=\"boldface\">►M1</span>\n</span> articolo 17, paragrafo 2, lettere a) e a <span class=\"italics\">bis</span>)<span class=\"boldface\"> ◄ </span>, con i dati personali dei fascicoli di domanda conservati nel sistema centrale ETIAS. In tal caso, il sistema centrale ETIAS collega il nuovo fascicolo di domanda a quello precedentemente creato per lo stesso richiedente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al momento della creazione del fascicolo di domanda, il richiedente riceve immediatamente, tramite il servizio di posta elettronica, una notifica che indica che durante il trattamento della domanda, il richiedente può essere invitato a fornire informazioni o documenti aggiuntivi o, in circostanze eccezionali, a sostenere un colloquio. La notifica comprende:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sullo status con la conferma della presentazione di una domanda di autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di domanda.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La notifica consente al richiedente l’accesso allo strumento di verifica di cui all’articolo 6, paragrafo 2, lettera h).</p>"]]}, "20": {"label": "Articolo 20", "heading": "Trattamento automatizzato", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il sistema centrale ETIAS tratta i fascicoli di domanda automaticamente alla ricerca di eventuali riscontri positivi. Il sistema centrale ETIAS esamina ciascun fascicolo di domanda individualmente.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il sistema centrale ETIAS avvia un’interrogazione utilizzando l’ESP per confrontare i dati pertinenti di cui all’articolo 17, paragrafo 2, lettere a), a <span class=\"italics\">bis</span>), b), c), d), f), g), j), k) e m), e paragrafo 8, con i dati contenuti in una cartella, un fascicolo o una segnalazione registrati in un fascicolo di domanda memorizzato nel sistema centrale ETIAS, nel SIS, nell’EES, nel VIS, nell’Eurodac, nei dati Europol, nell’ECRIS-TCN e nelle banche dati Interpol SLTD e TDAWN. In particolare, il sistema centrale ETIAS verifica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il documento di viaggio usato per la domanda corrisponde a un documento di viaggio segnalato come smarrito, rubato, altrimenti sottratto o invalidato nel SIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il documento di viaggio usato per la domanda corrisponde a un documento di viaggio segnalato come smarrito, rubato o invalidato nell’SLTD;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente è oggetto di una segnalazione ai fini del rifiuto d’ingresso e di soggiorno inserito nel SIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente è oggetto di una segnalazione come persona ricercata per l’arresto a fini di consegna sulla base di un mandato d’arresto europeo o ricercata per l’arresto a fini di estradizione nel SIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente e il documento di viaggio corrispondono a un’autorizzazione ai viaggi rifiutata, revocata o annullata nel sistema centrale ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se i dati forniti nella domanda relativi al documento di viaggio corrispondono a un’altra domanda di autorizzazione ai viaggi associata a dati di identità diversi di cui all’articolo 17, paragrafo 2, lettera a), nel sistema centrale ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente è attualmente segnalato come soggiornante fuoritermine o se lo è stato in passato nell’EES;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente è registrato nell’EES per essere stato oggetto di un rifiuto di ingresso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente è stato oggetto di una decisione di rifiuto, annullamento o revoca di un visto per soggiorno di breve durata registrata nel VIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se i dati forniti nella domanda corrispondono a informazioni contenute nei dati Europol;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente è registrato nell’Eurodac;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il documento di viaggio usato per la domanda corrisponde a un documento di viaggio registrato in un fascicolo del TDAWN;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nei casi in cui il richiedente sia un minore, se il titolare della responsabilità genitoriale o il tutore legale:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è oggetto di una segnalazione come persona ricercata per l’arresto a fini di consegna sulla base di un mandato d’arresto europeo o ricercata per l’arresto a fini di estradizione nel SIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è oggetto di una segnalazione ai fini del rifiuto d’ingresso e di soggiorno registrata nel SIS;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente corrisponde a una persona i cui dati sono stati registrati nel sistema ECRIS-TCN e sono provvisti di un indicatore di cui all’articolo 5, paragrafo 1, lettera c), del regolamento (UE) 2019/816; tali dati sono usati solo ai fini della verifica da parte dell’unità centrale ETIAS a norma dell’articolo 22 del presente regolamento e ai fini della consultazione dei casellari giudiziali nazionali da parte delle unità nazionali ETIAS a norma dell’articolo 25 <span class=\"italics\">bis</span>, paragrafo 2, del presente regolamento; le unità nazionali ETIAS consultano i casellari giudiziali nazionali prima delle valutazioni e delle decisioni di cui all’articolo 26 del presente regolamento e, se del caso, prima delle verifiche e dei pareri ai sensi dell’articolo 28 del presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>o) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente è oggetto di una segnalazione di rimpatrio inserita nel SIS.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il sistema centrale ETIAS verifica se il richiedente ha risposto affermativamente a una delle domande di cui all’articolo 17, paragrafo 4, e se ha dichiarato soltanto la città e il paese di residenza e non il domicilio, come previsto all’articolo 17, paragrafo 2, lettera f).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il sistema centrale ETIAS confronta i dati pertinenti di cui all’ <span>\n<span class=\"boldface\">►M1</span>\n</span> articolo 17, paragrafo 2, lettere a), a <span class=\"italics\">bis</span>), b), c), d), f), g), j), k) e m)<span class=\"boldface\"> ◄ </span>, e all’articolo 17, paragrafo 8, con i dati presenti nell’elenco di controllo ETIAS di cui all’articolo 34.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il sistema centrale ETIAS confronta i dati pertinenti di cui all’ <span>\n<span class=\"boldface\">►M1</span>\n</span> articolo 17, paragrafo 2, lettere a), a <span class=\"italics\">bis</span>), c), f), h) e i)<span class=\"boldface\"> ◄ </span>, con gli indicatori di rischio specifici di cui all’articolo 33.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il sistema centrale ETIAS inserisce nel fascicolo di domanda un riferimento a eventuali riscontri positivi emersi in conformità dei paragrafi da 2 a 5.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualora i dati registrati nel fascicolo di domanda corrispondano ai dati per i quali è emerso un riscontro positivo ai sensi dei paragrafi 2 e 4, il sistema centrale ETIAS individua, se del caso, lo Stato membro o gli Stati membri che hanno inserito o fornito i dati per i quali è emerso il riscontro positivo e lo registra nel fascicolo di domanda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">A seguito di un riscontro positivo ai sensi del paragrafo 2, lettera j), e del paragrafo 4 e qualora nessuno Stato membro abbia fornito i dati per i quali è emerso il riscontro positivo, il sistema centrale ETIAS determina se i dati sono stati inseriti da Europol e lo registra nel fascicolo di domanda.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Risultati del trattamento automatizzato", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora dal trattamento automatizzato di cui all’articolo 20, paragrafi da 2 a 5, non risulti alcun riscontro positivo, il sistema centrale ETIAS emette automaticamente un’autorizzazione ai viaggi in conformità dell’articolo 36 e ne informa il richiedente in conformità dell’articolo 38.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora dal trattamento automatizzato di cui all’articolo 20, paragrafi da 2 a 5, risultino uno o più riscontri positivi, la domanda è trattata secondo la procedura di cui all’articolo 22.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora tramite la verifica ai sensi dell’articolo 22 si confermi che i dati registrati nel fascicolo di domanda corrispondono ai dati per i quali è emerso un riscontro positivo durante il trattamento automatizzato di cui all’articolo 20, paragrafi da 2 a 5, o qualora a seguito di tale verifica persistano dubbi circa l’identità del richiedente, la domanda è trattata secondo la procedura di cui all’articolo 26.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora dal trattamento automatizzato ai sensi dell’articolo 20, paragrafo 3, risulti che il richiedente ha risposto affermativamente a una delle domande elencate nell’articolo 17, paragrafo 4, e in assenza di altri riscontri positivi, la domanda è trasmessa all’unità nazionale ETIAS dello Stato membro competente per il trattamento manuale di cui all’articolo 26.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Verifica da parte dell’unità centrale ETIAS", "anchor": "art_22", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora dal trattamento automatizzato di cui all’articolo 20, paragrafi da 2 a 5, emergano uno o più riscontri positivi, il sistema centrale ETIAS consulta automaticamente l’unità centrale ETIAS.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Se consultata, l’unità centrale ETIAS ha accesso al fascicolo di domanda e agli eventuali fascicoli di domanda collegati, nonché a tutti i riscontri positivi emersi dalle verifiche automatizzate ai sensi dell’articolo 20, paragrafi 2, 3 e 5, nonché alle informazioni rilevate dal sistema centrale ETIAS ai sensi dell’articolo 20, paragrafi 7 e 8.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’unità centrale ETIAS verifica se i dati registrati nel fascicolo di domanda corrispondono a uno o più dei seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indicatori di rischio specifici di cui all’articolo 33;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dati presenti nel sistema centrale ETIAS;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dati presenti in uno dei sistemi d’informazione dell’UE oggetto di consultazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dati Europol;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dati presenti nelle banche dati Interpol SLTD o TDAWN.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora i dati non corrispondano e non siano emersi altri riscontri positivi dal trattamento automatizzato di cui all’articolo 20, paragrafi da 2 a 5, l’unità centrale ETIAS elimina il falso riscontro positivo dal fascicolo di domanda e il sistema centrale ETIAS emette automaticamente un’autorizzazione ai viaggi in conformità dell’articolo 36.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora i dati corrispondano a quelli del richiedente, persistano dubbi sull’identità del richiedente o dalle verifiche automatizzate ai sensi dell’articolo 20, paragrafo 4, emerga un riscontro positivo, la domanda è trattata manualmente secondo la procedura di cui all’articolo 26.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’unità centrale ETIAS completa il trattamento manuale entro 12 ore dal ricevimento del fascicolo di domanda.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il sistema d’informazione ETIAS conserva i registri di tutte le operazioni di trattamento dei dati effettuate dall’unità centrale ETIAS ai fini di verifica ai sensi dei paragrafi da 2 a 6. Tali registri sono creati e inseriti automaticamente nel fascicolo di domanda. Essi indicano la data e l’ora di ciascuna operazione, i dati collegati ai riscontri positivi emersi, il membro del personale che ha effettuato il trattamento manuale ai sensi dei paragrafi da 2 a 6, il risultato della verifica e la corrispondente giustificazione.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "23": {"label": "Articolo 23", "heading": "Sostegno agli obiettivi del SIS", "anchor": "art_23", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il sistema centrale ETIAS avvia un'interrogazione utilizzando l'ESP per confrontare i dati pertinenti di cui all'articolo 17, paragrafo 2, lettere a), a <span class=\"italics\">bis</span>), b) e d), con i dati presenti nel SIS, per stabilire se il richiedente sia oggetto di una delle seguenti segnalazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">segnalazione di persona scomparsa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">segnalazione di persona ricercata nell'ambito di un procedimento giudiziario;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una segnalazione di persona da sottoporre a controllo discreto, controllo di indagine o controllo specifico.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ove dal confronto di cui al paragrafo 1 risultino uno o più riscontri positivi, il sistema centrale ETIAS trasmette una notifica automatizzata all’unità centrale ETIAS. Una volta ricevuta la notifica, l’unità centrale ETIAS ha accesso, a norma dell’articolo 11, paragrafo 8, al fascicolo di domanda e agli eventuali fascicoli di domanda collegati al fine di verificare se i dati personali del richiedente corrispondono a quelli contenuti nella segnalazione per la quale è emerso il riscontro positivo e, nel caso in cui la corrispondenza sia confermata, il sistema centrale ETIAS trasmette una notifica automatizzata all’ufficio SIRENE dello Stato membro che ha inserito la segnalazione. L’ufficio SIRENE interessato verifica a sua volta se i dati personali del richiedente corrispondono a quelli contenuti nella segnalazione per la quale è emerso il riscontro positivo e adotta adeguate misure di follow-up.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">Il sistema centrale ETIAS trasmette altresì una notifica automatizzata all’ufficio SIRENE dello Stato membro che ha inserito la segnalazione per la quale è emerso un riscontro positivo tramite consultazione del SIS durante il trattamento automatizzato di cui all’articolo 20 qualora, a seguito della verifica da parte dell’unità centrale ETIAS di cui all’articolo 22, tale segnalazione abbia determinato il trattamento manuale della domanda a norma dell’articolo 26.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<p class=\"norm\">Se il riscontro positivo riguarda una segnalazione di rimpatrio, l’ufficio SIRENE dello Stato membro che ha inserito la segnalazione, in cooperazione con l’unità nazionale ETIAS, se sia necessaria la cancellazione della segnalazione di rimpatrio a norma dell’articolo 14, paragrafo 1, del regolamento (UE) 2018/1860 e se sia necessario l’inserimento di una segnalazione al fine di impedire l’ingresso e il soggiorno a norma dell’articolo 24, paragrafo 3, del regolamento (UE) 2018/1861.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La notifica trasmessa all’ufficio SIRENE dello Stato membro che ha inserito la segnalazione contiene i dati seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome, nome o nomi, ed eventuali pseudonimi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">luogo e data di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadinanza ed eventuali altre cittadinanze;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Stato membro di primo soggiorno previsto e, se disponibile, indirizzo del primo soggiorno previsto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">domicilio del richiedente o, in mancanza, città e paese di residenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sullo status dell’autorizzazione ai viaggi che indichino se l’autorizzazione ai viaggi è stata rilasciata o rifiutata o se la domanda è oggetto di trattamento manuale ai sensi dell’articolo 26;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riferimento all’eventuale riscontro o riscontri positivi emersi conformemente ai paragrafi 1 e 2, comprese data e ora del riscontro.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il sistema centrale ETIAS inserisce nel fascicolo di domanda un riferimento a eventuali riscontri positivi emersi conformemente al paragrafo 1. Tale riferimento è visibile e accessibile solo all’unità centrale ETIAS e all’ufficio SIRENE che ha ricevuto la notifica conformemente al paragrafo 3, a meno che il presente regolamento non preveda altre limitazioni.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "24": {"label": "Articolo 24", "heading": "Norme specifiche per i familiari di cittadini dell’Unione o altri cittadini di paesi terzi che godono del diritto di libera circolazione a norma del diritto dell’Unione", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per i cittadini di paesi terzi di cui all’articolo 2, paragrafo 1, lettera c), l’autorizzazione ai viaggi di cui all’articolo 3, lettera e), è intesa come decisione emessa in virtù del presente regolamento secondo la quale non esistono indicazioni concrete né fondati motivi basati su indicazioni concrete per concludere che la presenza di una persona nel territorio degli Stati membri presenta un rischio per la sicurezza o un alto rischio epidemico ai sensi della direttiva 2004/38/CE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando un cittadino di paese terzo di cui all’articolo 2, paragrafo 1, lettera c), chiede un’autorizzazione ai viaggi, si applicano le norme specifiche seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il richiedente non risponde alla domanda di cui all’articolo 17, paragrafo 4, lettera c);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il richiedente è esentato dal pagamento dei diritti di cui all’articolo 18.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel trattare una domanda di autorizzazione ai viaggi per un cittadino di paese terzo di cui all’articolo 2, paragrafo 1, lettera c), il sistema centrale ETIAS non verifica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente è attualmente segnalato come soggiornante fuoritermine, o se lo è stato in passato, tramite consultazione dell’EES in conformità dell’articolo 20, paragrafo 2, lettera g);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il richiedente corrisponde a una persona i cui dati sono registrati nell’Eurodac in conformità dell’articolo 20, paragrafo 2, lettera k).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Non si applicano gli indicatori di rischio specifici basati su rischi di immigrazione illegale determinati in conformità dell’articolo 33.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Una domanda di autorizzazione ai viaggi non è rifiutata sulla base del rischio di immigrazione illegale di cui all’articolo 37, paragrafo 1, lettera c).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Laddove dal trattamento automatizzato della domanda ai sensi dell’articolo 20 emerga un riscontro positivo in relazione a una segnalazione ai fini del rifiuto d’ingresso e di soggiorno di cui all’articolo 24 del regolamento (CE) n. 1987/2006 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">15</span>\n), l’unità nazionale ETIAS verifica la base della decisione a seguito della quale tale segnalazione è stata inserita nel SIS. Se tale base è connessa a un rischio di immigrazione illegale, la segnalazione non è presa in considerazione ai fini della valutazione della domanda. L’unità nazionale ETIAS procede conformemente all’articolo 25, paragrafo 2, del regolamento (CE) n. 1987/2006.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Si applicano inoltre le norme seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con la comunicazione di cui all’articolo 38, paragrafo 1, il richiedente è informato del fatto che dev’essere in grado di dimostrare, all’atto dell’attraversamento della frontiera esterna, il suo status di familiare di cui all’articolo 2, paragrafo 1, lettera c); tale informazione include un richiamo al fatto che il familiare di un cittadino che esercita il diritto di libera circolazione che è in possesso di un’autorizzazione ai viaggi ha il diritto di entrare soltanto se è accompagnato o raggiunge il cittadino dell’Unione o un altro cittadino di un paese terzo che esercita il diritto di libera circolazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il ricorso di cui all’articolo 37, paragrafo 3, è proposto in conformità della direttiva 2004/38/CE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il periodo di conservazione del fascicolo di domanda di cui all’articolo 54, paragrafo 1:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">corrisponde al periodo di validità dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è di cinque anni a decorrere dall’ultima decisione di rifiuto, annullamento o revoca dell’autorizzazione ai viaggi in conformità degli articoli 37, 40 e 41. Se i dati contenuti in un registro, un fascicolo o una segnalazione registrati in uno dei sistemi d’informazione dell’UE, nei dati Europol, nelle banche dati Interpol SLTD o TDAWN, nell’elenco di controllo ETIAS o nelle regole di esame ETIAS che danno origine a una tale decisione sono cancellati prima della scadenza del periodo di cinque anni, il fascicolo di domanda è soppresso entro sette giorni a decorrere dalla data della cancellazione dei dati in tale registro, fascicolo o segnalazione. A tal fine, il sistema centrale ETIAS verifica regolarmente e automaticamente se le condizioni relative alla conservazione dei fascicoli di domanda di cui al presente punto continuano a essere soddisfatte. Qualora tali condizioni non siano più soddisfatte, il sistema sopprime il fascicolo di domanda in modo automatizzato.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Per facilitare una nuova domanda dopo la scadenza del periodo di validità di un’autorizzazione ai viaggi ETIAS, il fascicolo di domanda può essere conservato nel sistema centrale ETIAS per un ulteriore periodo non superiore a tre anni dalla scadenza del periodo di validità dell’autorizzazione ai viaggi e solo qualora, a seguito di una richiesta di consenso, il richiedente acconsenta liberamente ed esplicitamente mediante una dichiarazione firmata elettronicamente. Le richieste di consenso sono presentate in modo chiaramente distinguibile dalle altre questioni, in forma comprensibile e facilmente accessibile, e utilizzando un linguaggio semplice e chiaro conformemente all’articolo 7 del regolamento (UE) 2016/679 del Parlamento europeo e del Consiglio.</p>"], [null, "<p class=\"norm\">Il consenso è richiesto in seguito alla fornitura di informazioni automatiche ai sensi dell’articolo 15, paragrafo 2. Le informazioni fornite automaticamente ricordano al richiedente la finalità della conservazione dei dati sulla base delle informazioni di cui all’articolo 71, lettera o).</p>"]]}, "25": {"label": "Articolo 25", "heading": "Stato membro competente", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Lo Stato membro competente per il trattamento manuale delle domande ai sensi dell’articolo 26 («Stato membro competente») è individuato dal sistema centrale ETIAS come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora si accerti che i dati per i quali è emerso un riscontro positivo conformemente all’articolo 20 sono stati inseriti o forniti da un solo Stato membro, quest’ultimo è lo Stato membro competente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora si accerti che i dati per i quali è emerso un riscontro positivo conformemente all’articolo 20 sono stati inseriti o forniti da più Stati membri, lo Stato membro competente è:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro che ha inserito o fornito i dati più recenti in relazione a una segnalazione di cui all’articolo 20, paragrafo 2, lettera d); o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se nessuno di tali dati corrisponde a una segnalazione di cui all’articolo 20, paragrafo 2, lettera d), lo Stato membro che ha inserito o fornito i dati più recenti in relazione a una segnalazione di cui all’articolo 20, paragrafo 2, lettera c); o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se nessuno di tali dati corrisponde a una segnalazione di cui all’articolo 20, paragrafo 2, lettere c) o d), lo Stato membro che ha inserito o fornito i dati più recenti su una segnalazione di cui all’articolo 20, paragrafo 2, lettera a);</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora si accerti che i dati per i quali sono emersi riscontri positivi conformemente all’articolo 20 sono stati inseriti o forniti da più Stati membri, ma nessuno di tali dati corrisponda alle segnalazioni di cui all’articolo 20, paragrafo 2, lettere a), c) o d), lo Stato membro competente è quello che ha inserito o fornito i dati più recenti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Ai fini delle lettere a) e c) del primo comma, i riscontri positivi emersi per dati non inseriti o forniti da uno Stato membro non sono presi in considerazione per individuare lo Stato membro competente. Qualora il trattamento manuale di una domanda non sia determinato da dati inseriti o forniti da uno Stato membro, lo Stato membro competente è lo Stato membro del primo soggiorno previsto.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il sistema centrale ETIAS indica lo Stato membro competente nel fascicolo di domanda. Qualora il sistema centrale ETIAS non sia in grado di individuare lo Stato membro competente di cui al paragrafo 1, è l’unità centrale ETIAS a provvedervi.</div>\n</div>"]]}, "25a": {"label": "Articolo 25 bis", "heading": "Uso degli altri sistemi d’informazione dell’UE per il trattamento manuale delle domande da parte delle unità nazionali ETIAS", "anchor": "art_25a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatto salvo l’articolo 13, paragrafo 1, il personale debitamente autorizzato delle unità nazionali ETIAS ha accesso diretto agli altri sistemi d’informazione dell’UE e può consultarli in modalità di sola lettura al fine di esaminare le domande di autorizzazione ai viaggi e decidere al riguardo conformemente all’articolo 26. Le unità nazionali ETIAS possono consultare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati di cui agli articoli 16, 17 e 18 del regolamento (UE) 2017/2226;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati di cui agli articoli da 9 a 14 del regolamento (CE) n. 767/2008;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati di cui all’articolo 20 del regolamento (UE) 2018/1861 trattati ai fini degli articoli 24, 25 e 26 di tale regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati di cui all’articolo 20 del regolamento (UE) 2018/1862 trattati ai fini dell’articolo 26 e dell’articolo 38, paragrafo 2, lettere k) e l), di tale regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati di cui all’articolo 4 del regolamento (UE) 2018/1860 trattati ai fini dell’articolo 3 di tale regolamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nella misura in cui un riscontro positivo è il risultato di una verifica a norma dell’articolo 20, paragrafo 2, lettera n), ai fini di cui al paragrafo 1 del presente articolo, il personale debitamente autorizzato delle unità nazionali ETIAS ha altresì accesso, direttamente o indirettamente e in conformità del diritto nazionale, ai dati pertinenti contenuti nei casellari giudiziali nazionali del proprio Stato membro per ottenere informazioni sui cittadini di paesi terzi, quali definiti nel regolamento (UE) 2019/816, i condannati per reati di terrorismo o altri eventuali reati di cui all’allegato del presente regolamento.</div>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Trattamento manuale delle domande da parte delle unità nazionali ETIAS", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora dal trattamento automatizzato di cui all’articolo 20, paragrafi da 2 a 5, emergano uno o più riscontri positivi, la domanda è trattata manualmente dall’unità nazionale ETIAS dello Stato membro competente. Tale unità nazionale ETIAS ha accesso al fascicolo di domanda e agli eventuali fascicoli di domanda collegati, nonché a tutti i riscontri positivi emersi dal trattamento automatizzato di cui all’articolo 20, paragrafi da 2 a 5. L’unità centrale ETIAS comunica all’unità nazionale ETIAS dello Stato membro competente se i dati per i quali è emerso un riscontro positivo conformemente all’articolo 20, paragrafi 2 o 4, risultano essere stati inseriti o forniti da uno o più altri Stati membri o da Europol. Qualora si accerti che i dati per i quali è emerso il riscontro positivo sono stati inseriti o forniti da uno o più Stati membri, l’unità centrale ETIAS specifica altresì gli Stati membri interessati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In seguito al trattamento manuale della domanda, l’unità nazionale ETIAS dello Stato membro competente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rilascia un’autorizzazione ai viaggi; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rifiuta un’autorizzazione ai viaggi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora dal trattamento automatizzato di cui all’articolo 20, paragrafo 2, emerga un riscontro positivo, l’unità nazionale ETIAS dello Stato membro competente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rifiuta l’autorizzazione ai viaggi se il riscontro positivo corrisponde a una o più delle verifiche di cui all’articolo 20, paragrafo 2, lettere a) e c);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valuta il rischio per la sicurezza o di immigrazione illegale e decide se rilasciare o rifiutare l’autorizzazione ai viaggi se il riscontro positivo corrisponde a una delle verifiche di cui all’articolo 20, paragrafo 2, lettera b), e lettere da d) a o).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora dal trattamento automatizzato di cui all’articolo 20, paragrafo 2, lettera o), emerga un riscontro positivo, l’unità nazionale ETIAS dello Stato membro competente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rifiuta l’autorizzazione ai viaggi del richiedente se la verifica ai sensi dell’articolo 23, paragrafo 2, terzo comma, ha determinato la cancellazione della segnalazione di rimpatrio e l’inserimento di una segnalazione ai fini del rifiuto d’ingresso e di soggiorno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valuta il rischio per la sicurezza o di immigrazione illegale e decide se rilasciare o rifiutare l’autorizzazione ai viaggi in tutti gli altri casi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">L’unità nazionale ETIAS dello Stato membro che ha inserito i dati consulta il proprio ufficio SIRENE per verificare se sia necessaria la cancellazione della segnalazione di rimpatrio a norma dell’articolo 14, paragrafo 1, del regolamento (UE) 2018/1860 e, se del caso, se sia necessario l’inserimento di una segnalazione ai fini del rifiuto d’ingresso e di soggiorno a norma dell’articolo 24, paragrafo 3, del regolamento (UE) 2018/1861.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora dal trattamento automatizzato ai sensi dell’articolo 20, paragrafo 3, risulti che il richiedente ha risposto affermativamente a una delle domande di cui all’articolo 17, paragrafo 4, l’unità nazionale ETIAS dello Stato membro competente valuta il rischio per la sicurezza o di immigrazione illegale e decide se rilasciare o rifiutare l’autorizzazione ai viaggi.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<p class=\"norm\">Qualora dal trattamento automatizzato ai sensi dell’articolo 20, paragrafo 2, lettera n), emerga un riscontro positivo senza tuttavia che ne emerga uno ai sensi della lettera c) del predetto paragrafo, l’unità nazionale ETIAS dello Stato membro competente tiene in particolare considerazione l’assenza di tale riscontro positivo nella sua valutazione del rischio per la sicurezza al fine di decidere se rilasciare o rifiutare l’autorizzazione ai viaggi.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora dal trattamento automatizzato ai sensi dell’articolo 20, paragrafo 4, emerga un riscontro positivo, l’unità nazionale ETIAS dello Stato membro competente valuta il rischio per la sicurezza e decide se rilasciare o rifiutare l’autorizzazione ai viaggi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Qualora dal trattamento automatizzato ai sensi dell’articolo 20, paragrafo 5, emerga un riscontro positivo, l’unità nazionale ETIAS dello Stato membro competente valuta il rischio per la sicurezza, di immigrazione illegale o l’alto rischio epidemico e decide se rilasciare o rifiutare l’autorizzazione ai viaggi. In nessun caso l’unità nazionale ETIAS dello Stato membro competente può adottare una decisione automaticamente sulla base di un riscontro positivo fondato su indicatori di rischio specifici. L’unità nazionale ETIAS dello Stato membro competente valuta individualmente, in tutti i casi, il rischio per la sicurezza, di immigrazione illegale e l’alto rischio epidemico.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il sistema d’informazione ETIAS conserva i registri di tutte le operazioni di trattamento dei dati effettuate per le valutazioni ai sensi del presente articolo dall’unità nazionale ETIAS dello Stato membro competente o dalle unità nazionali ETIAS degli Stati membri consultati a norma dell’articolo 28. Tali registri sono creati e inseriti automaticamente nel fascicolo di domanda e indicano la data e l’ora di ciascuna operazione, i dati utilizzati per la consultazione di altri sistemi d’informazione dell’UE, i dati collegati ai riscontri positivi ricevuti e il membro del personale che ha effettuato la valutazione dei rischi.</div>\n</div>"], [null, "<p class=\"norm\">Il risultato della valutazione del rischio per la sicurezza, di immigrazione illegale o dell’alto rischio epidemico e la giustificazione della decisione di rilasciare o rifiutare un’autorizzazione ai viaggi sono registrati nel fascicolo di domanda dal membro del personale che ha effettuato la valutazione dei rischi.</p>"]]}, "27": {"label": "Articolo 27", "heading": "Richiesta di informazioni o documenti aggiuntivi", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora l’unità nazionale ETIAS dello Stato membro competente ritenga che le informazioni fornite dal richiedente nel modulo di domanda siano insufficienti per consentirle di decidere se rilasciare o rifiutare un’autorizzazione ai viaggi, essa può chiedere al richiedente informazioni o documenti aggiuntivi. L’unità nazionale ETIAS dello Stato membro competente chiede informazioni o documenti aggiuntivi su richiesta di uno Stato membro consultato a norma dell’articolo 28.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La richiesta di informazioni o documenti aggiuntivi è notificata mediante il servizio di posta elettronica di cui all’articolo 6, paragrafo 2, lettera f), all’indirizzo di posta elettronica di contatto riportato nel fascicolo di domanda. Nella richiesta sono chiaramente indicati le informazioni o i documenti aggiuntivi che il richiedente è tenuto a fornire, nonché un elenco delle lingue in cui tali informazioni o documenti possono essere trasmessi. Tale elenco comprende almeno l’inglese, il francese o il tedesco, a meno che non includa una lingua ufficiale del paese terzo di cui il richiedente ha dichiarato di essere cittadino. In caso di richiesta di documenti aggiuntivi, occorre presentare anche una copia elettronica del documento o dei documenti originali. Il richiedente fornisce le informazioni o i documenti aggiuntivi direttamente all’unità nazionale ETIAS dello Stato membro competente tramite il servizio di account sicuro di cui all’articolo 6, paragrafo 2, lettera g), entro dieci giorni a decorrere dalla data di ricevimento della richiesta. Il richiedente fornisce tali informazioni o documenti in una delle lingue indicate nella richiesta. Il richiedente non è tenuto a fornire una traduzione ufficiale. Possono essere richiesti solo informazioni o documenti aggiuntivi necessari per la valutazione della domanda ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini della richiesta di informazioni o documenti aggiuntivi di cui al paragrafo 1, l’unità nazionale ETIAS dello Stato membro competente utilizza un elenco predefinito di opzioni. La Commissione adotta atti delegati in conformità dell’articolo 89 al fine di specificare il contenuto e il formato di detto elenco predefinito di opzioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In circostanze eccezionali, e come <span class=\"italics\">extrema ratio</span>, dopo il trattamento di informazioni o documenti aggiuntivi, quando permangono seri dubbi sulle informazioni o sui documenti forniti dal richiedente, l’unità nazionale ETIAS dello Stato membro competente può convocare il richiedente per un colloquio nel suo paese di residenza presso il consolato più vicino al suo luogo di residenza. In via eccezionale, e se è nell’interesse del richiedente, il colloquio può avere luogo presso un consolato situato in un paese diverso dal paese di residenza del richiedente.</div>\n</div>"], [null, "<p class=\"norm\">Se il consolato più vicino al luogo di residenza del richiedente si trova a una distanza superiore a 500 km, al richiedente è offerta la possibilità di effettuare il colloquio mediante mezzi remoti di comunicazione audio e video. Se la distanza è inferiore a 500 km, il richiedente e l’unità nazionale ETIAS dello Stato membro competente possono decidere di comune accordo di utilizzare ai fini del colloquio tali mezzi di comunicazione audio e video. Qualora siano utilizzati tali mezzi di comunicazione audio e video, i colloqui sono effettuati dall’unità nazionale ETIAS dello Stato membro competente o, in via eccezionale, da uno dei consolati di tale Stato membro. I mezzi di comunicazione a distanza audio e video garantiscono un livello adeguato di sicurezza e di riservatezza.</p>"], [null, "<p class=\"norm\">Il motivo della richiesta di un colloquio è registrato nel fascicolo di domanda.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione definisce, mediante atti di esecuzione, i requisiti dei mezzi di comunicazione audio e video di cui al paragrafo 4, anche per quanto riguarda le norme in materia di protezione, di sicurezza e di riservatezza dei dati e adotta le norme sulla verifica e selezione degli strumenti idonei e adotta le norme relative al loro funzionamento.</div>\n</div>"], [null, "<p class=\"norm\">Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 90, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’unità nazionale ETIAS dello Stato membro competente convoca il richiedente con invito al colloquio notificato mediante il servizio di posta elettronica di cui all’articolo 6, paragrafo 2, lettera f), all’indirizzo di posta elettronica di contatto riportato nel fascicolo di domanda. L’invito al colloquio è notificato entro 72 ore dalla presentazione da parte del richiedente delle informazioni o dei documenti aggiuntivi ai sensi del paragrafo 2 del presente articolo. L’invito al colloquio contiene informazioni sullo Stato membro che lo ha emesso, sulle opzioni di cui al paragrafo 4 del presente articolo e i dati di contatto pertinenti. Il richiedente contatta l’unità nazionale ETIAS dello Stato membro competente o il consolato prima possibile e comunque entro cinque giorni dall’invito al colloquio per concordare ora e data del colloquio e per decidere se tenere il colloquio a distanza. Il colloquio deve avere luogo entro 10 giorni dalla data dell’invito.</div>\n</div>"], [null, "<p class=\"norm\">Il sistema centrale ETIAS registra l’invito al colloquio nel fascicolo di domanda.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualora il richiedente non si presenti al colloquio in conformità del paragrafo 6 del presente articolo a seguito di un invito al colloquio, la domanda è rigettata in conformità dell’articolo 37, paragrafo 1, lettera g). L’unità nazionale ETIAS dello Stato membro competente ne informa senza indugio il richiedente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Ai fini del colloquio di cui al paragrafo 4, l’unità nazionale ETIAS dello Stato membro competente indica gli elementi che dovranno essere trattati dall’intervistatore. Tali elementi devono essere relativi ai motivi per cui è stato richiesto il colloquio.</div>\n</div>"], [null, "<p class=\"norm\">Il colloquio mediante mezzi di comunicazione a distanza audio e video è effettuato nella lingua dell’unità nazionale ETIAS dello Stato membro competente che richiede il colloquio o nella lingua scelta da quest’ultima per la presentazione delle informazioni o dei documenti aggiuntivi.</p>"], [null, "<p class=\"norm\">Il colloquio che ha luogo presso il consolato è effettuato in una lingua ufficiale del paese terzo in cui si trova il consolato o in qualsiasi altra lingua concordata tra il richiedente e il consolato.</p>"], [null, "<p class=\"norm\">Dopo il colloquio, l’intervistatore emette un parere motivando la propria raccomandazione.</p>"], [null, "<p class=\"norm\">Gli elementi trattati e il parere figurano in un modulo che deve essere registrato nel fascicolo di domanda lo stesso giorno in cui ha luogo il colloquio.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Al momento della presentazione da parte del richiedente delle informazioni o dei documenti aggiuntivi in conformità del paragrafo 2, il sistema centrale ETIAS registra e conserva tali informazioni o documenti nel fascicolo di domanda. L’unità nazionale ETIAS dello Stato membro competente aggiunge al fascicolo di domanda le informazioni o i documenti aggiuntivi forniti nel corso di un colloquio ai sensi del paragrafo 6.</div>\n</div>"], [null, "<p class=\"norm\">Il modulo usato per il colloquio e le informazioni o i documenti aggiuntivi registrati nel fascicolo di domanda sono consultati unicamente per valutare la domanda e decidere in merito ad essa, per gestire una procedura di ricorso e per trattare una nuova domanda dello stesso richiedente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">L’unità nazionale ETIAS dello Stato membro competente riassume l’esame della domanda dal momento in cui il richiedente fornisce le informazioni o i documenti aggiuntivi o, se del caso, a decorrere dalla data del colloquio.</div>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Consultazione di altri Stati membri", "anchor": "art_28", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora si accerti che i dati per i quali è emerso un riscontro positivo conformemente all’articolo 20, paragrafo 7, sono stati inseriti o forniti da uno o più Stati membri, a seguito della verifica ai sensi dell’articolo 22, l’unità centrale ETIAS ne informa l’unità nazionale ETIAS dello Stato membro o degli Stati membri interessati, avviando in tal modo un processo di consultazione tra questi e l’unità nazionale ETIAS dello Stato membro competente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le unità nazionali ETIAS degli Stati membri consultati hanno accesso al fascicolo di domanda ai fini della consultazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le unità nazionali ETIAS degli Stati membri consultati esprimono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un parere motivato positivo sulla domanda; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un parere motivato negativo sulla domanda.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il parere positivo o negativo è registrato nel fascicolo di domanda dall’unità nazionale ETIAS dello Stato membro consultato.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<p class=\"norm\">Ai fini del trattamento manuale di cui all’articolo 26, il parere motivato positivo o negativo è visibile unicamente all’unità nazionale ETIAS dello Stato membro consultato e all’unità nazionale ETIAS dello Stato membro competente.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’unità nazionale ETIAS dello Stato membro competente può inoltre consultare le unità nazionali ETIAS di uno o più Stati membri in seguito alla risposta di un richiedente ad una richiesta di informazioni aggiuntive. Qualora tali informazioni aggiuntive siano state richieste per conto di uno Stato membro consultato a norma dell’articolo 27, paragrafo 1, l’unità nazionale ETIAS dello Stato membro competente consulta l’unità nazionale ETIAS di tale Stato membro consultato in seguito alla risposta del richiedente alla richiesta di informazioni aggiuntive. In tali casi, le unità nazionali ETIAS degli Stati membri consultati hanno accesso anche alle informazioni o ai documenti aggiuntivi pertinenti forniti dal richiedente su richiesta dell’unità nazionale ETIAS dello Stato membro competente riguardo alla questione per la quale sono consultate. Se sono consultati più Stati membri, l’unità nazionale ETIAS dello Stato membro competente provvede al coordinamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’unità nazionale ETIAS dello Stato membro consultato risponde entro 60 ore dalla notifica della consultazione. La mancata risposta entro tale termine vale come parere positivo sulla domanda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Durante il processo di consultazione, la richiesta di consultazione e le risposte alla medesima sono trasmesse tramite il software di cui all’articolo 6, paragrafo 2, lettera m), e sono messe a disposizione dell’unità nazionale ETIAS dello Stato membro competente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Se l’unità nazionale ETIAS di almeno uno Stato membro consultato esprime parere negativo sulla domanda, l’unità nazionale ETIAS dello Stato membro competente rifiuta l’autorizzazione ai viaggi a norma dell’articolo 37. Il presente paragrafo fa salvo l’articolo 44.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Se del caso, in presenza di problemi tecnici o circostanze impreviste, l’unità centrale ETIAS determina lo Stato membro competente e gli Stati membri da consultare e facilita le consultazioni tra gli Stati membri di cui al presente articolo.</div>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Consultazione di Europol", "anchor": "art_29", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora si accerti che i dati per i quali è emerso un riscontro positivo conformemente all’articolo 20, paragrafo 8, del presente regolamento sono stati forniti da Europol, l’unità centrale ETIAS ne informa Europol, avviando in tal modo un processo di consultazione tra Europol e l’unità nazionale ETIAS dello Stato membro competente. Tale consultazione è effettuata in conformità del regolamento (UE) 2016/794 e in particolare del capo IV.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In caso di consultazione di Europol, l’unità centrale ETIAS trasmette a Europol i dati pertinenti del fascicolo di domanda e i riscontri positivi necessari ai fini della consultazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In nessun caso Europol ha accesso ai dati personali relativi all’istruzione del richiedente di cui all’articolo 17, paragrafo 2, lettera h).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Quando è consultata a norma del paragrafo 1, Europol esprime un parere motivato sulla domanda. Il parere di Europol è messo a disposizione dell’unità nazionale ETIAS dello Stato membro competente, che lo registra nel fascicolo di domanda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’unità nazionale ETIAS dello Stato membro competente può consultare Europol in seguito alla risposta di un richiedente ad una richiesta di informazioni aggiuntive. In tal caso, l’unità nazionale ETIAS trasmette a Europol le informazioni o i documenti aggiuntivi pertinenti forniti dal richiedente riguardo alla domanda di autorizzazione ai viaggi per la quale Europol è consultata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Europol risponde entro 60 ore dalla notifica della consultazione. La mancata risposta di Europol entro tale termine vale come parere positivo sulla domanda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Durante il processo di consultazione, la richiesta di consultazione e le risposte alla medesima sono trasmesse tramite il software di cui all’articolo 6, paragrafo 2, lettera m), e sono messe a disposizione dell’unità nazionale ETIAS dello Stato membro competente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Se Europol esprime parere negativo sulla domanda e l’unità nazionale ETIAS dello Stato membro competente decide di rilasciare l’autorizzazione ai viaggi, giustifica la sua decisione e la registra nel fascicolo di domanda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Se del caso, in presenza di problemi tecnici o circostanze impreviste, l’unità centrale ETIAS determina lo Stato membro competente e facilita le consultazioni tra quest’ultimo ed Europol di cui al presente articolo.</div>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Termini per la notifica al richiedente", "anchor": "art_30", "frags": [[null, "<p class=\"norm\">Entro 96 ore dalla presentazione di una domanda ammissibile ai sensi dell’articolo 19, il richiedente riceve una notifica che indica:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se l’autorizzazione ai viaggi gli è rilasciata o rifiutata; oppure</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che sono richiesti informazioni o documenti aggiuntivi e che il richiedente può essere convocato per un colloquio, con indicazione dei tempi massimi di trattamento applicabili ai sensi dell’articolo 32, paragrafo 2.</p>\n</div>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Strumento di verifica", "anchor": "art_31", "frags": [[null, "<p class=\"norm\">La Commissione predispone uno strumento di verifica per consentire ai richiedenti di verificare lo status delle loro domande nonché la durata della validità e lo status delle loro autorizzazioni ai viaggi (valida, rifiutata, annullata o revocata). Tale strumento è reso accessibile tramite l’apposito sito web pubblico o l’applicazione per dispositivi mobili di cui all’articolo 16.</p>"], [null, "<p class=\"norm\">La Commissione adotta atti delegati conformemente all’articolo 89 per definire ulteriormente lo strumento di verifica.</p>"]]}, "32": {"label": "Articolo 32", "heading": "Decisione sulla domanda", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Una decisione sulla domanda è adottata entro 96 ore dalla presentazione di una domanda ammissibile ai sensi dell’articolo 19.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Eccezionalmente, se è notificata una richiesta di informazioni o documenti aggiuntivi e se il richiedente è convocato per un colloquio, il termine di cui al paragrafo 1 del presente articolo è prorogato. La decisione sulla domanda è adottata entro 96 ore dalla presentazione delle informazioni o dei documenti aggiuntivi da parte del richiedente. Se il richiedente è convocato per un colloquio conformemente all’articolo 27, paragrafo 4, la decisione sulla domanda è adottata entro 48 ore da quando il colloquio ha avuto luogo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Prima della scadenza dei termini di cui ai paragrafi 1 e 2 del presente articolo è adottata la decisione di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rilasciare un’autorizzazione ai viaggi in conformità dell’articolo 36; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rifiutare un’autorizzazione ai viaggi in conformità dell’articolo 37.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Regole di esame ETIAS", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le norme di esame ETIAS sono un algoritmo che permette la profilazione, quale definita all’articolo 4, punto 4), del regolamento (UE) 2016/679, mediante il confronto a norma dell’articolo 20 del presente regolamento dei dati registrati in un fascicolo di domanda del sistema centrale ETIAS con indicatori di rischio specifici stabiliti dall’unità centrale ETIAS ai sensi del paragrafo 4 del presente articolo, relativi ai rischi per la sicurezza, di immigrazione illegale o all’alto rischio epidemico. L’unità centrale ETIAS registra le regole di esame ETIAS nel sistema centrale ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione adotta un atto delegato conformemente all’articolo 89 al fine di definire ulteriormente tali rischi per la sicurezza, di immigrazione illegale o l’alto rischio epidemico in base a:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">statistiche generate dall’EES che indicano tassi anormali di soggiornanti fuoritermine e respingimenti per uno specifico gruppo di viaggiatori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">statistiche generate dall’ETIAS in conformità dell’articolo 84 indicanti tassi anormali di rifiuto di autorizzazioni ai viaggi dovuti a un rischio per la sicurezza, di immigrazione illegale o a un alto rischio epidemico associato a uno specifico gruppo di viaggiatori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">statistiche generate dall’ETIAS in conformità dell’articolo 84 e dall’EES indicanti correlazioni tra informazioni raccolte tramite il modulo di domanda e soggiornanti fuoritermine o respingimenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni, suffragate da elementi fattuali e basati su dati concreti, fornite da Stati membri relative a indicatori di rischio specifici o minacce per la sicurezza individuati dagli Stati membri in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni, suffragate da elementi fattuali e basati su dati concreti, fornite da Stati membri relative a tassi anormali di soggiornanti fuoritermine e respingimenti per uno specifico gruppo di viaggiatori in tali Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni su alti rischi epidemici specifici fornite da Stati membri e informazioni in materia di sorveglianza epidemiologica e valutazioni del rischio fornite dall’ECDC nonché segnalazioni di focolai di malattie da parte dell’OMS.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione, mediante atti di esecuzione, specificai rischi, come definiti nel presente regolamento e nell’atto delegato di cui al paragrafo 2 del presente articolo, sui quali si basano gli indicatori di rischio specifici di cui al paragrafo 4 del presente articolo. Tale atto di esecuzione è adottato secondo la procedura d’esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"], [null, "<p class=\"norm\">I rischi specifici sono riesaminati almeno ogni sei mesi e, se necessario, la Commissione adotta un nuovo atto di esecuzione secondo la procedura d’esame di cui all’articolo 90, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sulla base dei rischi specifici rilevati in conformità del paragrafo 3, l’unità centrale ETIAS stabilisce indicatori di rischio specifici consistenti in una combinazione di uno o più dei dati seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fascia di età, sesso, cittadinanza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">paese e città di residenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">livello di istruzione (primaria, secondaria, superiore o nessuna istruzione);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attuale occupazione (gruppo di posizioni lavorative).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli indicatori di rischio specifici sono mirati e proporzionati. Essi non sono in alcun caso basati esclusivamente sul sesso o sull’età di una persona. Non sono in alcun caso basati su informazioni che rivelino il colore della pelle, la razza, l’origine etnica o sociale, le caratteristiche genetiche, la lingua, le opinioni politiche o di qualsiasi altra natura, la religione o le convinzioni filosofiche, l’appartenenza sindacale, l’appartenenza a una minoranza nazionale, il patrimonio, la nascita, la disabilità o l’orientamento sessuale di una persona.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’unità centrale ETIAS, previa consultazione della commissione di esame ETIAS, definisce, stabilisce, valuta preliminarmente, attua, valuta a posteriori, rivede ed elimina gli indicatori di rischio specifici.</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Elenco di controllo ETIAS", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’elenco di controllo ETIAS consta di dati relativi a persone sospettate di aver commesso o partecipato a un reato di terrorismo o altro reato grave o a persone riguardo alle quali vi sono indicazioni concrete o fondati motivi, sulla base di una valutazione globale della persona, per ritenere che possano commettere un reato di terrorismo o altri reati gravi. L’elenco di controllo ETIAS fa parte del sistema centrale ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’elenco di controllo ETIAS è stabilito sulla base di informazioni relative a reati di terrorismo o altri reati gravi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le informazioni di cui al paragrafo 2, sono inserite nell’elenco di controllo ETIAS da Europol, fatto salvo il regolamento (UE) 2016/794, o dagli Stati membri. Europol o lo Stato membro interessato è responsabile di tutti i dati da esso inseriti. L’elenco di controllo ETIAS indica, per ciascun dato, la data e l’ora dell’inserimento da parte di Europol o dello Stato membro che l’ha inserito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sulla base delle informazioni di cui al paragrafo 2, l’elenco di controllo ETIAS è composto da dati consistenti in uno o più dei seguenti elementi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome alla nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altri nomi (pseudonimi, nomi d’arte, soprannomi);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">documento o documenti di viaggio (tipo, numero e paese di rilascio);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">domicilio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indirizzo di posta elettronica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numero di telefono;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">denominazione, indirizzo di posta elettronica, indirizzo postale e numero di telefono della ditta o organizzazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indirizzo IP.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se disponibili, sono aggiunti al relativo punto, costituito da almeno uno degli elementi sopra elencati, gli elementi seguenti: nome o nomi, luogo e paese di nascita, sesso e cittadinanza.</p>"]]}, "35": {"label": "Articolo 35", "heading": "Responsabilità e compiti relativi all’elenco di controllo ETIAS", "anchor": "art_35", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Prima che Europol o uno Stato membro inseriscano i dati nell’elenco di controllo ETIAS, essi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabiliscono se le informazioni siano adeguate, esatte e sufficientemente importanti da essere inserite nell’elenco di controllo ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valutano il potenziale impatto dei dati sulla parte di domande trattate manualmente.</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verificano se i rispettivi dati corrispondano a una segnalazione inserita nel SIS.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">eu-LISA attua uno strumento specifico ai fini della valutazione ai sensi del paragrafo 1, lettera b).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Laddove la verifica ai sensi del paragrafo 1, lettera c) riveli che i dati corrispondono a una segnalazione inserita nel SIS, tali dati non sono inseriti nell’elenco di controllo ETIAS. Se sono soddisfatte le condizioni di utilizzo dei dati ai fini dell’inserimento di una segnalazione nel SIS, è data priorità all’inserimento di una segnalazione nel SIS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri ed Europol sono responsabili dell’accuratezza dei dati di cui all’articolo 34, paragrafo 2, che inseriscono nell’elenco di controllo ETIAS, nonché del loro aggiornamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Europol riesamina e verifica periodicamente, e almeno una volta l’anno, la continua accuratezza dei dati che ha inserito nell’elenco di controllo ETIAS. Gli Stati membri, allo stesso modo, riesaminano e verificano, regolarmente e almeno una volta l’anno, la continua accuratezza dei dati che hanno inserito nell’elenco di controllo ETIAS. Europol e gli Stati membri elaborano ed attuano una procedura congiunta volta a garantire l’adempimento dei loro obblighi ai sensi del presente paragrafo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">A seguito del riesame, gli Stati membri ed Europol ritirano i dati dall’elenco di controllo ETIAS se è dimostrato che i motivi per cui erano stati inseriti non sono più validi o che i dati sono obsoleti o non aggiornati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’elenco di controllo ETIAS e lo strumento di valutazione di cui ai paragrafi 1 e 2 del presente articolo sono sviluppati a livello tecnico e ospitati da eu-LISA. La Commissione stabilisce, mediante atti di esecuzione, le specifiche tecniche dell’elenco di controllo ETIAS e dello strumento di valutazione. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Rilascio di un’autorizzazione ai viaggi", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora, dall’esame di una domanda secondo le procedure di cui ai capi III, IV e V, risulti che non esistono indicazioni concrete né fondati motivi basati su indicazioni concrete per concludere che la presenza di una persona nel territorio degli Stati membri presenta un rischio per la sicurezza, di immigrazione illegale o un alto rischio epidemico, il sistema centrale ETIAS o l’unità nazionale ETIAS dello Stato membro competente rilascia un’autorizzazione ai viaggi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In caso di dubbi in merito all’esistenza di motivi sufficienti per rifiutare l’autorizzazione ai viaggi, l’unità nazionale ETIAS dello Stato membro competente ha la possibilità, anche dopo un colloquio, di rilasciare un’autorizzazione ai viaggi con un indicatore volto a raccomandare alle autorità di frontiera di procedere a una verifica in seconda linea.</div>\n</div>"], [null, "<p class=\"norm\">L’unità nazionale ETIAS dello Stato membro competente può aggiungere tale indicatore anche su richiesta di uno Stato membro consultato. Tale indicatore è visibile soltanto alle autorità di frontiera.</p>"], [null, "<p class=\"norm\">L’indicatore è eliminato automaticamente dopo che tali autorità hanno effettuato il controllo e hanno inserito la cartella di ingresso nell’EES.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’unità nazionale ETIAS dello Stato membro competente ha la possibilità di aggiungere un indicatore che segnali alle autorità di frontiera e alle altre autorità che hanno accesso ai dati del sistema centrale ETIAS che è stato valutato un riscontro positivo specifico emerso durante il trattamento della domanda e che è stato verificato che esso costituiva un falso riscontro positivo o che il trattamento manuale ha dimostrato che non vi era alcun motivo per rifiutare un’autorizzazione ai viaggi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti delegati conformemente all’articolo 89 per istituire adeguate salvaguardie per mezzo di regole e procedure destinate a evitare conflitti con le segnalazioni in altri sistemi d’informazione e per definire le condizioni, i criteri e la durata dell’apposizione di un indicatore ai sensi del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’autorizzazione ai viaggi è valida per tre anni o fino al termine di validità del documento di viaggio registrato al momento della domanda, se precedente, ed è valida nel territorio degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’autorizzazione ai viaggi non conferisce automaticamente un diritto d’ingresso o di soggiorno.</div>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Rifiuto di un’autorizzazione ai viaggi", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’autorizzazione ai viaggi è rifiutata se il richiedente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ha utilizzato un documento di viaggio segnalato come smarrito, rubato, altrimenti sottratto o invalidato nel SIS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presenta un rischio per la sicurezza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presenta un rischio di immigrazione illegale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presenta un alto rischio epidemico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è oggetto di una segnalazione inserita nel SIS ai fini del rifiuto d’ingresso e di soggiorno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non risponde a una richiesta di informazioni o documenti aggiuntivi entro i termini di cui all’articolo 27;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non si presenta al colloquio di cui all’articolo 27, paragrafo 4.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’autorizzazione ai viaggi è inoltre rifiutata se, al momento della presentazione della domanda, sussistono ragionevoli e seri dubbi circa l’autenticità dei dati, l’affidabilità delle dichiarazioni presentate dal richiedente, i documenti giustificativi presentati dal richiedente o la veridicità del loro contenuto.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I richiedenti le cui domande di autorizzazione ai viaggi sono state rifiutate hanno il diritto di presentare ricorso. I ricorsi sono proposti nello Stato membro che ha adottato la decisione sulla domanda e conformemente alla sua legislazione nazionale. Durante la procedura di ricorso, il ricorrente ha accesso alle informazioni contenute nel fascicolo di domanda conformemente alle norme in materia di protezione di dati di cui all’articolo 56 del presente regolamento. L’unità nazionale ETIAS dello Stato membro competente fornisce ai richiedenti le informazioni sulla procedura di ricorso. Tali informazioni sono fornite in una delle lingue ufficiali dei paesi che figurano nell’elenco dell’allegato II del regolamento (CE) n. 539/2001 di cui il richiedente è cittadino.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Un precedente rifiuto dell’autorizzazione ai viaggi non comporta il rifiuto automatico di una nuova domanda. Una nuova domanda è valutata sulla base di tutte le informazioni disponibili.</div>\n</div>"]]}, "38": {"label": "Articolo 38", "heading": "Comunicazione sul rilascio o rifiuto dell’autorizzazione ai viaggi", "anchor": "art_38", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando è rilasciata un’autorizzazione ai viaggi, il richiedente riceve immediatamente, tramite il servizio di posta elettronica, una comunicazione comprendente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la chiara attestazione del rilascio dell’autorizzazione ai viaggi e il numero di domanda dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data di decorrenza e di scadenza dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la chiara attestazione che, all’ingresso, il richiedente dovrà presentare lo stesso documento di viaggio indicato nel modulo di domanda e che qualsiasi modifica del documento di viaggio richiederà una nuova domanda di autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un richiamo alle condizioni d’ingresso di cui all’articolo 6 del regolamento (UE) 2016/399 e al fatto che un soggiorno di breve durata è possibile esclusivamente per una durata non superiore a 90 giorni su un periodo di 180 giorni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un richiamo al fatto che il semplice possesso di un’autorizzazione ai viaggi non conferisce automaticamente un diritto d’ingresso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un richiamo al fatto che le autorità di frontiera possono richiedere documenti giustificativi alle frontiere esterne al fine di verificare l’adempimento delle condizioni d’ingresso e di soggiorno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un richiamo al fatto che il possesso di un’autorizzazione ai viaggi valida costituisce una condizione di soggiorno che deve essere rispettata per l’intera durata del soggiorno di breve durata nel territorio degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un collegamento al servizio web di cui all’articolo 13 del regolamento (UE) 2017/2226 che consenta ai cittadini di paesi terzi di verificare in qualsiasi momento il loro soggiorno rimanente autorizzato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, gli Stati membri nei quali il richiedente è autorizzato a viaggiare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un link al sito web pubblico dell’ETIAS contenente informazioni sulla possibilità per il richiedente di chiedere la revoca dell’autorizzazione ai viaggi, sulla possibilità che l’autorizzazione ai viaggi sia revocata se le condizioni per il suo rilascio non sono più soddisfatte e sulla possibilità che sia annullata qualora risulti che le condizioni di rilascio della stessa non erano soddisfatte al momento del rilascio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulle procedure per esercitare i diritti di cui agli articoli da 13 a 16 del regolamento (CE) n. 45/2001 e agli articoli da 15 a 18 del regolamento (UE) 2016/679; i dati di contatto del responsabile della protezione dei dati dell’Agenzia europea della guardia di frontiera e costiera, del Garante europeo della protezione dei dati e dell’autorità nazionale di controllo dello Stato membro di primo soggiorno previsto, se l’autorizzazione ai viaggi è stata rilasciata dal sistema centrale ETIAS, o dello Stato membro competente, se l’autorizzazione ai viaggi è stata rilasciata da un’unità nazionale ETIAS.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando un’autorizzazione ai viaggi è rifiutata, il richiedente riceve immediatamente, tramite il servizio di posta elettronica, una comunicazione comprendente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la chiara attestazione del rifiuto dell’autorizzazione ai viaggi e il numero di domanda dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riferimento all’unità nazionale ETIAS dello Stato membro competente che ha rifiutato l’autorizzazione ai viaggi e il suo indirizzo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attestazione dei motivi del rifiuto dell’autorizzazione ai viaggi, con indicazione del motivo applicabile tra quelli elencati all’articolo 37, paragrafi 1 e 2, in modo da consentire al richiedente di presentare ricorso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni sul diritto di presentare ricorso e sul relativo termine; un link alle informazioni di cui all’articolo 16, paragrafo 7, sul sito web;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulle procedure per esercitare i diritti di cui agli articoli da 13 a 16 del regolamento (CE) n. 45/2001 e agli articoli da 15 a 18 del regolamento (UE) 2016/679; i dati di contatto del responsabile della protezione dei dati dell’Agenzia europea della guardia di frontiera e costiera, del Garante europeo della protezione dei dati e dell’autorità nazionale di controllo dello Stato membro competente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante atti di esecuzione, un modulo standard per il rifiuto, l’annullamento o la revoca di un’autorizzazione ai viaggi. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Dati da aggiungere al fascicolo di domanda a seguito della decisione di rilascio o di rifiuto dell’autorizzazione ai viaggi", "anchor": "art_39", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando è stata adottata una decisione di rilascio di un’autorizzazione ai viaggi, il sistema centrale ETIAS o, se la decisione è stata adottata a seguito del trattamento manuale di cui al capo IV, l’unità nazionale ETIAS dello Stato membro competente aggiunge senza indugio al fascicolo di domanda i dati seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sullo status con indicazione del rilascio dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riferimento che indichi se l’autorizzazione ai viaggi è stata rilasciata dal sistema centrale ETIAS o a seguito di trattamento manuale; in quest’ultimo caso, è aggiunto un riferimento all’unità nazionale ETIAS dello Stato membro competente che ha adottato la decisione e il suo indirizzo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data della decisione di rilascio dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data iniziale e finale dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eventuali indicatori posti a corredo dell’autorizzazione ai viaggi conformemente all’articolo 36, paragrafi 2 e 3, con indicazione dei motivi di tale o tali indicatori, nonché informazioni aggiuntive rilevanti per le verifiche in seconda linea, nel caso dell’articolo 36, paragrafo 2, e informazioni aggiuntive rilevanti per le autorità di frontiera, nel caso dell’articolo 36, paragrafo 3.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti delegati conformemente all’articolo 89 per definire ulteriormente il tipo, la lingua e il formato delle informazioni aggiuntive che possono essere aggiunte, nonché i motivi degli indicatori.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando è adottata una decisione di rifiuto di un’autorizzazione ai viaggi, l’unità nazionale ETIAS dello Stato membro competente aggiunge al fascicolo di domanda i dati seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sullo status con indicazione del rifiuto dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riferimento all’unità nazionale ETIAS dello Stato membro competente che ha rifiutato l’autorizzazione ai viaggi e il suo indirizzo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data della decisione di rifiuto dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i motivi del rifiuto dell’autorizzazione ai viaggi, con indicazione dei motivi tra quelli elencati all’articolo 37, paragrafi 1 e 2.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Oltre ai dati di cui ai paragrafi 1 e 3, quando è adottata una decisione di rilascio o di rifiuto di un’autorizzazione ai viaggi, l’unità nazionale ETIAS dello Stato membro competente aggiunge anche i motivi della sua decisione finale, a meno che non si tratti di una decisione di rifiuto fondata su un parere negativo di uno Stato membro consultato.</div>\n</div>"]]}, "40": {"label": "Articolo 40", "heading": "Annullamento dell’autorizzazione ai viaggi", "anchor": "art_40", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’autorizzazione ai viaggi è annullata qualora risulti che le condizioni di rilascio della stessa non erano soddisfatte al momento del rilascio. L’autorizzazione ai viaggi è annullata sulla base di uno o più dei motivi di rifiuto dell’autorizzazione ai viaggi di cui all’articolo 37, paragrafi 1 e 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se uno Stato membro dispone di prove indicanti che le condizioni di rilascio di un’autorizzazione ai viaggi non erano soddisfatte al momento del rilascio, l’unità nazionale ETIAS di tale Stato membro annulla l’autorizzazione ai viaggi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La persona la cui autorizzazione ai viaggi è stata annullata ha il diritto di presentare ricorso. I ricorsi sono proposti nello Stato membro che ha preso la decisione sull’annullamento e conformemente alla sua legislazione nazionale. L’unità nazionale ETIAS dello Stato membro competente fornisce ai richiedenti le informazioni sulla procedura di ricorso. Le informazioni sono fornite in una delle lingue ufficiali dei paesi che figurano nell’elenco dell’allegato II del regolamento (CE) n. 539/2001 di cui il richiedente è cittadino.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La giustificazione della decisione di annullare un’autorizzazione ai viaggi è registrata nel fascicolo di domanda dal membro del personale che ha effettuato la valutazione del rischio.</div>\n</div>"]]}, "41": {"label": "Articolo 41", "heading": "Revoca dell’autorizzazione ai viaggi", "anchor": "art_41", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’autorizzazione ai viaggi è revocata qualora risulti che le condizioni di rilascio della stessa non sono più soddisfatte. L’autorizzazione ai viaggi è revocata sulla base di uno o più dei motivi di rifiuto dell’autorizzazione ai viaggi di cui all’articolo 37, paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se uno Stato membro dispone di prove indicanti che le condizioni di rilascio dell’autorizzazione ai viaggi non sono più soddisfatte, l’unità nazionale ETIAS di tale Stato membro revoca l’autorizzazione ai viaggi.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 2, qualora sia inserita una nuova segnalazione nel SIS relativa a un rifiuto d’ingresso e di soggiorno o relativa ad un documento di viaggio segnalato come smarrito, rubato, altrimenti sottratto o invalidato, il SIS ne informa il sistema centrale ETIAS. Il sistema centrale ETIAS verifica se la nuova segnalazione corrisponde a un’autorizzazione ai viaggi valida. In caso affermativo, il sistema centrale ETIAS trasferisce il fascicolo di domanda all’unità nazionale ETIAS dello Stato membro che ha inserito la segnalazione. Qualora sia stata inserita una nuova segnalazione ai fini del rifiuto d’ingresso e di soggiorno, l’unità nazionale ETIAS revoca l’autorizzazione ai viaggi. Qualora l’autorizzazione ai viaggi sia collegata a un documento di viaggio segnalato come smarrito, rubato, altrimenti sottratto o invalidato nel SIS o nella banca dati Interpol SLTD, l’unità nazionale ETIAS tratta manualmente il fascicolo di domanda.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Eventuali nuovi dati inseriti nell’elenco di controllo ETIAS sono confrontati con i dati contenuti nei fascicoli di domanda del sistema centrale ETIAS. Il sistema centrale ETIAS verifica se tali nuovi dati corrispondono a un’autorizzazione ai viaggi valida. In caso affermativo, il sistema centrale ETIAS trasferisce il fascicolo di domanda all’unità nazionale ETIAS dello Stato membro che ha inserito i nuovi dati o, qualora i nuovi dati siano stato inseriti da Europol, all’unità nazionale ETIAS dello Stato membro di primo soggiorno previsto dichiarato dal richiedente in conformità dell’articolo 17, paragrafo 2, lettera j). L’unità nazionale ETIAS valuta il rischio per la sicurezza e revoca l’autorizzazione ai viaggi qualora giunga alla conclusione che le condizioni per il suo rilascio non sono più soddisfatte.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora sia inserita nell’EES una cartella relativa al respingimento del titolare di un’autorizzazione ai viaggi valida e tale registrazione sia giustificata sulla base dei motivi B o I di cui all’allegato V, parte B, del regolamento (UE) 2016/399, il sistema centrale ETIAS trasferisce il fascicolo di domanda all’unità nazionale ETIAS dello Stato membro che ha proceduto al respingimento. L’unità nazionale ETIAS valuta se le condizioni per il rilascio dell’autorizzazione ai viaggi sono ancora soddisfatte e in caso negativo procede alla revoca dell’autorizzazione ai viaggi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La giustificazione della decisione di revocare un’autorizzazione ai viaggi è registrata nel fascicolo di domanda dal membro del personale che ha effettuato la valutazione del rischio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il richiedente la cui autorizzazione ai viaggi è stata revocata ha il diritto di presentare ricorso. I ricorsi sono proposti nello Stato membro che ha adottato la decisione sulla revoca e conformemente alla sua legislazione nazionale. L’unità nazionale ETIAS dello Stato membro competente fornisce ai richiedenti le informazioni sulla procedura di ricorso. Le informazioni sono fornite in una delle lingue ufficiali dei paesi che figurano nell’elenco dell’allegato II del regolamento (CE) n. 539/2001 di cui il richiedente è cittadino.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">L’autorizzazione ai viaggi può essere revocata su richiesta del richiedente. Non è ammesso il ricorso contro una revoca su tale base. Se al momento della presentazione di tale richiesta il richiedente si trova nel territorio di uno Stato membro, la revoca diventa effettiva al momento dell’uscita del richiedente dal territorio e dal momento della creazione della corrispondente cartella di ingresso/uscita nell’EES conformemente all’articolo 16, paragrafo 3, e all’articolo 17, paragrafo 2, del regolamento (UE) 2017/2226.</div>\n</div>"]]}, "42": {"label": "Articolo 42", "heading": "Notifica dell’annullamento o della revoca dell’autorizzazione ai viaggi", "anchor": "art_42", "frags": [[null, "<p class=\"norm\">Quando un’autorizzazione ai viaggi è annullata o revocata, il richiedente riceve immediatamente, tramite il servizio di posta elettronica, una notifica comprendente:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’attestazione chiara dell’annullamento o della revoca dell’autorizzazione ai viaggi e il numero di domanda dell’autorizzazione ai viaggi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riferimento all’unità nazionale ETIAS dello Stato membro competente che ha annullato o revocato l’autorizzazione ai viaggi e il suo indirizzo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’attestazione dei motivi dell’annullamento o della revoca dell’autorizzazione ai viaggi, con indicazione dei motivi applicabili tra quelli elencati all’articolo 37, paragrafi 1 e 2, in modo da consentire al richiedente di presentare ricorso;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni sul diritto di presentare ricorso e sul relativo termine; un link alle informazioni di cui all’articolo 16, paragrafo 7, sul sito web;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la chiara attestazione che il possesso di un’autorizzazione ai viaggi valida costituisce una condizione di soggiorno che deve essere soddisfatta per l’intera durata del soggiorno di breve durata nel territorio degli Stati membri;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulle procedure per esercitare i diritti di cui agli articoli da 13 a 16 del regolamento (CE) n. 45/2001 e agli articoli da 15 a 18 del regolamento (UE) 2016/679 e sui dati di contatto del responsabile della protezione dei dati dell’Agenzia europea della guardia di frontiera e costiera, del Garante europeo della protezione dei dati e dell’autorità nazionale di controllo dello Stato membro competente.</p>\n</div>\n</div>"]]}, "43": {"label": "Articolo 43", "heading": "Dati da aggiungere al fascicolo di domanda in seguito alla decisione di annullamento o di revoca dell’autorizzazione ai viaggi", "anchor": "art_43", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando è adottata una decisione di annullamento o di revoca di un’autorizzazione ai viaggi, l’unità nazionale ETIAS dello Stato membro competente che ha annullato o revocato l’autorizzazione ai viaggi aggiunge senza indugio al fascicolo di domanda i dati seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sullo status con indicazione dell’annullamento o della revoca dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riferimento all’unità nazionale ETIAS dello Stato membro competente che ha revocato o annullato l’autorizzazione ai viaggi e il suo indirizzo; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data della decisione di annullamento o di revoca dell’autorizzazione ai viaggi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’unità nazionale ETIAS dello Stato membro competente che ha annullato o revocato l’autorizzazione ai viaggi indica altresì nel fascicolo di domanda il motivo o i motivi dell’annullamento o della revoca che sono applicabili ai sensi dell’articolo 37, paragrafi 1 e 2, o che l’autorizzazione ai viaggi è stata revocata su richiesta del richiedente ai sensi dell’articolo 41, paragrafo 8.</div>\n</div>"]]}, "44": {"label": "Articolo 44", "heading": "Rilascio di un’autorizzazione ai viaggi con validità territoriale limitata per motivi umanitari o di interesse nazionale o in virtù di obblighi internazionali", "anchor": "art_44", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora una domanda sia stata ritenuta ammissibile in conformità dell’articolo 19, lo Stato membro in cui il cittadino di paese terzo interessato intende recarsi può eccezionalmente rilasciare un’autorizzazione ai viaggi con validità territoriale limitata se tale Stato membro lo ritiene necessario per motivi umanitari ai sensi del proprio diritto nazionale o di interesse nazionale o in virtù di obblighi internazionali, nonostante il fatto che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non sia ancora ultimato il trattamento manuale di cui all’articolo 26; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’autorizzazione ai viaggi sia stata rifiutata, annullata o revocata.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Tali autorizzazioni saranno generalmente valide solo nel territorio dello Stato membro che le ha rilasciate. Tuttavia, eccezionalmente, esse possono essere rilasciate con una validità territoriale che comprende più di uno Stato membro, a condizione che vi sia il consenso di ognuno di tali Stati membri attraverso le loro unità nazionali ETIAS. Qualora un’unità nazionale ETIAS stia valutando il rilascio di un’autorizzazione ai viaggi con validità territoriale limitata che copre diversi Stati membri, tale unità nazionale ETIAS dello Stato membro competente consulta tali Stati membri.</p>"], [null, "<p class=\"norm\">La richiesta o il rilascio di un’autorizzazione ai viaggi con validità territoriale limitata nelle circostanze di cui al primo comma, lettera a), del presente paragrafo non interrompe il trattamento manuale della domanda che consente il rilascio di un’autorizzazione ai viaggi senza validità territoriale limitata.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1, e come indicato sul sito web pubblico e sull’applicazione per dispositivi mobili, il richiedente può contattare l’unità centrale ETIAS indicando il suo numero di domanda, lo Stato membro in cui intende recarsi e che lo scopo del suo viaggio si fonda su motivi umanitari o è collegato a obblighi internazionali. Qualora tale contatto abbia luogo, l’unità centrale ETIAS ne informa l’unità nazionale ETIAS dello Stato membro in cui il cittadino di paese terzo intende recarsi e registra le informazioni nel fascicolo di domanda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’unità nazionale ETIAS dello Stato membro in cui il cittadino di paese terzo intende recarsi può chiedere informazioni o documenti aggiuntivi al richiedente e può fissare il termine entro cui tali informazioni o documenti aggiuntivi devono essere presentati. Tale richiesta è notificata tramite il servizio di posta elettronica di cui all’articolo 6, paragrafo 2, lettera f), all’indirizzo di posta elettronica di contatto registrato nel fascicolo di domanda, e indica un elenco delle lingue in cui le informazioni o i documenti possono essere forniti. Tale elenco comprende almeno l’inglese, il francese o il tedesco, a meno che non includa una lingua ufficiale del paese terzo di cui il richiedente ha dichiarato di essere cittadino. Il richiedente non è tenuto a fornire una traduzione ufficiale in tali lingue. Il richiedente fornisce le informazioni o i documenti aggiuntivi direttamente all’unità nazionale ETIAS tramite il servizio di account sicuro di cui all’articolo 6, paragrafo 2, lettera g). Al momento della presentazione delle informazioni o dei documenti aggiuntivi, il sistema centrale ETIAS registra e conserva tali informazioni o documenti nel fascicolo di domanda. Le informazioni o i documenti aggiuntivi registrati nel fascicolo di domanda sono consultati unicamente per valutare e decidere in merito alla domanda, per gestire una procedura di ricorso ovvero per trattare una nuova domanda dello stesso richiedente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’autorizzazione ai viaggi con validità territoriale limitata è valida per un massimo di 90 giorni a decorrere dalla data del primo ingresso sulla base di tale autorizzazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le autorizzazioni ai viaggi rilasciate ai sensi del presente articolo possono essere soggette ad un indicatore ai sensi dell’articolo 36, paragrafi 2 o 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando è rilasciata un’autorizzazione ai viaggi con validità territoriale limitata, l’unità nazionale ETIAS che ha rilasciato tale autorizzazione aggiunge nel fascicolo di domanda i dati seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sullo status con indicazione del rilascio di un’autorizzazione ai viaggi con validità territoriale limitata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro o gli Stati membri in cui il titolare dell’autorizzazione ai viaggi può viaggiare e il periodo di validità dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’unità nazionale ETIAS dello Stato membro che ha rilasciato l’autorizzazione ai viaggi con validità territoriale limitata e il suo indirizzo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data della decisione di rilascio dell’autorizzazione ai viaggi con validità territoriale limitata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riferimento ai motivi umanitari, ai motivi di interesse nazionale o agli obblighi internazionali invocati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eventuali indicatori posti a corredo dell’autorizzazione ai viaggi conformemente all’articolo 36, paragrafi 2 e 3, con indicazione dei motivi di tale o tali indicatori, nonché informazioni aggiuntive rilevanti perle verifiche in seconda linea, nel caso dell’articolo 36, paragrafo 2, e informazioni aggiuntive rilevanti per le autorità di frontiera, nel caso dell’articolo 36, paragrafo 3.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se un’unità nazionale ETIAS rilascia un’autorizzazione ai viaggi con validità territoriale limitata senza che il richiedente abbia presentato informazioni o documenti, tale unità nazionale ETIAS registra e conserva le informazioni o i documenti appropriati che giustificano tale decisione nel fascicolo di domanda.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando è rilasciata un’autorizzazione ai viaggi con validità territoriale limitata, il richiedente riceve, tramite il servizio di posta elettronica, una comunicazione comprendente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la chiara attestazione del rilascio di un’autorizzazione ai viaggi con validità territoriale limitata e il numero di domanda dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data di decorrenza e di scadenza dell’autorizzazione ai viaggi con validità territoriale limitata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la chiara attestazione degli Stati membri in cui il titolare dell’autorizzazione ha il permesso di viaggiare e del fatto che può viaggiare soltanto all’interno del territorio di tali Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un richiamo al fatto che il possesso di un’autorizzazione ai viaggi valida costituisce una condizione di soggiorno che deve essere soddisfatta per l’intera durata del soggiorno di breve durata nel territorio dello Stato membro per cui è stata rilasciata l’autorizzazione ai viaggi con validità territoriale limitata;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un link al servizio web di cui all’articolo 13 del regolamento (UE) 2017/2226 che consenta ai cittadini di paesi terzi di verificare in qualsiasi momento il loro periodo di soggiorno rimanente autorizzato.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Accesso ai dati per verifica da parte dei vettori", "anchor": "art_45", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I vettori aerei, marittimi e internazionali stradali che effettuano trasporti di gruppo con autopullman interrogano il sistema d’informazione ETIAS per verificare se i cittadini di paesi terzi soggetti all’obbligo dell’autorizzazione ai viaggi siano in possesso o meno di un’autorizzazione ai viaggi valida.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’accesso sicuro al portale per i vettori, di cui all’articolo 6, paragrafo 2, lettera k), con la possibilità di usare soluzioni tecniche mobili, permette ai vettori di procedere all’interrogazione di cui al paragrafo 1 del presente articolo prima che un passeggero salga a bordo. Il vettore fornisce i dati contenuti nella zona a lettura ottica del documento di viaggio e indica lo Stato membro di ingresso. A titolo di deroga, in caso di transito aeroportuale il vettore non è obbligato a verificare se il cittadino di paese terzo è in possesso di un’autorizzazione ai viaggi valida.</div>\n</div>"], [null, "<p class=\"norm\">Mediante il portale per i vettori, il sistema d’informazione ETIAS fornisce ai vettori una risposta «OK/NON OK», indicando se la persona è in possesso o meno di un’autorizzazione ai viaggi valida. Qualora sia stata rilasciata un’autorizzazione ai viaggi con validità territoriale limitata a norma dell’articolo 44, la risposta fornita dal sistema centrale ETIAS tiene conto degli Stati membri per cui l’autorizzazione è valida nonché dello Stato membro di ingresso indicato dal vettore. I vettori possono conservare le informazioni trasmesse e la risposta ricevuta in conformità del diritto applicabile. La risposta «OK/NON OK» non deve essere considerata un provvedimento di autorizzazione d’ingresso o di respingimento ai sensi del regolamento (UE) 2016/399.</p>"], [null, "<p class=\"norm\">La Commissione adotta, mediante atti di esecuzione, norme dettagliate concernenti le condizioni per il funzionamento del portale per i vettori nonché la protezione dei dati e le norme di sicurezza applicabili. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 90, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione definisce, mediante atti di esecuzione, un metodo di autenticazione, riservato esclusivamente ai vettori, che consente a membri debitamente autorizzati del personale dei vettori di accedere al portale per i vettori ai fini del paragrafo 2 del presente articolo. Nel definire il metodo di autenticazione, si tiene conto della gestione dei rischi relativi alla sicurezza delle informazioni e dei principi della protezione dei dati sin dalla progettazione e per impostazione predefinita. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il portale per i vettori fa uso di una banca dati distinta a sola lettura aggiornata quotidianamente mediante estrazione a senso unico del sottoinsieme minimo necessario di dati conservati nell’ETIAS. eu-LISA è responsabile della sicurezza del portale per i vettori, della sicurezza dei dati personali in esso contenuti e del processo per l’estrazione dei dati personali nella banca dati distinta a sola lettura.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I vettori di cui al paragrafo 1 del presente articolo sono passibili delle sanzioni previste a norma dell’articolo 26, paragrafo 2, della convenzione di applicazione dell’accordo di Schengen del 14 giugno 1985 tra i governi degli Stati dell’Unione economica del Benelux, della Repubblica federale di Germania e della Repubblica francese relativo all’eliminazione graduale dei controlli alle frontiere comuni («convenzione di applicazione dell’accordo di Schengen») e dell’articolo 4 della direttiva 2001/51/CE del Consiglio (\n<span class=\"superscript\">16</span>\n) quando trasportano cittadini di paesi terzi che, sebbene soggetti all’obbligo dell’autorizzazione ai viaggi, non sono in possesso di un’autorizzazione ai viaggi valida.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 5 del presente articolo, nel caso in cui, per lo stesso cittadino di paese terzo, i vettori di cui al paragrafo 1 del presente articolo siano già passibili delle sanzioni previste a norma dell’articolo 26, paragrafo 2, della convenzione di applicazione dell’accordo di Schengen e dell’articolo 4 della direttiva 2001/51/CE, le sanzioni di cui al paragrafo 5 del presente articolo non si applicano.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Ai fini dell’attuazione del paragrafo 5 o al fine di risolvere eventuali controversie derivanti dalla sua applicazione, eu-LISA conserva le registrazioni di tutti i trattamenti di dati effettuati dai vettori nel portale per i vettori. Tali registrazioni riportano la data e l’ora di ciascuna operazione, i dati utilizzati per l’interrogazione, i dati trasmessi dal portale per i vettori e il nome del vettore in questione.</div>\n</div>"], [null, "<p class=\"norm\">Le registrazioni sono conservate per due anni. Le registrazioni sono protette con misure adeguate dall’accesso non autorizzato.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">In caso di respingimento di cittadini di paesi terzi, il vettore che li ha condotti alle frontiere esterne per via aerea, marittima e terrestre è tenuto a prenderli immediatamente a proprio carico. Su richiesta delle autorità di frontiera, i vettori sono tenuti a riportare i cittadini di paesi terzi in uno dei paesi terzi da cui li hanno trasportati, nel paese terzo che ha rilasciato il documento di viaggio con il quale hanno viaggiato, o in qualsiasi altro paese terzo in cui la loro ammissione è garantita.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">\n<span>\n<span class=\"boldface\">►C2</span>\n</span> In deroga al paragrafo 1, con riferimento ai vettori stradali che effettuano trasporti di gruppo con autopullman<span class=\"boldface\"> ◄ </span>, per i primi tre anni successivi all’entrata in funzione di ETIAS, la verifica di cui al paragrafo 1 è facoltativa e le disposizioni di cui al paragrafo 5 non si applicano a tali vettori.</div>\n</div>"]]}, "46": {"label": "Articolo 46", "heading": "Procedure sostitutive in caso di impossibilità tecnica per i vettori di accedere ai dati", "anchor": "art_46", "frags": [[null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora sia tecnicamente impossibile procedere all’interrogazione di cui all’articolo 45, paragrafo 1, a causa di un guasto di una parte qualsiasi del sistema d’informazione ETIAS, i vettori sono esentati dall’obbligo di verificare il possesso di un’autorizzazione ai viaggi valida. Se un tale guasto è rilevato da eu-LISA, l’unità centrale ETIAS ne informa i vettori e gli Stati membri. Informa altresì i vettori e gli Stati membri dell’avvenuta riparazione del guasto. Se un tale guasto è rilevato dai vettori, questi possono informarne l’unità centrale ETIAS. L’unità centrale ETIAS informa senza ritardo gli Stati membri in merito alle comunicazioni ricevute dal vettore.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le sanzioni di cui all’articolo 45, paragrafo 5, non sono irrogate ai vettori nei casi di cui al paragrafo 1 del presente articolo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora, per ragioni diverse da un guasto di una parte qualsiasi del sistema d’informazione ETIAS, sia tecnicamente impossibile per un vettore procedere all’interrogazione di cui all’articolo 45, paragrafo 1, per un periodo prolungato, il vettore ne informa l’unità centrale ETIAS. L’unità centrale ETIAS informa senza ritardo gli Stati membri in merito alle comunicazioni ricevute dal vettore.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione fissa, mediante atti di esecuzione, i dettagli delle procedure sostitutive di cui al presente articolo. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’unità centrale ETIAS fornisce sostegno operativo ai vettori in relazione ai paragrafi 1 e 3. L’unità centrale ETIAS stabilisce le procedure operative standard che stabiliscono le modalità per la fornitura di tale sostegno. La Commissione adotta, mediante atti di esecuzione, ulteriori norme dettagliate relative al sostegno da fornire e ai mezzi per fornirlo. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "47": {"label": "Articolo 47", "heading": "Accesso ai dati a fini di verifica alle frontiere esterne", "anchor": "art_47", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le autorità di frontiera competenti ad effettuare verifiche di frontiera ai valichi di frontiera esterni in conformità del regolamento (UE) 2016/399 consultano il sistema centrale ETIAS usando i dati contenuti nella zona a lettura ottica del documento di viaggio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il sistema centrale ETIAS risponde indicando:</p>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se la persona è in possesso o meno di un’autorizzazione ai viaggi valida, segnalando anche se lo status della persona corrisponde allo status di cui all’articolo 2, paragrafo 1, lettera c), e, nel caso di un’autorizzazione ai viaggi con validità territoriale limitata ai sensi dell’articolo 44, lo Stato membro o gli Stati membri per cui essa è valida;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualsiasi indicatore collegato all’autorizzazione di viaggio ai sensi dell’articolo 36, paragrafi 2 e 3;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se l’autorizzazione ai viaggi scadrà entro i successivi 90 giorni e il restante periodo di validità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati di cui all’articolo 17, paragrafo 2, lettere k) e l).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se l’autorizzazione ai viaggi scade entro i 90 giorni successivi, le autorità di frontiera informano il titolare di tale autorizzazione ai viaggi del restante periodo di validità, della possibilità di richiedere una nuova autorizzazione ai viaggi anche durante il soggiorno nel territorio degli Stati membri, e dell’obbligo di essere in possesso di un’autorizzazione ai viaggi valida per l’intera durata del soggiorno di breve durata. Tale informazione è fornita dalle guardie di frontiera al momento delle verifiche di frontiera oppure per mezzo di attrezzature, installate al valico di frontiera, che consentono al cittadino di paese terzo di consultare lo strumento di verifica di cui all’articolo 31. Tale informazione è inoltre fornita attraverso il sito Internet pubblico di cui all’articolo 16. Inoltre il sistema centrale ETIAS fornisce automaticamente al titolare di un’autorizzazione ai viaggi le stesse informazioni tramite il servizio di posta elettronica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se il sistema centrale ETIAS risponde segnalando un indicatore collegato ad un’autorizzazione di viaggio ai sensi dell’articolo 36, paragrafo 2, le autorità di frontiera procedono a una verifica di seconda linea. Ai fini della verifica di seconda linea le autorità sono autorizzate a consultare le informazioni aggiunte nel fascicolo di domanda ai sensi dell’articolo 39, paragrafo 1, lettera e), o dell’articolo 44, paragrafo 6, lettera f),</div>\n</div>"], [null, "<p class=\"norm\">Se il sistema centrale ETIAS risponde segnalando un indicatore di cui all’articolo 36, paragrafo 3, e se sono necessarie ulteriori verifiche, le autorità di frontiera possono accedere al sistema centrale ETIAS per ottenere le informazioni aggiuntive di cui all’articolo 39, paragrafo 1, lettera e), o all’articolo 44, paragrafo 6, lettera f).</p>"]]}, "48": {"label": "Articolo 48", "heading": "Procedure sostitutive in caso di impossibilità tecnica di accedere ai dati alle frontiere esterne", "anchor": "art_48", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora sia tecnicamente impossibile procedere alla consultazione di cui all’articolo 47, paragrafo 1, a causa di un guasto di qualsiasi parte del sistema d’informazione ETIAS, l’unità centrale ETIAS informa le autorità di frontiera e le unità nazionali ETIAS degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora sia tecnicamente impossibile procedere alla consultazione di cui all’articolo 47, paragrafo 1, a causa di un guasto dell’infrastruttura di frontiera nazionale in uno Stato membro, le autorità di frontiera ne informano l’unità centrale ETIAS e l’unità nazionale ETIAS di tale Stato membro. L’unità centrale ETIAS ne informa quindi immediatamente eu-LISA e la Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In entrambi i casi di cui ai paragrafi 1 e 2 del presente articolo, le autorità di frontiera seguono i piani d’emergenza nazionali. In conformità del regolamento (UE) 2016/399, il piano d’emergenza nazionale può autorizzare le autorità di frontiera a derogare temporaneamente all’obbligo di consultare il sistema centrale ETIAS di cui all’articolo 47, paragrafo 1 del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante atti di esecuzione, piani d’emergenza tipo per i casi di cui ai paragrafi 1 e 2 del presente articolo, comprese le procedure che devono essere seguite dalle autorità di frontiera. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 90, paragrafo 2. Gli Stati membri adottano i loro piani d’emergenza nazionali utilizzando quale base i piani d’emergenza tipo, adattati se necessario a livello nazionale.</div>\n</div>"]]}, "49": {"label": "Articolo 49", "heading": "Accesso ai dati da parte delle autorità competenti in materia di immigrazione", "anchor": "art_49", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Al fine di accertare o verificare se siano soddisfatte le condizioni d’ingresso o di soggiorno nel territorio degli Stati membri e di adottare misure appropriate al riguardo, le autorità competenti in materia di immigrazione degli Stati membri sono abilitate a eseguire interrogazioni del sistema centrale ETIAS con i dati di cui all’articolo 17, paragrafo 2, lettere da a) ad e).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’accesso al sistema centrale ETIAS ai sensi del paragrafo 1 del presente articolo è consentito solo se sono soddisfatte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stata effettuata una precedente interrogazione nell’EES ai sensi dell’articolo 26 del regolamento (UE) 2017/2226; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">da tale interrogazione risulta che l’EES non contiene una cartella di ingresso corrispondente alla presenza del cittadino di paese terzo nel territorio degli Stati membri.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se necessario, si verifica l’adempimento delle condizioni di cui al primo comma, lettere a) e b) del primo comma del presente paragrafo, accedendo, nell’EES, alle registrazioni ai sensi dell’articolo 46 del regolamento (UE) 2017/2226 corrispondenti all’interrogazione di cui alla lettera a) del primo comma del presente paragrafo e alla risposta di cui alla lettera b) di tale comma.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il sistema centrale ETIAS risponde indicando se la persona è in possesso o meno di un’autorizzazione ai viaggi valida e, nel caso di un’autorizzazione ai viaggi con validità territoriale limitata rilasciata ai sensi dell’articolo 44, gli Stati membri per cui l’autorizzazione di viaggio è valida. Il sistema centrale ETIAS indica inoltre se l’autorizzazione ai viaggi scadrà entro i successivi 90 giorni e il restante periodo di validità.</div>\n</div>"], [null, "<p class=\"norm\">Nel caso di minori, le autorità competenti in materia di immigrazione hanno anche accesso alle informazioni relative al titolare della responsabilità genitoriale o al tutore legale del viaggiatore di cui all’articolo 17, paragrafo 2, lettera k).</p>"]]}, "50": {"label": "Articolo 50", "heading": "Autorità designate dagli Stati membri", "anchor": "art_50", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri designano le autorità che sono autorizzate a chiedere la consultazione dei dati registrati nel sistema centrale ETIAS al fine di prevenire, accertare e indagare reati di terrorismo o altri reati gravi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro designa un punto di accesso centrale abilitato ad accedere al sistema centrale ETIAS. Il punto di accesso centrale verifica che siano soddisfatte le condizioni per la richiesta di accesso al sistema centrale ETIAS di cui all’articolo 52.</div>\n</div>"], [null, "<p class=\"norm\">L’autorità designata e il punto di accesso centrale possono far parte della stessa organizzazione se la legislazione nazionale lo consente, ma il punto di accesso centrale agisce in modo del tutto indipendente dalle autorità designate nello svolgimento dei propri compiti ai sensi del presente regolamento. Il punto di accesso centrale è distinto dalle autorità designate e non riceve istruzioni dalle stesse in merito al risultato della verifica che esso effettua in modo indipendente.</p>"], [null, "<p class=\"norm\">Gli Stati membri possono designare più punti di accesso centrale in modo da riflettere le loro strutture organizzative e amministrative in adempimento dei loro obblighi costituzionali o derivanti da altri atti giuridici.</p>"], [null, "<p class=\"norm\">Gli Stati membri comunicano a eu-LISA e alla Commissione le rispettive autorità designate e i rispettivi punti di accesso centrale e possono in qualsiasi momento modificare o sostituire le loro comunicazioni.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">A livello nazionale ciascuno Stato membro tiene un elenco delle unità operative in seno alle autorità designate che sono autorizzate a richiedere la consultazione dei dati conservati nel sistema centrale ETIAS attraverso i punti di accesso centrale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Solo il personale debitamente autorizzato dei punti di accesso centrale può accedere al sistema centrale ETIAS conformemente agli articoli 51 e 52.</div>\n</div>"]]}, "51": {"label": "Articolo 51", "heading": "Procedura di accesso al sistema centrale ETIAS a fini di contrasto", "anchor": "art_51", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Un’unità operativa di cui all’articolo 50, paragrafo 3, presenta una richiesta motivata in formato elettronico o cartaceo a un punto di accesso centrale di cui all’articolo 50, paragrafo 2, per la consultazione di una serie specifica di dati conservati nel sistema centrale ETIAS. Quando è richiesta la consultazione dei dati di cui all’articolo 17, paragrafo 2, lettera i), e all’articolo 17, paragrafo 4, lettere da a) a c), la richiesta motivata in formato elettronico o cartaceo comprende una giustificazione della necessità di consultare tali dati specifici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Al ricevimento di una richiesta di accesso, il punto di accesso centrale verifica se siano soddisfatte le condizioni di accesso di cui all’articolo 52, inclusa la verifica se sia giustificata l’eventuale richiesta di consultazione dei dati di cui all’articolo 17, paragrafo 2, lettera i), e all’articolo 17, paragrafo 4, lettere da a) a c).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se sono soddisfatte le condizioni di accesso di cui all’articolo 52, il punto di accesso centrale tratta la richiesta. Il punto di accesso centrale accede ai dati conservati nel sistema centrale ETIAS e li trasmette all’unità operativa che ha effettuato la richiesta in modo tale da non comprometterne la sicurezza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In caso di urgenza in cui sia necessario prevenire un rischio imminente alla vita di una persona da un reato di terrorismo o da un altro reato grave, il punto di accesso centrale tratta la richiesta immediatamente e verifica solo a posteriori se tutte le condizioni di cui all’articolo 52 sono soddisfatte e l’effettiva sussistenza di un caso di urgenza. La verifica a posteriori ha luogo senza indebito ritardo e, in ogni caso, non oltre sette giorni lavorativi dal trattamento della richiesta.</div>\n</div>"], [null, "<p class=\"norm\">Qualora la verifica a posteriori accerti che la consultazione dei dati o l’accesso ai dati registrati nel sistema centrale ETIAS non erano giustificati, tutte le autorità che hanno avuto accesso ai dati cancellano i dati acquisiti dal sistema centrale ETIAS e ne informano il pertinente punto di accesso centrale dello Stato membro in cui è stata effettuata la richiesta di cancellazione.</p>"]]}, "52": {"label": "Articolo 52", "heading": "Condizioni di accesso ai dati registrati nel sistema centrale ETIAS per le autorità designate degli Stati membri", "anchor": "art_52", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le autorità designate possono chiedere la consultazione dei dati conservati nel sistema centrale ETIAS se sussistono tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accesso per la consultazione è necessario a fini di prevenzione, accertamento o indagine di un reato di terrorismo o altro reato grave;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accesso per la consultazione è necessario e proporzionato in un caso specifico; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esistono prove o fondati motivi per ritenere che la consultazione dei dati conservati nel sistema centrale ETIAS contribuirà alla prevenzione, all’accertamento o all’indagine di uno dei reati in questione, in particolare laddove sussista il sospetto fondato che l’autore presunto o effettivo oppure la vittima di un reato di terrorismo o altro reato grave rientri in una categoria di viaggiatori contemplata dal presente regolamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Le autorità designate possono accedere a fini di consultazione ai fascicoli di domanda conservati nel sistema centrale ETIAS a norma del presente articolo qualora, in caso di interrogazione del CIR conformemente all'articolo 22 del regolamento (UE) 2019/817, la risposta ricevuta di cui all'articolo 22, paragrafo 2, del regolamento (UE) 2019/817 indichi che in detti fascicoli sono conservati dati.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La consultazione del sistema centrale ETIAS è limitata all’interrogazione con uno o più dei elementi relativi ai dati seguenti registrati nel fascicolo di domanda:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cognome e, se disponibile, nome o nomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altri nomi (pseudonimi, nomi d’arte, soprannomi);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numero del documento di viaggio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">domicilio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indirizzo di posta elettronica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numeri di telefono;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indirizzo IP.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per restringere la ricerca è possibile combinare la consultazione del sistema centrale ETIAS mediante i dati di cui al paragrafo 2 con i dati seguenti registrati nel fascicolo di domanda:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadinanza o cittadinanze;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">data di nascita o fascia di età.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La consultazione del sistema centrale ETIAS, in caso di riscontro positivo con i dati registrati in un fascicolo di domanda, dà accesso ai dati di cui all’articolo 17, paragrafo 2, lettere da a) a g) e da j) a m), registrati nel fascicolo di domanda, nonché ai dati relativi al rilascio, al rifiuto, all’annullamento o alla revoca di un’autorizzazione ai viaggi inseriti nel fascicolo di domanda in conformità degli articoli 39 e 43. L’accesso ai dati di cui all’articolo 17, paragrafo 2, lettera i), e all’articolo 17, paragrafo 4, lettere da a) a c), registrati nel fascicolo di domanda è permesso solo se la loro consultazione è stata esplicitamente chiesta da un’unità operativa nella richiesta motivata in formato elettronico o cartaceo presentata in conformità dell’articolo 51, paragrafo 1, e se tale richiesta è stata verificata in modo indipendente e approvata dal punto di accesso centrale. La consultazione del sistema centrale ETIAS non dà accesso ai dati relativi all’istruzione di cui all’articolo 17, paragrafo 2, lettera h).</div>\n</div>"]]}, "53": {"label": "Articolo 53", "heading": "Procedura e condizioni di accesso da parte di Europol ai dati registrati nel sistema centrale ETIAS", "anchor": "art_53", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini dell’articolo 1, paragrafo 2, Europol può chiedere di consultare i dati conservati nel sistema centrale ETIAS e presentare all’unità centrale ETIAS una richiesta motivata in formato elettronico di consultare una serie specifica di dati conservati nel sistema centrale ETIAS. Quando è richiesta la consultazione dei dati di cui all’articolo 17, paragrafo 2, lettera i), e all’articolo 17, paragrafo 4, lettere da a) a c), la richiesta motivata in formato elettronico comprende una giustificazione della necessità di consultare tali dati specifici.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Europol può accedere a fini di consultazione ai fascicoli di domanda conservati nel sistema centrale ETIAS a norma del presente articolo qualora, in caso di interrogazione del CIR conformemente all'articolo 22 del regolamento (UE) 2019/817, la risposta ricevuta di cui all'articolo 22, paragrafo 2, del regolamento (UE) 2019/817 indichi che in detti fascicoli sono conservati dati.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La richiesta motivata contiene la prova che sussistono tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la consultazione è necessaria per sostenere e rafforzare l’azione degli Stati membri in materia di prevenzione, accertamento o indagine di reati di terrorismo o altri reati gravi che sono di competenza di Europol;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la consultazione è necessaria e proporzionata in un caso specifico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la consultazione è limitata all’interrogazione con i dati di cui all’articolo 52, in combinazione con i dati elencati all’articolo 52, paragrafo 3, laddove necessario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esistono prove o fondati motivi per ritenere che la consultazione contribuirà alla prevenzione, all’accertamento o all’indagine di uno dei reati in questione, in particolare laddove sussista il sospetto fondato che l’autore presunto o effettivo oppure la vittima di un reato di terrorismo o altro reato grave rientri in una categoria di viaggiatori contemplata dal presente regolamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La richiesta di Europol di consultare i dati conservati nel sistema centrale ETIAS è soggetta alla verifica preliminare da parte di un’unità specializzata composta di funzionari di Europol debitamente autorizzati, che esamina in modo efficace e tempestivo se la richiesta soddisfa tutte le condizioni di cui al paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La consultazione del sistema centrale ETIAS, in caso di riscontro positivo con i dati conservati in un fascicolo di domanda, dà accesso ai dati di cui all’articolo 17, paragrafo 2, lettere da a) a g) e da j) a m), e ai dati aggiunti nel fascicolo di domanda relativi al rilascio, al rifiuto, all’annullamento o alla revoca di un’autorizzazione ai viaggi in conformità degli articoli 39 e 43. L’accesso ai dati di cui all’articolo 17, paragrafo 2, lettera i), e all’articolo 17, paragrafo 4, lettere da a) a c), aggiunti nel fascicolo di domanda è permesso solo se la loro consultazione è stata esplicitamente richiesta da Europol. La consultazione del sistema centrale ETIAS non dà accesso ai dati relativi all’istruzione di cui all’articolo 17, paragrafo 2, lettera h).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Una volta che l’unità specializzata composta di funzionari di Europol debitamente autorizzati l’abbia approvata, l’unità centrale ETIAS tratta la richiesta di consultazione dei dati conservati nel sistema centrale ETIAS e trasmette i dati richiesti ad Europol in modo tale da non comprometterne la sicurezza.</div>\n</div>"]]}, "54": {"label": "Articolo 54", "heading": "Conservazione dei dati", "anchor": "art_54", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ciascun fascicolo di domanda è conservato nel sistema centrale ETIAS per:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il periodo di validità dell’autorizzazione ai viaggi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cinque anni a decorrere dall’ultima decisione di rifiuto, annullamento o revoca dell’autorizzazione ai viaggi in conformità degli articoli 37, 40 e 41. Se i dati contenuti in un registro, un fascicolo o una segnalazione registrati in uno dei sistemi d’informazione dell’UE, nei dati Europol, nelle banche dati Interpol SLTD o TDAWN, nell’elenco di controllo ETIAS o nelle regole di esame ETIAS che danno origine alla decisione in questione sono cancellati prima della scadenza del periodo di cui alla lettera b), il fascicolo di domanda è soppresso entro sette giorni a decorrere dalla data della cancellazione summenzionata. A tal fine, il sistema centrale ETIAS verifica regolarmente e automaticamente se le condizioni relative alla conservazione dei fascicoli di domanda di cui alla presente lettera continuano a essere soddisfatte. Qualora tali condizioni non siano più soddisfatte, sopprime il fascicolo di domanda in modo automatizzato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per facilitare una nuova domanda dopo la scadenza del periodo di validità di un’autorizzazione ai viaggi ETIAS, il fascicolo di domanda può essere conservato nel sistema centrale ETIAS per un ulteriore periodo non superiore a tre anni dalla fine del periodo di validità dell’autorizzazione ai viaggi e solo qualora, a seguito di una richiesta di consenso, il richiedente acconsenta liberamente ed esplicitamente mediante una dichiarazione firmata elettronicamente. Le richieste di consenso sono presentate in modo chiaramente distinguibile dalle altre materie, in forma comprensibile e facilmente accessibile e utilizzando un linguaggio semplice e chiaro conformemente all’articolo 7 del regolamento (UE) 2016/679.</div>\n</div>"], [null, "<p class=\"norm\">Il consenso è richiesto in seguito alla fornitura automatica di informazioni ai sensi dell’articolo 15, paragrafo 2. Le informazioni fornite automaticamente rammentano al richiedente lo scopo della conservazione dei dati in conformità con le indicazioni di cui all’articolo 71, lettera o), e la possibilità di revocare il consenso in ogni momento.</p>"], [null, "<p class=\"norm\">Il richiedente può revocare il proprio consenso in qualsiasi momento in conformità dell’articolo 7, paragrafo 3, del regolamento (UE) 2016/679. In caso di revoca del consenso, il fascicolo di domanda è automaticamente soppresso dal sistema centrale ETIAS.</p>"], [null, "<p class=\"norm\">eu-LISA sviluppa uno strumento per consentire ai richiedenti di prestare e revocare il loro consenso. Tale strumento è reso accessibile tramite l’apposito sito web pubblico o l’applicazione per dispositivi mobili.</p>"], [null, "<p class=\"norm\">La Commissione adotta atti delegati in conformità dell’articolo 89 per definire ulteriormente lo strumento che i richiedenti devono utilizzare per prestare e revocare il loro consenso.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Allo scadere del periodo di conservazione, il fascicolo di domanda è automaticamente soppresso dal sistema centrale ETIAS.</div>\n</div>"]]}, "55": {"label": "Articolo 55", "heading": "Modifica dei dati e cancellazione anticipata dei dati", "anchor": "art_55", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’unità centrale ETIAS e le unità nazionali ETIAS sono tenute ad aggiornare i dati conservati nel sistema centrale ETIAS e a garantirne l’accuratezza. L’unità centrale ETIAS e le unità nazionali ETIAS non hanno il diritto di modificare i dati aggiunti nel modulo di domanda direttamente dal richiedente a norma dell’articolo 17, paragrafi 2, 3 o 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora disponga di prove indicanti che i dati registrati nel sistema centrale ETIAS dall’unità centrale ETIAS sono sostanzialmente inesatti o che sono stati trattati nel sistema centrale ETIAS in violazione del presente regolamento, l’unità centrale ETIAS li verifica e, se necessario, li modifica o li cancella senza ritardo dal sistema centrale ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora lo Stato membro competente disponga di prove indicanti che i dati registrati nel sistema centrale ETIAS sono sostanzialmente inesatti o che sono stati trattati nel sistema centrale ETIAS in violazione del presente regolamento, la sua unità nazionale ETIAS li verifica e, se necessario, li modifica o li cancella senza ritardo dal sistema centrale ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora l’unità centrale ETIAS disponga di prove indicanti che i dati conservati nel sistema centrale ETIAS sono sostanzialmente inesatti o sono stati trattati nel sistema centrale ETIAS in violazione del presente regolamento, contatta entro 14 giorni l’unità nazionale ETIAS dello Stato membro competente. Qualora lo Stato membro diverso dallo Stato membro competente disponga di tali prove, contatta entro 14 giorni l’unità centrale ETIAS oppure l’unità nazionale ETIAS dello Stato membro competente. L’unità centrale ETIAS o l’unità nazionale ETIAS dello Stato membro competente verifica l’esattezza dei dati e la liceità del loro trattamento entro un mese e, se necessario, li modifica o li cancella senza indugio dal sistema centrale ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora un cittadino di paese terzo abbia acquisito la cittadinanza di uno Stato membro o rientri nel ambito di applicazione dell’articolo 2, paragrafo 2, lettere da a) a c), le autorità di tale Stato membro verificano se detta persona sia titolare di un’autorizzazione ai viaggi valida e, se del caso, sopprime senza indugio il fascicolo di domanda dal sistema centrale ETIAS. L’autorità competente per la soppressione del fascicolo di domanda è:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’unità nazionale ETIAS dello Stato membro che ha rilasciato il documento di viaggio di cui all’articolo 2, paragrafo 2, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’unità nazionale ETIAS dello Stato membro di cui la persona ha acquisito la cittadinanza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’unità nazionale ETIAS dello Stato membro che ha rilasciato la carta di soggiorno o il permesso di soggiorno.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Qualora un cittadino di paese terzo rientri nell’ambito di applicazione dell’articolo 2, paragrafo 2, lettere d), e), f) o l), può informare le autorità competenti dello Stato membro che ha rilasciato il permesso di soggiorno nazionale di cui in tale articolo, il visto uniforme o il visto per soggiorno di lunga durata di essere titolare di un’autorizzazione ai viaggi valida e può chiedere la corrispondente soppressione del fascicolo di domanda dal sistema centrale ETIAS. Le autorità di tale Stato membro verificano se detta persona sia titolare di un’autorizzazione ai viaggi valida. Se è confermato che detta persona è titolare di una tale autorizzazione, l’unità nazionale ETIAS dello Stato membro che ha rilasciato il permesso di soggiorno nazionale, il visto uniforme o il visto per soggiorno di lunga durata sopprime senza indugio il fascicolo di domanda dal sistema centrale ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il cittadino di paese terzo che rientra nell’ambito di applicazione dell’articolo 2, paragrafo 2, lettera g), può informarne le autorità competenti dello Stato membro in cui fa il successivo ingresso. Detto Stato membro contatta l’unità centrale ETIAS entro 14 giorni. L’unità centrale ETIAS verifica l’esattezza dei dati entro un mese e, se necessario, sopprime senza ritardo il fascicolo di domanda e i dati ivi contenuti dal sistema centrale ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Fatto salvo ogni ricorso amministrativo o extragiudiziale disponibile, il cittadino di paese terzo ha accesso a un mezzo di ricorso giurisdizionale effettivo per assicurarsi che i dati conservati nell’ETIAS siano modificati o cancellati.</div>\n</div>"]]}, "56": {"label": "Articolo 56", "heading": "Protezione dei dati", "anchor": "art_56", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Al trattamento di dati personali da parte dell’Agenzia europea della guardia di frontiera e costiera e di eu-LISA si applica il regolamento (CE) n. 45/2001.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Al trattamento di dati personali da parte delle unità nazionali ETIAS che valutano le domande, delle autorità di frontiera e delle autorità competenti in materia di immigrazione si applica il regolamento (UE) 2016/679.</div>\n</div>"], [null, "<p class=\"norm\">Quando il trattamento di dati personali da parte delle unità nazionali ETIAS è effettuato dalle autorità competenti che valutano le domande a fini di prevenzione, accertamento o indagine di reati di terrorismo o di altri reati gravi, si applica la direttiva (UE) 2016/680.</p>"], [null, "<p class=\"norm\">Quando l’unità nazionale ETIAS decide in merito al rilascio, al rifiuto, alla revoca o all’annullamento di un’autorizzazione ai viaggi, si applica il regolamento (UE) 2016/679.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Al trattamento di dati personali da parte delle autorità designate dagli Stati membri ai fini dell’articolo 1, paragrafo 2, del presente regolamento si applica la direttiva (UE) 2016/680.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Al trattamento di dati personali da parte di Europol in conformità degli articoli 29 e 53 del presente regolamento si applica il regolamento (UE) 2016/794.</div>\n</div>"]]}, "57": {"label": "Articolo 57", "heading": "Responsabile del trattamento", "anchor": "art_57", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Agenzia europea della guardia di frontiera e costiera è considerata responsabile del trattamento ai sensi dell’articolo 2, lettera d), del regolamento (CE) n. 45/2001 in relazione al trattamento di dati personali nel sistema centrale ETIAS. Relativamente alla gestione della sicurezza delle informazioni del sistema centrale ETIAS, è da considerarsi responsabile del trattamento eu-LISA.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda il trattamento di dati personali nel sistema centrale ETIAS da parte di uno Stato membro, l’unità nazionale ETIAS è considerata titolare del trattamento ai sensi dell’articolo 4, punto 7, del regolamento (UE) 2016/679.Essa ha la responsabilità centrale del trattamento di dati personali nel sistema centrale ETIAS da parte di detto Stato membro.</div>\n</div>"]]}, "58": {"label": "Articolo 58", "heading": "Incaricato del trattamento", "anchor": "art_58", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">eu-LISA è considerata incaricata del trattamento ai sensi dell’articolo 2, lettera e), del regolamento (CE) n. 45/2001 in relazione al trattamento di dati personali nel sistema d’informazione ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">eu-LISA provvede affinché il sistema d’informazione ETIAS sia gestito conformemente al presente regolamento.</div>\n</div>"]]}, "59": {"label": "Articolo 59", "heading": "Sicurezza del trattamento", "anchor": "art_59", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">eu-LISA, l’unità centrale ETIAS e le unità nazionali ETIAS garantiscono la sicurezza del trattamento di dati personali a norma del presente regolamento. eu-LISA, l’unità centrale ETIAS e le unità nazionali ETIAS cooperano nei compiti relativi alla sicurezza dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 22 del regolamento (CE) n. 45/2001, eu-LISA adotta le misure necessarie per garantire la sicurezza del sistema d’informazione ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatti salvi l’articolo 22 del regolamento (CE) n. 45/2001 e gli articoli 32 e 34 del regolamento (UE) 2016/679, eu-LISA, l’unità centrale ETIAS e le unità nazionali ETIAS adottano le misure necessarie, compresi un piano di sicurezza e un piano di continuità operativa e di ripristino in caso di disastro, al fine di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">proteggere fisicamente i dati, tra l’altro mediante l’elaborazione di piani di emergenza per la protezione delle infrastrutture critiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">negare alle persone non autorizzate l’accesso al servizio web sicuro, al servizio di posta elettronica, al servizio di account sicuro, al portale per i vettori, allo strumento di verifica per i richiedenti e allo strumento di consenso per i richiedenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">negare alle persone non autorizzate l’accesso alle attrezzature usate per il trattamento di dati e alle strutture nazionali conformemente alle finalità dell’ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che supporti di dati possano essere letti, copiati, modificati o asportati da persone non autorizzate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che i dati siano inseriti senza autorizzazione e che sia presa visione senza autorizzazione dei dati personali registrati, o che gli stessi siano modificati o cancellati senza autorizzazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che persone non autorizzate usino sistemi di trattamento automatizzato di dati servendosi di attrezzature per la comunicazione di dati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire che i dati siano trattati nel sistema centrale ETIAS senza autorizzazione e che i dati trattati nel sistema centrale ETIAS siano modificati o cancellati senza autorizzazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedere affinché le persone autorizzate ad accedere al sistema d’informazione ETIAS abbiano accesso solo ai dati previsti dalla loro autorizzazione di accesso, tramite identità di utente individuali e uniche ed esclusivamente con modalità di accesso riservato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedere affinché tutte le autorità con diritto di accesso al sistema d’informazione ETIAS creino profili che descrivano le funzioni e le responsabilità delle persone autorizzate ad accedere ai dati e mettano tali profili a disposizione delle autorità di controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedere affinché sia possibile verificare e stabilire a quali organismi possono essere trasmessi dati personali mediante apparecchiature di comunicazione di dati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedere affinché sia possibile verificare e stabilire quali dati sono stati trattati nel sistema d’informazione ETIAS, quando, da chi e per quale scopo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impedire, in particolare mediante tecniche appropriate di cifratura, che, all’atto della trasmissione di dati personali dal sistema centrale ETIAS o verso il medesimo ovvero durante il trasporto dei supporti di dati, tali dati personali siano letti, copiati, modificati o cancellati senza autorizzazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedere affinché, in caso di interruzione, i sistemi installati possano essere ripristinati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantire l’affidabilità, accertandosi che eventuali anomalie nel funzionamento dell’ETIAS siano adeguatamente segnalate e che siano adottate le misure tecniche necessarie per assicurare che i dati personali possano essere recuperati in caso di danneggiamento a causa di un malfunzionamento dell’ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>o) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">monitorare l’efficacia delle misure di sicurezza di cui al presente paragrafo e adottare le necessarie misure organizzative relative al monitoraggio interno per garantire l’osservanza del presente regolamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante atti di esecuzione, un piano di sicurezza tipo e un piano di continuità operativa e di ripristino in caso di disastro tipo. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 90, paragrafo 2. Il consiglio di amministrazione di eu-LISA, il consiglio di amministrazione dell’Agenzia europea della guardia di frontiera e costiera e gli Stati membri adottano i piani di sicurezza e i piani di continuità operativa e di ripristino in caso di disastro rispettivamente per eu-LISA, per l’unità centrale ETIAS e per le unità nazionali ETIAS. Essi utilizzano come base i piani tipo adottati dalla Commissione, adattati per quanto necessario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">eu-LISA informa il Parlamento europeo, il Consiglio e la Commissione nonché il Garante europeo della protezione dei dati, delle misure da essa adottate in conformità del presente articolo.</div>\n</div>"]]}, "60": {"label": "Articolo 60", "heading": "Incidenti di sicurezza", "anchor": "art_60", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È considerato incidente di sicurezza l’evento che ha o può avere ripercussioni sulla sicurezza dell’ETIAS e può causare danni o perdite dei dati conservati nell’ETIAS, in particolare quando possono essere stati consultati dati senza autorizzazione o quando sono state o possono essere state compromesse la disponibilità, l’integrità e la riservatezza dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni incidente di sicurezza è gestito in modo da garantire una risposta rapida, efficace e adeguata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatte salve la notifica e la comunicazione di una violazione dei dati personali a norma dell’articolo 33 del regolamento (UE) 2016/679, dell’articolo 30 della direttiva (UE) 2016/680, o di entrambi, gli Stati membri notificano gli incidenti di sicurezza alla Commissione, a eu-LISA e al Garante europeo della protezione dei dati. Qualora si verifichi un incidente di sicurezza in relazione al sistema d’informazione ETIAS, eu-LISA ne dà notifica alla Commissione e al Garante europeo della protezione dei dati. Europol informa la Commissione e il Garante europeo della protezione dei dati qualora si verifichi un incidente di sicurezza relativo all’ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le informazioni su un incidente di sicurezza che ha o può avere ripercussioni sul funzionamento dell’ETIAS o sulla disponibilità, integrità e riservatezza dei dati sono fornite alla Commissione e, se interessate da tali ripercussioni, all’unità centrale ETIAS, alle unità nazionali ETIAS e a Europol. Tali incidenti sono altresì registrati secondo il piano di gestione degli incidenti stabilito da eu-LISA.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri, l’Agenzia europea della guardia di frontiera e costiera, eu-LISA ed Europol cooperano in caso di un incidente di sicurezza.</div>\n</div>"]]}, "61": {"label": "Articolo 61", "heading": "Verifica interna", "anchor": "art_61", "frags": [[null, "<p class=\"norm\">L’Agenzia europea della guardia di frontiera e costiera, Europol e gli Stati membri provvedono affinché ciascuna autorità con diritto di accesso al sistema d’informazione ETIAS adotti le misure necessarie per conformarsi al presente regolamento e cooperi, se necessario, con l’autorità di controllo.</p>"]]}, "62": {"label": "Articolo 62", "heading": "Sanzioni", "anchor": "art_62", "frags": [[null, "<p class=\"norm\">Gli Stati membri stabiliscono il regime sanzionatorio applicabile in caso di violazione del presente regolamento e adottano tutte le misure necessarie per assicurarne l’attuazione. Le sanzioni previste sono efficaci, proporzionate e dissuasive.</p>"]]}, "63": {"label": "Articolo 63", "heading": "Responsabilità", "anchor": "art_63", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatti salvi il diritto al risarcimento e la responsabilità da parte del titolare del trattamento o del responsabile del trattamento ai sensi del regolamento (UE) 2016/679, della direttiva (UE) 2016/680 e del regolamento (CE) n. 45/2001:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni persona o Stato membro che abbia subito danni materiali o immateriali in conseguenza di un trattamento illecito di dati personali o di qualsiasi altro atto incompatibile con il presente regolamento compiuti da uno Stato membro ha diritto al risarcimento da parte di tale Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni persona o Stato membro che abbia subito danni materiali o immateriali in conseguenza di qualsiasi atto incompatibile con il presente regolamento compiuto da eu-LISA, ha diritto al risarcimento da parte di tale agenzia. eu-LISA è responsabile dei trattamenti illeciti di dati personali nel suo ruolo di incaricata del trattamento o, a seconda dei casi, di responsabile del trattamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro in questione o eu-LISA sono esonerati in tutto o in parte da tale responsabilità ai sensi del primo comma se provano che l’evento dannoso non è loro imputabile.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Uno Stato membro è ritenuto responsabile di ogni eventuale danno arrecato al sistema centrale ETIAS conseguente all’inosservanza degli obblighi del presente regolamento, fatto salvo il caso e nella misura in cui eu-LISA o un altro Stato membro che partecipa al sistema centrale ETIAS abbiano omesso di adottare provvedimenti ragionevolmente idonei a prevenire il danno o a ridurne al minimo l’impatto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le azioni proposte contro uno Stato membro per il risarcimento dei danni di cui ai paragrafi 1 e 2 sono disciplinate dalla legislazione di tale Stato membro. Le azioni proposte contro il responsabile del trattamento o eu-LISA per il risarcimento dei danni di cui ai paragrafi 1 e 2 sono soggette alle condizioni previste dai trattati.</div>\n</div>"]]}, "64": {"label": "Articolo 64", "heading": "Diritto di accesso ai dati personali, di rettifica, integrazione e cancellazione degli stessi e di limitazione del loro trattamento", "anchor": "art_64", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatto salvo il diritto d’informazione di cui agli articoli 11 e 12 del regolamento (CE) n. 45/2001, i richiedenti i cui dati sono conservati nel sistema centrale ETIAS sono informati, al momento in cui i loro dati sono raccolti, delle procedure per esercitare i diritti di cui agli articoli da 13 a 16 del regolamento (CE) n. 45/2001 e agli articoli da 15 a 18 del regolamento (UE) 2016/679 e allo stesso tempo dei dati di contatto del responsabile della protezione dei dati dell’Agenzia europea della guardia di frontiera e costiera e del Garante europeo della protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per esercitare i loro diritti di cui agli articoli da 13 a 16 del regolamento (CE) n. 45/2001 e agli articoli da 15 a 18 del regolamento (UE) 2016/679, ogni richiedente ha il diritto di rivolgersi all’unità centrale ETIAS o all’unità nazionale ETIAS competente per la domanda. L’unità che riceve la richiesta la esamina e risponde quanto prima e, in ogni caso, al più tardi entro 30 giorni.</div>\n</div>"], [null, "<p class=\"norm\">Qualora in risposta a una richiesta emerga che i dati conservati nel sistema centrale ETIAS sono sostanzialmente inesatti o sono stati registrati illecitamente, l’unità centrale ETIAS o l’unità nazionale ETIAS dello Stato membro competente rettifica o cancella senza ritardo tali dati nel sistema centrale ETIAS.</p>"], [null, "<p class=\"norm\">Qualora, in risposta una richiesta presentata a norma del presente paragrafo, un’autorizzazione ai viaggi sia modificata dall’unità centrale ETIAS o da un’unità nazionale ETIAS durante il suo periodo di validità, il sistema centrale ETIAS procede al trattamento automatizzato di cui all’articolo 20 per stabilire se il fascicolo di domanda modificato generi un riscontro positivo in conformità dell’articolo 20, paragrafi da 2 a 5. Qualora dal trattamento automatizzato non emergano riscontri positivi, il sistema centrale ETIAS rilascia un’autorizzazione ai viaggi modificata con lo stesso periodo di validità dell’originale e ne informa il richiedente. Qualora dal trattamento automatizzato emergano uno o più riscontri positivi l’unità nazionale ETIAS dello Stato membro competente valuta il rischio per la sicurezza, di immigrazione illegale o l’alto rischio epidemico, in conformità dell’articolo 26, e decide se rilasciare un’autorizzazione ai viaggi modificata oppure, ove concluda che non sono più soddisfatte le condizioni di rilascio, revocare l’autorizzazione ai viaggi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora l’unità centrale ETIAS o l’unità nazionale ETIAS dello Stato membro competente per la domanda non concordino con l’affermazione secondo cui i dati conservati nel sistema centrale ETIAS sono di fatto inesatti o sono stati registrati illecitamente, l’unità centrale ETIAS o l’unità nazionale ETIAS dello Stato membro competente adotta senza ritardo una decisione amministrativa con la quale illustra per iscritto all’interessato la ragione per cui non intende rettificare o cancellare i dati che lo riguardano.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Tale decisione fornisce inoltre all’interessato informazioni sulla possibilità di impugnare la decisione adottata sulla richiesta di cui al paragrafo 2 e, se del caso, informazioni su come intentare un’azione o presentare un reclamo dinanzi alle autorità competenti o alle autorità giurisdizionali competenti e su qualunque tipo di assistenza disponibile, anche da parte delle autorità nazionali di controllo competenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualsiasi richiesta presentata a norma del paragrafo 2 contiene le informazioni necessarie per identificare l’interessato. Tali informazioni sono utilizzate unicamente per consentire l’esercizio dei diritti di cui al paragrafo 2 e sono cancellate subito dopo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’unità centrale ETIAS o l’unità nazionale ETIAS dello Stato membro competente tiene un registro, sotto forma di documento scritto, della presentazione di una richiesta ai sensi del paragrafo 2 e di come è stata trattata. Mette tale documento a disposizione delle autorità nazionali di controllo competenti per la protezione dei dati senza ritardo e, in ogni caso, non oltre sette giorni dalla decisione di rettificare o cancellare i dati di cui, rispettivamente, al paragrafo 2, secondo comma, o in seguito alla decisione di cui al paragrafo 3.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il diritto di accesso ai dati personali a norma del presente articolo lascia impregiudicati l’articolo 53 del regolamento (UE) 2018/1861 e l’articolo 67 del regolamento (UE) 2018/1862.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "65": {"label": "Articolo 65", "heading": "Comunicazione di dati personali a paesi terzi, organizzazioni internazionali e soggetti privati", "anchor": "art_65", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I dati personali conservati nel sistema centrale ETIAS non sono trasferiti a paesi terzi, organizzazioni internazionali o soggetti privati, né sono messi a loro disposizione, fatta eccezione per i trasferimenti a Interpol ai fini del trattamento automatizzato di cui all’articolo 20, paragrafo 2, lettere b) e l) del presente regolamento. Il trasferimento di dati personali a Interpol è soggetto alle disposizioni dell’articolo 9 del regolamento (CE) n. 45/2001.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I dati personali del sistema centrale ETIAS a cui accede uno Stato membro o Europol ai fini di cui all’articolo 1, paragrafo 2, non sono trasferiti a paesi terzi, organizzazioni internazionali o soggetti di diritto privato, né sono messi a loro disposizione. Tale divieto si applica anche al trattamento ulteriore di tali dati effettuato a livello nazionale o tra Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga all’articolo 49 del presente regolamento, se necessario ai fini del rimpatrio, le autorità competenti in materia di immigrazione possono accedere al sistema centrale ETIAS per estrarre dati da trasferire a un paese terzo in casi specifici, purché siano rispettate tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stata effettuata una precedente interrogazione nell’EES in conformità dell’articolo 26 del regolamento (UE) 2017/2226; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tale ricerca indica che l’EES non contiene dati relativi al cittadino di paese terzo che deve essere rimpatriato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se necessario, si verifica l’adempimento di tali condizioni accedendo alle registrazioni, di cui all’articolo 46 del regolamento (UE) 2017/2226 corrispondenti all’interrogazione di cui alla lettera a) del primo comma del presente paragrafo e alla risposta corrispondente alla lettera b) di tale comma.</p>"], [null, "<p class=\"norm\">Se tali condizioni sono soddisfatte, le autorità competenti in materia di immigrazione sono abilitate a interrogare il sistema centrale ETIAS con parte o con la totalità dei dati di cui all’articolo 17, paragrafo 2, lettere da a) a e), del presente regolamento. Se un fascicolo di domanda ETIAS corrisponde a tali dati, le autorità competenti in materia di immigrazione avranno accesso ai dati di cui all’articolo 17, paragrafo 2, lettere da a) a g), e, in caso di minori, al paragrafo 2, lettera k), di tale articolo.</p>"], [null, "<p class=\"norm inline-element\">In deroga al paragrafo 1 del presente articolo, i dati del sistema centrale ETIAS a cui accedono le autorità competenti in materia di immigrazione possono essere trasferiti a un paese terzo in casi specifici, se necessario per dimostrare l’identità dei cittadini di paesi terzi ai soli fini del rimpatrio, e purché sia rispettata una delle condizioni seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la Commissione ha adottato una decisione sull’adeguata protezione dei dati personali in tale paese terzo in conformità dell’articolo 45, paragrafo 3, del regolamento (UE) 2016/679;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono state previste garanzie adeguate ai sensi dell’articolo 46 del regolamento (UE) 2016/679 attraverso, ad esempio, un accordo di riammissione in vigore tra l’Unione o uno Stato membro e il paese terzo in questione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si applica l’articolo 49, paragrafo 1, lettera d), del regolamento (UE) 2016/679.</p>\n</div>\n</div>"], [null, "<p class=\"norm inline-element\">I dati di cui all’ <span>\n<span class=\"boldface\">►M1</span>\n</span> articolo 17, paragrafo 2, lettere a), a <span class=\"italics\">bis</span>), b), d), e) e f)<span class=\"boldface\"> ◄ </span> del presente regolamento possono essere trasferiti in purché siano rispettate tutte le condizioni seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il trasferimento dei dati è effettuato conformemente alle disposizioni applicabili del diritto dell’Unione, in particolare alle disposizioni in materia di protezione dei dati, compreso il capo V del regolamento (UE) 2016/679, agli accordi di riammissione e alla legislazione nazionale dello Stato membro che trasferisce i dati;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paese terzo ha concordato di trattare i dati limitatamente alle finalità per le quali sono stati trasmessi; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una decisione di rimpatrio adottata a norma della direttiva 2008/115/CE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">17</span>\n) è stata emessa nei confronti del cittadino di paese terzo interessato, purché l’esecuzione di tale decisione di rimpatrio non sia sospesa e purché non sia stato presentato alcun ricorso che possa portare alla sospensione della sua esecuzione.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I trasferimenti di dati personali a paesi terzi ai sensi del paragrafo 3 non pregiudicano i diritti dei richiedenti o dei beneficiari di protezione internazionale, in particolare in materia di non respingimento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga al paragrafo 2 del presente articolo, i dati del sistema centrale ETIAS di cui all’articolo 52, paragrafo 4, a cui accedono le autorità designate ai fini di cui all’articolo 1, paragrafo 2, possono essere trasferiti a un paese terzo o messi a sua disposizione dall’autorità designata in casi specifici, ma solo se sono soddisfatte tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ricorre un caso eccezionale di urgenza in cui sussiste:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un pericolo imminente associato a un reato di terrorismo; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un pericolo imminente per la vita di una persona associato a un reato grave;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il trasferimento dei dati è necessario a fini di prevenzione, accertamento o indagine nel territorio degli Stati membri o nel paese terzo interessato di tale reato di terrorismo o reato grave;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’autorità designata ha accesso a tali dati secondo la procedura e alle condizioni di cui agli articoli 51 e 52;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il trasferimento è effettuato in conformità delle condizioni applicabili previste dalla direttiva (UE) 2016/680, in particolare dal capo V;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paese terzo ha presentato una richiesta debitamente motivata, in formato cartaceo o elettronico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è garantita, su base di reciprocità, la fornitura delle informazioni nei sistemi di autorizzazione ai viaggi detenute dal paese terzo richiedente agli Stati membri in cui l’ETIAS è operativo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Qualora sia effettuato a norma del primo comma del presente paragrafo, un tale trasferimento è documentato e, su richiesta, la documentazione è messa a disposizione dell’autorità di controllo istituita a norma dell’articolo 41, paragrafo 1, della direttiva (UE) 2016/680, con l’indicazione della data e dell’ora del trasferimento, delle informazioni sull’autorità competente ricevente, della motivazione del trasferimento e dei dati personali trasferiti.</p>"]]}, "66": {"label": "Articolo 66", "heading": "Vigilanza dell’autorità di controllo", "anchor": "art_66", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro assicura che l’autorità di controllo istituita a norma dell’articolo 51, paragrafo 1, del regolamento (UE) 2016/679 controlli indipendentemente la liceità del trattamento dei dati personali ai sensi del presente regolamento effettuato dallo Stato membro in questione, nonché la loro trasmissione all’ETIAS e viceversa.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro provvede affinché le disposizioni legislative, regolamentari e amministrative nazionali adottate ai sensi della direttiva (UE) 2016/680 siano altresì applicabili all’accesso all’ETIAS effettuato dalle proprie autorità nazionali conformemente al capo X del presente regolamento, anche per quanto riguarda i diritti delle persone i cui dati sono così consultati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’autorità di controllo istituita a norma dell’articolo 41, paragrafo 1, della direttiva (UE) 2016/680 controlla la liceità dell’accesso ai dati personali effettuato dagli Stati membri conformemente al capo X del presente regolamento, nonché la trasmissione dei dati all’ETIAS e viceversa. Si applica di conseguenza l’articolo 66, paragrafi 5 e 6, del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’autorità o le autorità di controllo istituite a norma dell’articolo 51, paragrafo 1, del regolamento (UE) 2016/679 provvedono affinché, almeno ogni tre anni dall’entrata in funzione dell’ETIAS, sia svolta una verifica dei trattamenti di dati da parte delle unità nazionali ETIAS conformemente ai pertinenti principi internazionali di audit. I risultati della verifica possono essere presi in considerazione nelle valutazioni effettuate nel quadro del meccanismo istituito dal regolamento (UE) n. 1053/2013 del Consiglio (\n<span class=\"superscript\">18</span>\n). L’autorità di controllo istituita a norma dell’articolo 51, paragrafo 1, del regolamento (UE) 2016/679, pubblica ogni anno il numero delle richieste di rettifica, integrazione, cancellazione o limitazione del trattamento dei dati, le conseguenti azioni intraprese e il numero delle rettifiche, integrazioni, cancellazioni e limitazioni del trattamento effettuate in seguito alla richiesta degli interessati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri provvedono affinché la loro autorità di controllo, istituita a norma dell’articolo 51, paragrafo 1, del regolamento (UE) 2016/679, disponga delle risorse e delle competenze sufficienti per assolvere i compiti ad essa affidati dal presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri comunicano qualsiasi informazione richiesta dall’autorità di controllo istituita a norma dell’articolo 51, paragrafo 1, del regolamento (UE) 2016/679 e, in particolare, le forniscono informazioni sulle attività svolte conformemente alle loro responsabilità previste dal presente regolamento. Gli Stati membri permettono all’autorità di controllo istituita a norma dell’articolo 51, paragrafo 1, del regolamento (UE) 2016/679 di consultare le loro registrazioni e di accedere in qualsiasi momento a tutti i loro locali utilizzati per le finalità dell’ETIAS.</div>\n</div>"]]}, "67": {"label": "Articolo 67", "heading": "Vigilanza del Garante europeo della protezione dei dati", "anchor": "art_67", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il Garante europeo della protezione dei dati ha il compito di controllare le attività di trattamento dei dati personali relative a ETIAS da parte di eu-LISA, di Europol e dell’Agenzia europea della guardia di frontiera e costiera e di assicurare che tali attività siano effettuate in conformità del regolamento (CE) n. 45/2001 e del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il Garante europeo della protezione dei dati provvede affinché, almeno ogni tre anni, sia svolta una verifica delle attività di trattamento di dati personali da parte di eu-LISA e dell’unità centrale ETIAS conformemente ai pertinenti principi internazionali di audit. Una relazione su tale verifica è trasmessa al Parlamento europeo, al Consiglio, alla Commissione, a eu-LISA e alle autorità di controllo. A eu-LISA e all’Agenzia europea della guardia di frontiera e costiera è data la possibilità di presentare osservazioni prima dell’adozione della relazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">eu-LISA e l’unità centrale ETIAS forniscono al Garante europeo della protezione dei dati le informazioni da questo richieste, gli permettono di consultare tutti i documenti e le loro registrazioni e di avere accesso, in qualsiasi momento, a tutti i loro locali.</div>\n</div>"]]}, "68": {"label": "Articolo 68", "heading": "Cooperazione tra le autorità di vigilanza e il Garante europeo della protezione dei dati", "anchor": "art_68", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le autorità di vigilanza e il Garante europeo della protezione dei dati, ciascuno nei limiti delle proprie competenze, cooperano attivamente nell’ambito delle rispettive responsabilità. Essi assicurano la vigilanza coordinata dell’ETIAS e delle infrastrutture nazionali di frontiera.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le autorità di vigilanza e il Garante europeo della protezione dei dati si scambiano informazioni pertinenti, si assistono vicendevolmente nello svolgimento di verifiche e ispezioni, esaminano ogni difficoltà relativa all’interpretazione o all’applicazione del presente regolamento, valutano i problemi nell’esercizio di un controllo indipendente o nell’esercizio dei diritti dell’interessato, elaborano proposte armonizzate per soluzioni congiunte ad eventuali problemi e promuovono la sensibilizzazione sui diritti in materia di protezione dei dati, a seconda delle necessità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 2, le autorità di vigilanza e il Garante europeo della protezione dei dati si riuniscono almeno due volte l’anno nell’ambito del comitato europeo per la protezione dei dati istituito dal regolamento (UE) 2016/679. I costi di tali riunioni sono a carico di detto comitato e la loro organizzazione è effettuata dallo stesso. Nella prima riunione è adottato un regolamento interno. Ulteriori metodi di lavoro sono elaborati congiuntamente a seconda delle necessità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Una relazione congiunta sulle attività svolte è trasmessa ogni due anni dal comitato europeo per la protezione dei dati al Parlamento europeo, al Consiglio, alla Commissione, all’Agenzia europea della guardia di frontiera e costiera e a eu-LISA. Tale relazione comprende un capitolo su ciascuno Stato membro redatto dall’autorità di controllo dello Stato membro in questione.</div>\n</div>"]]}, "69": {"label": "Articolo 69", "heading": "Conservazione delle registrazioni", "anchor": "art_69", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">eu-LISA conserva le registrazioni di tutti i trattamenti di dati nell’ambito del sistema d’informazione ETIAS. Tali registrazioni comprendono gli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la finalità dell’accesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data e l’ora di ciascuna operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati usati ai fini del trattamento automatizzato delle domande;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ca) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, un riferimento all'uso dell'ESP per interrogare il sistema centrale ETIAS di cui all'articolo 7, paragrafo 2, del regolamento (UE) 2019/817;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i riscontri positivi emersi durante il trattamento automatizzato di cui all’articolo 20;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati usati per verificare l’identità conservati nel sistema centrale ETIAS o altri sistemi d’informazione e banche dati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i risultati della verifica di cui all’articolo 2; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il membro del personale che l’ha svolt.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’unità centrale ETIAS conserva i registri dei membri del personale debitamente autorizzati a effettuare le verifiche d’identità.</div>\n</div>"], [null, "<p class=\"norm\">L’unità nazionale ETIAS dello Stato membro competente conserva i registri del membro del personale debitamente autorizzato ad inserire ed estrarre i dati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">eu-LISA conserva le registrazioni di tutti i trattamenti di dati effettuati nel sistema d’informazione ETIAS riguardanti l’accesso delle autorità di frontiera di cui all’articolo 47 e l’accesso delle autorità competenti in materia di immigrazione di cui all’articolo 49. Tali registrazioni indicano la data e l’ora di ciascuna operazione, i dati usati per avviare la ricerca, i dati trasmessi dal sistema centrale ETIAS e i nomi delle autorità di frontiera e delle autorità competenti in materia di immigrazione che inseriscono ed estraggono dati.</div>\n</div>"], [null, "<p class=\"norm\">Inoltre, le autorità competenti conservano i registri dei membri del personale debitamente autorizzati ad inserire ed estrarre i dati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Tali registrazioni possono essere utilizzate unicamente per il monitoraggio dell’ammissibilità del trattamento dei dati e per garantire la sicurezza e l’integrità degli stessi. Tali registrazioni sono protette dall’accesso non autorizzato con misure adeguate. Esse sono cancellate dopo un anno dalla scadenza del periodo di conservazione di cui all’articolo 54, sempreché non siano necessarie per procedure di monitoraggio già avviate.</div>\n</div>"], [null, "<p class=\"norm\">eu-LISA e le unità nazionali ETIAS mettono tali registrazioni a disposizione del Garante europeo della protezione dei dati e delle autorità di controllo competenti su richiesta.</p>"]]}, "70": {"label": "Articolo 70", "heading": "Conservazione delle registrazioni per richieste di consultazione di dati a fini di prevenzione, accertamento e indagine di reati di terrorismo o altri reati gravi", "anchor": "art_70", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">eu-LISA conserva le registrazioni di tutti i trattamenti di dati nel sistema centrale ETIAS riguardanti l’accesso dei punti di accesso centrale di cui all’articolo 50, paragrafo 2, ai fini di cui all’articolo 1, paragrafo 2. Tali registrazioni indicano la data e l’ora di ciascuna operazione, i dati usati per avviare la ricerca, i dati trasmessi dal sistema centrale ETIAS e i nomi dei membri del personale dei punti di accesso centrale che inseriscono ed estraggono dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Inoltre, ciascuno Stato membro ed Europol conservano le registrazioni di tutti i trattamenti di dati effettuati nel sistema centrale ETIAS in seguito a richieste di consultazione di dati o di accesso ai dati conservati nel sistema centrale ETIAS ai fini di cui all’articolo 1, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le registrazioni di cui al paragrafo 2 indicano:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo scopo esatto della richiesta di consultazione o di accesso ai dati conservati nel sistema centrale ETIAS, compreso il tipo di reato di terrorismo o altro reato grave in questione e, per Europol, lo scopo esatto della richiesta di consultazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la decisione adottata in merito all’ammissibilità della richiesta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il riferimento dell’archivio nazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data e l’ora esatta della richiesta di accesso inviata dal punto di accesso centrale al sistema centrale ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">laddove applicabile, l’esperimento della procedura di urgenza di cui all’articolo 51, paragrafo 4, e i risultati della verifica a posteriori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i dati o la serie di dati di cui all’articolo 52, paragrafi 2 e 3, usati per la consultazione; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conformemente alle disposizioni nazionali o al regolamento (UE) 2016/794, l’identificazione del funzionario che ha effettuato la consultazione e del funzionario che ha ordinato di ricercare i dati o di trasmetterli.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le registrazioni di cui ai paragrafi 1 e 2 del presente articolo sono usate solo per verificare l’ammissibilità della richiesta, controllare la liceità del trattamento dei dati e garantire l’integrità e la sicurezza dei dati. Tali registrazioni sono protette dall’accesso non autorizzato con misure adeguate e sono cancellate dopo un anno dalla scadenza del periodo di conservazione di cui all’articolo 54, sempreché non siano necessarie per procedure di monitoraggio già avviate. Il Garante europeo della protezione dei dati e le autorità di vigilanza competenti a controllare la liceità del trattamento dei dati e l’integrità e la sicurezza dei dati hanno accesso a tali registrazioni, su loro richiesta, per l’adempimento delle loro funzioni. Anche l’autorità competente per verificare l’ammissibilità della richiesta ha accesso a tali registrazioni per lo stesso fine. Qualora l’obiettivo sia diverso da tal fine, i dati personali sono cancellati da tutti gli archivi nazionali e da quelli di Europol dopo un mese, salvo se tali dati sono necessari ai fini della specifica indagine penale per la quale i dati sono stati richiesti da uno Stato membro o da Europol. Soltanto le registrazioni che non contengono dati personali possono essere usate ai fini del monitoraggio e della valutazione di cui all’articolo 92.</div>\n</div>"]]}, "71": {"label": "Articolo 71", "heading": "Informazioni al pubblico", "anchor": "art_71", "frags": [[null, "<p class=\"norm\">Previa consultazione della Commissione e del Garante europeo della protezione dei dati, l’unità centrale ETIAS fornisce al pubblico tutte le informazioni utili in merito alle domande di autorizzazione ai viaggi. Tali informazioni sono messe a disposizione sul sito web pubblico e comprendono:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i criteri, le condizioni e le procedure per presentare domanda di autorizzazione ai viaggi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sul sito web e sull’applicazione per dispositivi mobili mediante i quali può essere presentata la domanda;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulla possibilità che una domanda possa essere presentata da un’altra persona o da un intermediario commerciale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulla possibilità di segnalare abusi da parte di intermediari commerciali utilizzando il modulo di cui all’articolo 15, paragrafo 5;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i termini per la decisione sulla domanda di cui all’articolo 32;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che un’autorizzazione ai viaggi è legata al documento di viaggio indicato nel modulo di domanda e, di conseguenza, che la scadenza e qualunque modifica del documento di viaggio comporterà l’invalidità o il mancato riconoscimento dell’autorizzazione ai viaggi all’atto dell’attraversamento della frontiera;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che i richiedenti sono responsabili dell’autenticità, della completezza, della correttezza e dell’affidabilità dei dati da essi presentati nonché della veridicità e dell’affidabilità delle dichiarazioni rese;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che le decisioni relative alle domande devono essere notificate al richiedente, che tali decisioni devono indicare, in caso di rifiuto di un’autorizzazione ai viaggi, i motivi di tale rifiuto e che il richiedente la cui domanda è rifiutata ha diritto di proporre ricorso, con informazioni riguardo alla procedura da seguire in caso di ricorso, compresi i recapiti dell’autorità competente e i termini per proporlo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che il richiedente ha la possibilità di contattare l’unità centrale ETIAS indicando che lo scopo del suo viaggio si fonda su motivi umanitari o è collegato a obblighi internazionali, nonché le relative condizioni e procedure;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le condizioni d’ingresso di cui all’articolo 6 del regolamento (UE) 2016/399 e il fatto che un soggiorno di breve durata è possibile esclusivamente per una durata non superiore a 90 giorni su un periodo di 180 giorni, ad eccezione dei cittadini di paesi terzi che beneficiano di disposizioni più favorevoli previste da un accordo bilaterale concluso anteriormente alla convenzione di applicazione dell’accordo di Schengen;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che il semplice possesso di un’autorizzazione ai viaggi non conferisce automaticamente un diritto d’ingresso;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che le autorità di frontiera possono richiedere documenti giustificativi alle frontiere esterne al fine di verificare l’adempimento delle condizioni d’ingresso;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che il possesso di un’autorizzazione ai viaggi valida costituisca una condizione di soggiorno che deve essere soddisfatta per l’intera durata di un soggiorno di breve durata nel territorio degli Stati membri;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un collegamento al servizio web di cui all’articolo 13 del regolamento (UE) 2017/2226 che consenta ai cittadini di paesi terzi di verificare in qualsiasi momento il periodo di soggiorno rimanente autorizzato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>o) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il fatto che i dati inseriti nel sistema d’informazione ETIAS sono utilizzati ai fini della gestione delle frontiere, segnatamente per verifiche nelle banche dati, e che gli Stati membri ed Europol possono accedere ai dati a fini di prevenzione, accertamento e indagine di reati di terrorismo o altri reati gravi, secondo le procedure e le condizioni di cui al capo X;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>p) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il periodo di conservazione dei dati;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>q) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i diritti degli interessati a norma dei regolamenti (CE) n. 45/2001, (UE) 2016/679, (UE) 2016/794 e della direttiva (UE) 2016/680;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>r) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la possibilità per i viaggiatori di ottenere il sostegno di cui all’articolo 7, paragrafo 2, lettera m).</p>\n</div>\n</div>"]]}, "72": {"label": "Articolo 72", "heading": "Campagna d’informazione", "anchor": "art_72", "frags": [[null, "<p class=\"norm\">La Commissione, in collaborazione con il Servizio europeo per l’azione esterna, l’unità centrale ETIAS, e gli Stati membri, inclusi i rispettivi consolati nei paesi terzi interessati, avviano, in concomitanza con l’entrata in funzione dell’ETIAS, una campagna d’informazione per rendere noto ai cittadini di paesi terzi rientranti nell’ambito di applicazione del presente regolamento che sono tenuti ad essere in possesso di un’autorizzazione ai viaggi valida per attraversare le frontiere esterne e per l’intera durata del loro soggiorno di breve durata nel territorio degli Stati membri.</p>"], [null, "<p class=\"norm\">Tale campagna d’informazione è condotta periodicamente e in almeno una delle lingue ufficiali dei paesi i cui cittadini rientrano nell’ambito di applicazione del presente regolamento.</p>"]]}, "73": {"label": "Articolo 73", "heading": "Responsabilità di eu-LISA in fase di progettazione e sviluppo", "anchor": "art_73", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il sistema centrale ETIAS è ospitato da eu-LISA nei suoi siti tecnici e fornisce le funzionalità di cui al presente regolamento nel rispetto delle condizioni di sicurezza, disponibilità, qualità e rapidità di cui al paragrafo 3 del presente articolo e all’articolo 74, paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le infrastrutture a sostegno del sito web pubblico, dell’applicazione per dispositivi mobili, del servizio di posta elettronica, del servizio di account sicuro, dello strumento di verifica per i richiedenti, dello strumento di consenso per i richiedenti, dello strumento di valutazione per l’elenco di controllo ETIAS, del portale per i vettori, del servizio web, del software per il trattamento delle domande, dell’archivio <span>\n<span class=\"boldface\">►M1</span>\n</span> centrale di relazioni e statistiche di cui all'articolo 39 del regolamento (UE) 2019/817, in quanto contenga dati ottenuti dal sistema centrale ETIAS conformemente all'articolo 84 del presente regolamento<span class=\"boldface\"> ◄ </span> e delle soluzioni tecniche di cui all’articolo 92, paragrafo 8, sono ospitate presso siti di eu-LISA o della Commissione. Tali infrastrutture sono distribuite geograficamente in modo da fornire le funzionalità di cui al presente regolamento nel rispetto delle condizioni di sicurezza, protezione e sicurezza dei dati, disponibilità, qualità e rapidità ai sensi del paragrafo 3 del presente articolo e dell’articolo 74, paragrafo 1. L’elenco di controllo ETIAS è ospitato in un sito di eu-LISA.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">eu-LISA è responsabile dello sviluppo tecnico del sistema d’informazione ETIAS, di eventuali sviluppi tecnici richiesti per assicurare l’interoperabilità tra il sistema centrale ETIAS e dei i sistemi d’informazione dell’UE di cui all’articolo 11, nonché di rendere possibile l’interrogazione delle banche dati Interpol di cui all’articolo 12.</div>\n</div>"], [null, "<p class=\"norm\">eu-LISA definisce la progettazione dell’architettura fisica del sistema, compresa la relativa infrastruttura di comunicazione, nonché le proprie specifiche tecniche e la loro evoluzione e le IUN. Tali specifiche tecniche sono adottate dal consiglio di amministrazione di eu-LISA previo parere favorevole della Commissione. eu-LISA provvede anche agli adeguamenti dell’EES, del SIS, dell’Eurodac o del VIS resi necessari dall’interoperabilità con l’ETIAS.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">delle misure di cui all’articolo 6, paragrafo 4, all’articolo 16, paragrafo 10, all’articolo 17, paragrafo 9, all’articolo 31, all’articolo 35, paragrafo 7, all’articolo 45, paragrafo 2, all’articolo 54, paragrafo 2, all’articolo 74, paragrafo 5, all’articolo 84, paragrafo 2, e all’articolo 92, paragrafo 8; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">delle misure adottate secondo la procedura d’esame di cui all’articolo 90, paragrafo 2, necessarie per lo sviluppo e la realizzazione tecnica del sistema centrale ETIAS, delle NUI, dell’infrastruttura di comunicazione, del canale di comunicazione sicuro fra il sistema centrale ETIAS e quello dell’EES, nonché del portale per i vettori, in particolare degli atti di esecuzione riguardanti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accesso ai dati a norma degli articoli da 22 a 29 e da 33 a 53;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la modifica, la cancellazione e la cancellazione anticipata dei dati a norma dell’articolo 55;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la conservazione delle registrazioni e l’accesso alle medesime a norma degli articoli 45 e 69;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i requisiti di prestazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le specifiche relative a soluzioni tecniche per la connessione dei punti di accesso centrale a norma degli articoli 51, 52 e 53.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm inline-element\">Lo sviluppo comporta l’elaborazione e l’applicazione delle specifiche tecniche, il collaudo e il coordinamento generale del progetto. Al riguardo, eu-LISA è inoltre incaricata di:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">effettuare una valutazione del rischio per la sicurezza;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attenersi ai principi della tutela della vita privata fin dalla progettazione e per impostazione predefinita durante l’intero ciclo di vita dello sviluppo dell’ETIAS; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">svolgere una valutazione del rischio per la sicurezza riguardo all’interoperabilità dell’ETIAS con i sistemi d’informazione dell’UE e i dati Europol di cui all’articolo 11.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In fase di progettazione e di sviluppo, è istituito un consiglio di gestione del programma composto da un massimo di dieci membri. Esso è costituito da sei membri nominati dal consiglio di amministrazione di eu-LISA tra i suoi membri e i loro supplenti, dal presidente del gruppo consultivo EES-ETIAS di cui all’articolo 91, da un membro che rappresenta eu-LISA nominato dal suo direttore esecutivo, da un membro che rappresenta l’Agenzia europea della guardia di frontiera e costiera nominato dal suo direttore esecutivo e da un membro nominato dalla Commissione. I membri nominati dal consiglio di amministrazione di eu-LISA sono eletti soltanto tra gli Stati membri che sono pienamente vincolati, in base al diritto dell’Unione, dagli strumenti legislativi che disciplinano lo sviluppo, l’istituzione, il funzionamento e l’uso di tutti i sistemi IT su larga scala gestiti da eu-LISA e che parteciperanno all’ETIAS. Il consiglio di gestione del programma si riunisce periodicamente e almeno tre volte a trimestre. Esso garantisce l’adeguata gestione della fase di progettazione e sviluppo dell’ETIAS. Il consiglio di gestione del programma presenta mensilmente relazioni scritte al consiglio di amministrazione di eu-LISA sui progressi del progetto. Non ha potere decisionale, né mandato di rappresentare i membri del consiglio di amministrazione di eu-LISA.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il consiglio di amministrazione di eu-LISA stabilisce il regolamento interno del consiglio di gestione del programma, che comprende in particolare disposizioni riguardanti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la presidenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i luoghi di riunione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la preparazione delle riunioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ammissione di esperti alle riunioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i piani di comunicazione atti a garantire che i membri non partecipanti del consiglio di amministrazione di eu-LISA siano pienamente informati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La presidenza è esercitata da uno Stato membro che è pienamente vincolato, in base al diritto dell’Unione, dagli strumenti legislativi che disciplinano lo sviluppo, l’istituzione, il funzionamento e l’uso di tutti i sistemi IT su larga scala gestiti da eu-LISA.</p>"], [null, "<p class=\"norm\">Tutte le spese di viaggio e di soggiorno sostenute dai membri del consiglio di gestione del programma sono a carico di eu-LISA. L’articolo 10 del suo regolamento interno si applica <span class=\"italics\">mutatis mutandis</span>. Il segretariato del consiglio di gestione del programma è assicurato da eu-LISA.</p>"], [null, "<p class=\"norm\">Il gruppo consultivo EES-ETIAS si riunisce regolarmente fino all’entrata in funzione dell’ETIAS. Dopo ciascuna riunione, riferisce al consiglio di gestione del programma. Fornisce la consulenza tecnica a sostegno delle attività del consiglio di gestione del programma e monitora lo stato di preparazione degli Stati membri.</p>"]]}, "74": {"label": "Articolo 74", "heading": "Competenze di eu-LISA in seguito all’entrata in funzione dell’ETIAS", "anchor": "art_74", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In seguito all'entrata in funzione dell'ETIAS, eu-LISA è responsabile della gestione tecnica del sistema centrale ETIAS e delle interfacce uniformi nazionali. È altresì responsabile dell'eventuale collaudo tecnico richiesto per la creazione e l'aggiornamento delle regole di esame ETIAS. In cooperazione con gli Stati membri provvede a che in qualsiasi momento siano utilizzate, previa analisi costi/benefici, le migliori tecnologie disponibili. eu-LISA è inoltre responsabile della gestione tecnica dell'infrastruttura di comunicazione tra il sistema centrale ETIAS e le IUN, nonché del sito web pubblico, dell'applicazione per dispositivi mobili, del servizio di posta elettronica, del servizio di account sicuro, dello strumento di verifica per i richiedenti, dello strumento di consenso per i richiedenti, dello strumento di valutazione per l'elenco di controllo ETIAS, del portale per i vettori, del servizio web e del software per il trattamento delle domande.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">La gestione tecnica dell’ETIAS consiste nell’insieme dei compiti necessari per garantire il funzionamento del sistema d’informazione ETIAS 24 ore al giorno e sette giorni su sette in conformità del presente regolamento e comprende, in particolare, la manutenzione e gli adeguamenti tecnici necessari per garantire che il sistema funzioni a un livello di qualità tecnica soddisfacente, specialmente per quanto riguarda i tempi di risposta alla consultazione del sistema centrale ETIAS, conformemente alle specifiche tecniche.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 17 dello statuto dei funzionari dell’Unione europea di cui al regolamento (CEE, Euratom; CECA) del Consiglio n. 259/68 (\n<span class=\"superscript\">19</span>\n), eu-LISA applica a tutti i membri del proprio personale che operano con i dati conservati nel sistema centrale ETIAS adeguate norme in materia di segreto professionale o altri doveri equivalenti di riservatezza. Tale obbligo vincola il personale anche dopo che abbia lasciato l’incarico o cessato di lavorare, ovvero portato a termine le attività.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se collabora con contraenti esterni per un qualsiasi compito relativo all’ETIAS, eu-LISA monitora da vicino le attività dei contraenti per garantire il rispetto di tutte le disposizioni del presente regolamento, comprese in particolare la sicurezza, la riservatezza e la protezione dei dati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">eu-LISA svolge anche compiti relativi alla formazione sull’uso tecnico del sistema d’informazione ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">eu-LISA sviluppa e mantiene un meccanismo e procedure per lo svolgimento di controlli di qualità sui dati contenuti nel sistema centrale ETIAS e riferisce periodicamente agli Stati membri e all’unità centrale ETIAS. eu-LISA riferisce periodicamente al Parlamento europeo, al Consiglio e alla Commissione in merito ai problemi incontrati. La Commissione, mediante atti di esecuzione, prevede e sviluppa tale meccanismo, le procedure e i requisiti appropriati relativi alla conformità qualitativa dei dati. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"]]}, "75": {"label": "Articolo 75", "heading": "Competenze dell’Agenzia europea della guardia di frontiera e costiera", "anchor": "art_75", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’Agenzia europea della guardia di frontiera e costiera è responsabile di quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’istituzione e il funzionamento dell’unità centrale ETIAS e la garanzia delle condizioni per la gestione sicura dei dati conservati nell’ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il trattamento automatizzato delle domande; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le regole di esame ETIAS.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Prima di essere autorizzato a trattare dati registrati nel sistema centrale ETIAS, il personale dell’unità centrale ETIAS con diritto di accesso al sistema centrale ETIAS riceve una formazione adeguata sulla sicurezza dei dati e i diritti fondamentali, in particolare per quanto riguarda la protezione dei dati. Partecipa inoltre alle formazioni offerte da eu-LISA sull’uso tecnico del sistema d’informazione ETIAS e sulla qualità dei dati.</div>\n</div>"]]}, "76": {"label": "Articolo 76", "heading": "Competenze degli Stati membri", "anchor": "art_76", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ciascuno Stato membro è responsabile di quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la connessione al NUI;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’organizzazione, la gestione, il funzionamento e la manutenzione delle unità nazionali ETIAS per il trattamento manuale delle domande di autorizzazione ai viaggi in relazione alle quali dal trattamento automatizzato è emerso un riscontro positivo e per la relativa decisione, come indicato all’articolo 26;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’organizzazione dei punti di accesso centrale e la loro connessione al NUI a fini di prevenzione, accertamento e indagine di reati di terrorismo o altri reati gravi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la gestione e le modalità di accesso al sistema d’informazione ETIAS del personale debitamente autorizzato delle autorità nazionali competenti a norma del presente regolamento, nonché la redazione e l’aggiornamento periodico di un elenco di tale personale con le relative qualifiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’istituzione e il funzionamento delle unità nazionali ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’inserimento nell’elenco di controllo ETIAS dei dati relativi a reati di terrorismo o altri reati gravi a norma dell’articolo 34, paragrafi 2 e 3; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la garanzia che ciascuna delle sue autorità con diritto di accesso al sistema d’informazione ETIAS adotti le misure necessarie per conformarsi al presente regolamento, comprese quelle necessarie ad assicurare il rispetto dei diritti fondamentali e la sicurezza dei dati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro utilizza procedure automatizzate per l’interrogazione del sistema centrale ETIAS alle frontiere esterne.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Prima di essere autorizzato a trattare dati registrati nel sistema centrale ETIAS, il personale delle unità nazionali ETIAS con diritto di accesso al sistema d’informazione ETIAS riceve una formazione adeguata sulla sicurezza dei dati e i diritti fondamentali, in particolare per quanto riguarda la protezione dei dati.</div>\n</div>"], [null, "<p class=\"norm\">Partecipa inoltre alle formazioni offerte da eu-LISA sull’uso tecnico del sistema d’informazione ETIAS e sulla qualità dei dati.</p>"]]}, "77": {"label": "Articolo 77", "heading": "Competenze di Europol", "anchor": "art_77", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Europol provvede al trattamento delle interrogazioni di cui all’articolo 20, paragrafo 2, lettera j), e paragrafo 4, e al conseguente adeguamento del suo sistema d’informazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Europol esercita le responsabilità e i compiti relativi all’elenco di controllo ETIAS di cui all’articolo 35, paragrafo 1 e paragrafi da 3 a 6.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Europol formula un parere motivato in seguito a una richiesta di consultazione a norma dell’articolo 29.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">A norma dell’articolo 34, paragrafo 2, Europol è responsabile dell’inserimento nell’elenco di controllo ETIAS dei dati relativi a reati di terrorismo o altri reati gravi da essa ottenute.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Prima di essere autorizzato a svolgere i compiti di cui agli articoli 34 e 35, il personale di Europol riceve una formazione adeguata sulla sicurezza dei dati e i diritti fondamentali, in particolare per quanto riguarda la protezione dei dati. Partecipa inoltre alle formazioni offerte da eu-LISA sull’uso tecnico del sistema d’informazione ETIAS e sulla qualità dei dati.</div>\n</div>"]]}, "78": {"label": "Articolo 78", "heading": "Modifica del regolamento (UE) n. 1077/2011", "anchor": "art_78", "frags": [[null, "<p class=\"norm\">Nel regolamento (UE) n. 1077/2011 è inserito l’articolo seguente:</p>"], [null, "<p class=\"title-article-quoted\">«Articolo 5 <span class=\"norm\">ter</span>\n</p>"], [null, "<p class=\"stitle-article-quoted\">Compiti relativi all’ETIAS</p>"], [null, "<p class=\"norm\">Con riguardo all’ETIAS, l’agenzia svolge i compiti a essa attribuiti conformemente all’articolo 73 del regolamento (UE) 2018/1240 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*1</span>\n).</p>"]]}, "79": {"label": "Articolo 79", "heading": "Modifiche del regolamento (UE) n. 515/2014", "anchor": "art_79", "frags": [[null, "<p class=\"norm\">All’articolo 6 del regolamento (UE) n. 515/2014 è inserito il paragrafo seguente:</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">«3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Durante la fase di sviluppo del sistema europeo di informazione e autorizzazione ai viaggi (ETIAS) gli Stati membri ricevono un importo aggiuntivo di 96,5 milioni di EUR rispetto all’importo di base, che assegnano interamente all’ETIAS per garantirne lo sviluppo rapido ed efficace in coerenza con l’attuazione del sistema centrale ETIAS secondo quanto previsto nel regolamento (UE) 2018/1240 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*2</span>\n).</div>\n</div>"]]}, "80": {"label": "Articolo 80", "heading": "Modifiche del regolamento (UE) 2016/399", "anchor": "art_80", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) 2016/399 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 6, paragrafo 1, è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera b) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">essere in possesso di un visto valido, se richiesto a norma del regolamento (CE) n. 539/2001 del Consiglio (\n<span class=\"superscript\">*3</span>\n), o di un’autorizzazione ai viaggi valida, se richiesto a norma del regolamento (UE) 2018/1240 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*4</span>\n), salvo che si sia in possesso di un permesso di soggiorno o di un visto per soggiorni di lunga durata in corso di validità;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono aggiunti i commi seguenti:</p>\n<p class=\"norm\">«Per un periodo transitorio stabilito a norma dell’articolo 83, paragrafi 1 e 2, del regolamento (UE) 2018/1240, l’uso del sistema europeo di informazione e autorizzazione ai viaggi (ETIAS) è facoltativo e non si applica l’obbligo di essere in possesso di un’autorizzazione ai viaggi valida si cui alla lettera b) del primo comma del presente paragrafo. Gli Stati membri informano i cittadini di paesi terzi soggetti all’obbligo dell’autorizzazione ai viaggi che attraversano le frontiere esterne dell’obbligo di possedere un’autorizzazione ai viaggi valida a partire dalla scadenza del periodo transitorio. A tale scopo, gli Stati membri distribuiscono, a questa categoria di viaggiatori, l’opuscolo comune di cui all’articolo 83, paragrafo 2, del regolamento (UE) 2018/1240.</p>\n<p class=\"norm\">Durante il periodo di tolleranza di cui all’articolo 83, paragrafo 3, del regolamento (UE) 2018/1240, le autorità di frontiera autorizzano eccezionalmente i cittadini di paesi terzi soggetti all’obbligo dell’autorizzazione ai viaggi che non ne sono in possesso ad attraversare le frontiere esterne se ricorrono tutte le rimanenti condizioni di cui al presente articolo purché attraversino le frontiere esterne degli Stati membri per la prima volta dal termine del periodo transitorio di cui all’articolo 83, paragrafi 1 e 2, del regolamento (UE) 2018/1240. Le autorità di frontiera informano tali cittadini di paesi terzi dell’obbligo di essere in possesso di un’autorizzazione ai viaggi valida conformemente al presente articolo. A tale scopo, le autorità di frontiera distribuiscono, a questi viaggiatori, un opuscolo comune a norma dell’articolo 83, paragrafo 3, del regolamento (UE) 2018/1240 per informarli che sono eccezionalmente autorizzati ad attraversare le frontiere esterne pur non adempiendo all’obbligo di essere in possesso di un’autorizzazione ai viaggi valida e per spiegare tale obbligo.».</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 8, paragrafo 3, è così modificato:</p>\n<p class=\"modref\">\n▼C1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alla lettera a), il punto ii) è sostituito dal seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accertamento che il documento di viaggio sia provvisto, all’occorrenza, del visto, dell’autorizzazione ai viaggi o del permesso di soggiorno richiesti.»</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserita la lettera seguente:</p>\n<div style=\"margin-left: 48pt; text-indent: -48pt\">\n<p class=\"norm\">«b bis)<span style=\"word-spacing: NaNpt\"> </span>Se il cittadino di paese terzo è in possesso di un’autorizzazione ai viaggi ai sensi dell’articolo 6, paragrafo 1, lettera b), del presente regolamento, le verifiche approfondite all’ingresso comprendono anche l’accertamento dell’autenticità, della validità e dello status dell’autorizzazione ai viaggi e, se applicabile, dell’identità del relativo titolare, mediante consultazione dell’ETIAS in conformità dell’articolo 47 del regolamento (UE) 2018/1240. Qualora sia tecnicamente impossibile procedere alla consultazione o all’interrogazione di cui all’articolo 47, paragrafi 1 e 2, del regolamento (UE) 2018/1240, si applica l’articolo 48, paragrafo 3, di tale regolamento.»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’allegato V, parte B, nel modello uniforme di provvedimento di respingimento alla frontiera, la lettera C) nell’elenco dei motivi del respingimento è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«C) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Sprovvisto/а di visto valido, di autorizzazione ai viaggi valida o di permesso di soggiorno valido.».</p>\n</div>\n</div>\n</div>\n</div>"]]}, "81": {"label": "Articolo 81", "heading": "Modifiche del regolamento (UE) 2016/1624", "anchor": "art_81", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) n. 2016/1624 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 8, paragrafo 1, è inserita la lettera seguente:</p>\n<div style=\"margin-left: 48pt; text-indent: -48pt\">\n<p class=\"norm\">«q bis)<span style=\"word-spacing: NaNpt\"> </span>adempie i compiti e gli obblighi affidati all’Agenzia europea della guardia di frontiera e costiera di cui al regolamento (UE) 2018/1240 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*5</span>\n) e assicura l’istituzione e il funzionamento dell’unità centrale ETIAS in conformità dell’articolo 7 di detto regolamento.</p>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al capo II è aggiunta la sezione seguente:</p>\n<p class=\"title-division-1\">\n                                             «\n                                             <span class=\"expanded\">sezione 5</span>\n</p>\n<p class=\"title-division-2\">\n<span class=\"boldface\">\n<span class=\"expanded\">ETIAS</span>\n</span>\n</p>\n<p class=\"title-article-quoted\">Articolo 33 <span class=\"norm\">bis</span>\n</p>\n<p class=\"stitle-article-quoted\">Istituzione dell’unità centrale ETIAS</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È istituita un’unità centrale ETIAS.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’Agenzia europea della guardia di frontiera e costiera provvede all’istituzione e al funzionamento dell’unità centrale ETIAS in conformità dell’articolo 7 del regolamento (UE) 2018/1240 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*6</span>\n).</div>\n</div>\n</div>\n</div>"]]}, "82": {"label": "Articolo 82", "heading": "Modifiche del regolamento (UE) 2017/2226", "anchor": "art_82", "frags": [[null, "<p class=\"norm\">All’articolo 64 del regolamento (UE) 2017/2226 è aggiunto il paragrafo seguente:</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">«5.  </span>\n<div class=\"norm inline-element\">I finanziamenti della dotazione di cui all’articolo 5, paragrafo 5, lettera b), del regolamento (UE) n. 515/2014 da mobilitare per coprire le spese di cui ai paragrafi da 1 a 4 del presente articolo sono attuati mediante gestione indiretta per quanto riguarda le spese sostenute da eu-LISA e mediante gestione concorrente per quanto riguarda le spese sostenute dagli Stati membri.».</div>\n</div>"]]}, "83": {"label": "Articolo 83", "heading": "Periodo transitorio e misure transitorie", "anchor": "art_83", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per un periodo di sei mesi dall’entrata in funzione dell’ETIAS, l’uso dell’ETIAS è facoltativo e non si applica l’obbligo di essere in possesso di un’autorizzazione ai viaggi valida. La Commissione può adottare un atto delegato conformemente all’articolo 89 per disporre una proroga di tale periodo di sei mesi al massimo, rinnovabile una volta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Durante il periodo di cui al paragrafo 1, gli Stati membri informano i cittadini di paesi terzi soggetti all’obbligo dell’autorizzazione ai viaggi che attraversano le frontiere esterne dell’obbligo di possedere un’autorizzazione ai viaggi valida a partire dalla scadenza del periodo di sei mesi. A tale scopo gli Stati membri distribuiscono un opuscolo comune a questa categoria di viaggiatori. L’opuscolo è reso disponibile anche presso i consolati degli Stati membri nei paesi i cui cittadini rientrano nell’ambito di applicazione del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Al termine del periodo di cui al paragrafo 1 del presente articolo si applica un periodo di tolleranza di sei mesi. Durante tale periodo di tolleranza si applica l’obbligo di essere in possesso di un’autorizzazione ai viaggi valida. Durante il periodo di tolleranza le autorità di frontiera autorizzano eccezionalmente i cittadini di paesi terzi soggetti all’obbligo dell’autorizzazione ai viaggi che non ne sono in possesso ad attraversare le frontiere esterne se ricorrono tutte le rimanenti condizioni di cui all’articolo 6, paragrafo 1, del regolamento (UE) 2016/399, purché attraversino le frontiere esterne degli Stati membri per la prima volta dal termine del periodo di cui al paragrafo 1 del presente articolo. Le autorità di frontiera informano tali cittadini di paesi terzi dell’obbligo di essere in possesso di un’autorizzazione ai viaggi valida conformemente all’articolo 6, paragrafo 1, lettera b), del regolamento (UE) 2016/399. A tale scopo, le autorità di frontiera distribuiscono, a tali viaggiatori, un opuscolo comune per informarli che sono eccezionalmente autorizzati ad attraversare le frontiere esterne pur non adempiendo all’obbligo di essere in possesso di un’autorizzazione ai viaggi valida e per spiegare tale obbligo. La Commissione può adottare un atto delegato conformemente all’articolo 89 del presente regolamento per prorogare tale periodo di sei mesi al massimo.</div>\n</div>"], [null, "<p class=\"norm\">Durante il periodo di tolleranza, gli ingressi nei territori degli Stati membri in cui l’EES non è operativo non sono presi in considerazione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione, mediante atti di esecuzione, elabora i due opuscoli comuni di cui ai paragrafi 2 e 3 del presente articolo, contenenti almeno le informazioni di cui all’articolo 71. Gli opuscoli sono chiari, semplici e disponibili in almeno una delle lingue ufficiali di ciascun paese i cui cittadini rientrano nell’ambito di applicazione del presente regolamento. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 90, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Durante il periodo transitorio di cui ai paragrafi 1 e 2, del presente articolo, il sistema d’informazione ETIAS risponde all’interrogazione dei vettori di cui all’articolo 45, paragrafo 2, fornendo ai vettori una risposta «OK». Durante il periodo di tolleranza di cui al paragrafo 3 del presente articolo, la risposta inviata dal sistema d’informazione ETIAS all’interrogazione dei vettori prende in considerazione se il cittadino di un paese terzo attraversa le frontiere esterne degli Stati membri per la prima volta dal termine del periodo di cui al paragrafo 1 del presente articolo.</div>\n</div>"]]}, "84": {"label": "Articolo 84", "heading": "Uso dei dati per l’elaborazione di relazioni e statistiche", "anchor": "art_84", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il personale debitamente autorizzato delle autorità competenti degli Stati membri, della Commissione, di eu-LISA e dell’unità centrale ETIAS è abilitato a consultare i seguenti dati, unicamente per elaborare relazioni e statistiche e senza che sia possibile l’identificazione individuale e in conformità delle misure di salvaguardia relative alla non discriminazione di cui all’articolo 14:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sullo stato della domanda;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadinanza, sesso e anno di nascita del richiedente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">paese di residenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">istruzione (primaria, secondaria, superiore o nessuna istruzione);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attuale occupazione (gruppo di posizioni lavorative);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipo del documento di viaggio e codice a tre lettere del paese di rilascio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tipo di autorizzazione ai viaggi e, per le autorizzazioni ai viaggi con validità territoriale limitata di cui all’articolo 44, lo Stato membro o gli Stati membri di rilascio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">periodo di validità dell’autorizzazione ai viaggi; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">motivi del rifiuto, della revoca o dell’annullamento dell’autorizzazione ai viaggi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1 del presente articolo, eu-LISA conserva i dati di cui a tale paragrafo nell'archivio centrale di relazioni e statistiche di cui all'articolo 39 del regolamento (UE) 2019/817. Ai sensi dell'articolo 39, paragrafo 1, di tale regolamento, i dati statistici intersistemici e le relazioni analitiche permettono alle autorità elencate al paragrafo 1 del presente articolo di ottenere relazioni e dati statistici personalizzabili al fine di sostenere l'applicazione delle regole di screening ETIAS previste all'articolo 33, migliorare la valutazione dei rischi per la sicurezza, di immigrazione illegale e di alto rischio epidemico, migliorare l'efficienza delle verifiche di frontiera e assistere l'unità centrale ETIAS e le unità nazionali ETIAS nel trattamento delle domande di autorizzazione ai viaggi.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">La Commissione adotta, mediante atti di esecuzione, le norme dettagliate concernenti il funzionamento dell’archivio centrale e le norme sulla protezione e la sicurezza dei dati applicabili all’archivio. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 90, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le procedure poste in essere da eu-LISA per monitorare lo sviluppo e il funzionamento del sistema d’informazione ETIAS di cui all’articolo 92, paragrafo 1, comprendono la possibilità di produrre statistiche periodiche per garantire tale monitoraggio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ogni trimestre eu-LISA pubblica statistiche relative al sistema d’informazione ETIAS in cui figurano, in particolare, il numero e la cittadinanza dei richiedenti a cui è stata rilasciata o rifiutata un’autorizzazione ai viaggi, compresi i motivi del rifiuto, e dei cittadini di paesi terzi la cui autorizzazione ai viaggi è stata annullata o revocata.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<p class=\"norm\">Le statistiche giornaliere sono conservate nell'archivio centrale di relazioni e statistiche di cui all'articolo 39 del regolamento (UE) 2019/817.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Alla fine di ogni anno i dati statistici sono raccolti in una relazione annuale relativa all’anno in questione. La relazione è pubblicata e trasmessa al Parlamento europeo, al Consiglio, alla Commissione, al Garante europeo della protezione dei dati, all’Agenzia europea della guardia di frontiera e costiera e alle autorità nazionali di controllo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Su richiesta della Commissione, eu-LISA le fornisce statistiche su aspetti specifici connessi all’attuazione del presente regolamento nonché le statistiche di cui al paragrafo 3.</div>\n</div>"]]}, "85": {"label": "Articolo 85", "heading": "Spese", "anchor": "art_85", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le spese sostenute per lo sviluppo del sistema d’informazione ETIAS, per l’integrazione delle esistenti infrastrutture nazionali di frontiera e per la connessione all’interfaccia uniforme nazionale, per ospitare l’interfaccia uniforme nazionale e per istituire l’unità centrale ETIAS e le unità nazionali ETIAS sono a carico del bilancio generale dell’Unione.</div>\n</div>"], [null, "<p class=\"norm\">eu-LISA presta particolare attenzione al rischio di aumento dei costi e assicura un monitoraggio sufficiente dei contraenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le spese per il funzionamento dell’ETIAS sono a carico del bilancio generale dell’Unione. Ciò vale anche per le spese di funzionamento e di manutenzione del sistema di informazione ETIAS, compresa l’IUN, le spese di funzionamento dell’unità centrale ETIAS e le spese per personale e attrezzature tecniche (hardware e software) necessarie all’adempimento dei compiti delle unità nazionali ETIAS, nonché i costi di traduzione di cui all’articolo 27, paragrafi 2 e 8.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Sono esclusi i costi seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ufficio di gestione di progetto degli Stati membri (riunioni, missioni, uffici);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’hosting dei sistemi informatici nazionali (spazio, implementazione, elettricità, impianti di raffreddamento);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la gestione dei sistemi informatici nazionali (operatori e contratti di assistenza);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la progettazione, lo sviluppo, l’implementazione, il funzionamento e la manutenzione di reti di comunicazione nazionali.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I costi di funzionamento dell’ETIAS includono inoltre il sostegno finanziario destinato agli Stati membri per le spese sostenute ai fini dell’adattamento e dell’automatizzazione delle verifiche di frontiera per attuare l’ETIAS. L’importo complessivo di tale sostegno finanziario è limitato a un massimo di 15 milioni di EUR per il primo anno di funzionamento, a un massimo di 25 milioni di EUR per il secondo anno di funzionamento e a un massimo di 50 milioni di EUR all’anno per i successivi anni di funzionamento. La Commissione adotta atti delegati conformemente all’articolo 89 per definire ulteriormente tale sostegno finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’Agenzia europea della guardia di frontiera e costiera, eu-LISA ed Europol ricevono adeguati finanziamenti supplementari e personale aggiuntivo necessari per l’esecuzione dei compiti ad essi affidati ai sensi del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I finanziamenti della dotazione di cui all’articolo 5, paragrafo 5, lettera b), del regolamento (UE) n. 515/2014 da mobilitare per coprire le spese di attuazione del presente regolamento di cui ai paragrafi da 1 a 4 del presente articolo sono attuati mediante gestione indiretta per quanto riguarda le spese sostenute da eu-LISA e dall’Agenzia europea della guardia di frontiera e costiera e mediante gestione concorrente per quanto riguarda le spese sostenute dagli Stati membri.</div>\n</div>"]]}, "86": {"label": "Articolo 86", "heading": "Entrate", "anchor": "art_86", "frags": [[null, "<p class=\"norm\">Le entrate generate dall’ETIAS costituiscono entrate con destinazione specifica interne ai sensi dell’articolo 21, paragrafo 4, del regolamento (UE, Euratom) n. 966/2012 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">20</span>\n). Esse sono destinate a coprire le spese di funzionamento e di manutenzione dell’ETIAS. Le entrate residue dopo la copertura di tali costi sono assegnate al bilancio dell’Unione.</p>"]]}, "87": {"label": "Articolo 87", "heading": "Notifiche", "anchor": "art_87", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri comunicano alla Commissione l’autorità considerata titolare del trattamento di cui all’articolo 57.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’unità centrale ETIAS e gli Stati membri comunicano alla Commissione e a eu-LISA le autorità competenti di cui all’articolo 13 che hanno accesso al sistema d’informazione ETIAS.</div>\n</div>"], [null, "<p class=\"norm\">Tre mesi dopo l’entrata in funzione dell’ETIAS ai sensi dell’articolo 88, eu-LISA pubblica nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> un elenco consolidato di tali autorità. Gli Stati membri comunicano alla Commissione e a eu-LISA senza indugio anche ogni modifica relativa a tali autorità. In caso di tali modifiche, eu-LISA pubblica una volta all’anno una versione consolidata aggiornata di tali informazioni. eu-LISA mantiene continuamente aggiornato il sito web pubblico che contiene tali informazioni.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli Stati membri comunicano alla Commissione e a eu-LISA le loro autorità designate e i loro punti di accesso centrale di cui all’articolo 50 e comunicano senza indugio ogni relativa modifica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">eu-LISA comunica alla Commissione il positivo completamento del collaudo di cui all’articolo 88, paragrafo 1, lettera e).</div>\n</div>"], [null, "<p class=\"norm\">La Commissione pubblica le informazioni di cui ai paragrafi 1 e 3 nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>. Se sono modificate, la Commissione pubblica una volta all’anno una versione consolidata aggiornata di tali informazioni. La Commissione mantiene continuamente aggiornato il sito web pubblico che contiene tali informazioni.</p>"]]}, "88": {"label": "Articolo 88", "heading": "Entrata in funzione", "anchor": "art_88", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione determina la data a partire dalla quale l’ETIAS entra in funzione una volta che:</p>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano entrate in vigore le necessarie modifiche agli atti giuridici che istituiscono gli altri sistemi d’informazione dell’UE, volte a realizzare l’interoperabilità, ai sensi dell’articolo 11, con il sistema d’informazione ETIAS, ad eccezione della rifusione del regolamento (UE) n. 603/2013;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia entrato in vigore il regolamento che affida a eu-LISA la gestione operativa dell’ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano entrate in vigore le necessarie modifiche agli atti giuridici che istituiscono i sistemi d’informazione dell’UE di cui all’articolo 20, paragrafo 2, volte a fornire l’accesso a tali banche dati all’unità centrale ETIAS;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M2\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano state adottate le misure di cui all’articolo 11, paragrafi 9 e 10, all’articolo 15, paragrafo 5, all’articolo 17, paragrafi 3, 5 e 6, all’articolo 18, paragrafo 4, all’articolo 27, paragrafi 3 e 5, all’articolo 33, paragrafi 2 e 3, all’articolo 36, paragrafo 3, all’articolo 38, paragrafo 3, all’articolo 39, paragrafo 2, all’articolo 45, paragrafo 3, all’articolo 46, paragrafo 4, all’articolo 48, paragrafo 4, all’articolo 59, paragrafo 4, all’articolo 73, paragrafo 3, lettera b), all’articolo 83, paragrafi 1, 3 e 4 e all’articolo 85, paragrafo 3;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eu-LISA abbia dichiarato il positivo completamento di un collaudo generale dell’ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eu-LISA e l’unità centrale ETIAS abbiano convalidato le necessarie disposizioni tecniche e giuridiche per raccogliere e trasmettere al sistema centrale ETIAS i dati di cui all’articolo 17 e le abbiano comunicate alla Commissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli Stati membri e l’unità centrale ETIAS abbiano comunicato alla Commissione i dati relativi alle diverse autorità di cui all’articolo 87, paragrafi 1 e 3.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il collaudo dell’ETIAS di cui al paragrafo 1, lettera e), è effettuato da eu-LISA in cooperazione con gli Stati membri e l’unità centrale ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione informa il Parlamento europeo e il Consiglio dell’esito del collaudo effettuato in base al paragrafo 1, lettera e).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La decisione della Commissione di cui al paragrafo 1 è pubblicata nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e l’unità centrale ETIAS iniziano a utilizzare l’ETIAS a decorrere dalla data stabilita dalla Commissione ai sensi del paragrafo 1.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’interoperabilità, di cui all’articolo 11, con il sistema ECRIS-TCN ha inizio con l’entrata in funzione del CIR. L’ETIAS entra in funzione indipendentemente dalla realizzazione dell’interoperabilità con il sistema ECRIS-TCN.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’ETIAS entra in funzione indipendentemente dalla possibilità di interrogare le banche dati di Interpol di cui all’articolo 12.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "89": {"label": "Articolo 89", "heading": "Esercizio della delega", "anchor": "art_89", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all’articolo 6, paragrafo 4, all’articolo 11, paragrafo 9, all’articolo 17, paragrafi 3, 5, e 6, all’articolo 18, paragrafo 4, all’articolo 27, paragrafo 3, all’articolo 31, all’articolo 33, paragrafo 2, all’articolo 36, paragrafo 4, all’articolo 39, paragrafo 2, all’articolo 54, paragrafo 2, all’articolo 83, paragrafi 1 e 3, e all’articolo 85, paragrafo 3, è conferito alla Commissione per un periodo di cinque anni a decorrere dal 9 ottobre 2018. La Commissione elabora una relazione sulla delega di potere al più tardi nove mesi prima della scadenza del periodo di cinque anni. La delega di potere è tacitamente prorogata per periodi di identica durata, a meno che il Parlamento europeo o il Consiglio non si opponga a tale proroga al più tardi tre mesi prima della scadenza di ciascun periodo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui all’articolo 6, paragrafo 4, all’articolo11, paragrafo 9, all’articolo 17, paragrafi 3, 5 e 6, all’articolo 18, paragrafo 4, all’articolo 27, paragrafo 3, all’articolo 31, all’articolo 33, paragrafo 2, all’articolo 36, paragrafo 4, all’articolo 39, paragrafo 2, all’articolo 54, paragrafo 2, all’articolo 83, paragrafi 1 e 3, e all’articolo 85, paragrafo 3, può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Prima dell’adozione dell’atto delegato la Commissione consulta gli esperti designati da ciascuno Stato membro nel rispetto dei principi stabiliti nell’accordo interistituzionale «Legiferare meglio» del 13 aprile 2016.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’atto delegato adottato ai sensi dell’articolo 6, paragrafo 4, dell’articolo 11, paragrafo 9, dell’articolo 17, paragrafi 3, 5 o 6, dell’articolo 18, paragrafo 4, dell’articolo 27, paragrafo 3, dell’articolo 31, dell’articolo 33, paragrafo 2, dell’articolo 36, paragrafo 4, dell’articolo 39, paragrafo 2, dell’articolo 54, paragrafo 2, dell’articolo 83, paragrafi 1 o 3, o dell’articolo 85, paragrafo 3, entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "90": {"label": "Articolo 90", "heading": "Procedura di comitato", "anchor": "art_90", "frags": [[null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita dal comitato istituito dall’articolo 68 del regolamento (UE) 2017/2226. Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 5 del regolamento (UE) n. 182/2011. Qualora il comitato non esprima alcun parere, la Commissione non adotta il progetto di atto di esecuzione e si applica l’articolo 5, paragrafo 4, terzo comma, del regolamento (UE) n. 182/2011.</div>\n</div>"]]}, "91": {"label": "Articolo 91", "heading": "Gruppo consultivo", "anchor": "art_91", "frags": [[null, "<p class=\"norm\">Le competenze del gruppo consultivo EES sono estese per comprendere l’ETIAS. Tale gruppo consultivo EES-ETIAS fornisce a eu-LISA la competenza tecnica relativa all’ETIAS, in particolare nel contesto della preparazione del programma di lavoro annuale e della relazione annuale di attività.</p>"]]}, "92": {"label": "Articolo 92", "heading": "Monitoraggio e valutazione", "anchor": "art_92", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">eu-LISA provvede affinché siano istituite procedure per monitorare lo sviluppo del sistema d’informazione ETIAS rispetto agli obiettivi relativi alla pianificazione e ai costi, nonché per monitorare il funzionamento dell’ETIAS rispetto agli obiettivi prefissati in termini di risultati tecnici, di rapporto costi/benefici, di sicurezza e di qualità del servizio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 10 aprile 2019 e successivamente ogni sei mesi durante la fase di sviluppo del sistema d’informazione ETIAS, eu-LISA presenta al Parlamento europeo e al Consiglio una relazione sulla situazione dello sviluppo del sistema centrale ETIAS, delle IUN e dell’infrastruttura di comunicazione tra il sistema centrale ETIAS e le IUN. La relazione include informazioni dettagliate sui costi sostenuti e informazioni sui rischi che possono incidere sui costi complessivi del sistema che sono a carico del bilancio generale dell’Unione a norma dell’articolo 85.</div>\n</div>"], [null, "<p class=\"norm\">Entro il 10 aprile 2019 e successivamente ogni sei mesi durante la fase di sviluppo del sistema d’informazione ETIAS, Europol e l’Agenzia europea della guardia di frontiera e costiera presentano al Parlamento europeo e al Consiglio una relazione sullo stato di preparazione all’attuazione del presente regolamento, che includa informazioni dettagliate sui costi sostenuti e informazioni sui rischi che possono incidere sui costi complessivi del sistema che sono a carico del bilancio generale dell’Unione a norma dell’articolo 85.</p>"], [null, "<p class=\"norm\">Una volta che lo sviluppo è completato, eu-LISA presenta al Parlamento europeo e al Consiglio una relazione che illustra nel dettaglio il modo in cui sono stati conseguiti gli obiettivi, in particolare quelli relativi alla pianificazione e ai costi, giustificando eventuali scostamenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini della manutenzione tecnica, eu-LISA ha accesso alle informazioni necessarie riguardanti i trattamenti dei dati effettuati nel sistema d’informazione ETIAS.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Due anni dopo l’entrata in funzione dell’ETIAS, e successivamente ogni due anni, eu-LISA presenta al Parlamento europeo, al Consiglio e alla Commissione una relazione sul funzionamento tecnico del sistema d’informazione ETIAS, compresa la sua sicurezza, nonché dati statistici relativi all’elenco di controllo ETIAS secondo la procedura di riesame di cui all’articolo 35, paragrafi 5 e 6.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Tre anni dopo l’entrata in funzione dell’ETIAS, e successivamente ogni quattro anni, la Commissione effettua una valutazione dell’ETIAS e formula le necessarie raccomandazioni al Parlamento europeo e al Consiglio. Tale valutazione comprende:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’interrogazione delle banche dati di Interpol SLTD e TDAWN attraverso l’ETIAS, comprese informazioni sul numero di riscontri positivi rispetto alle banche dati di Interpol, sul numero di autorizzazioni ai viaggi rifiutate a seguito di tali riscontri positivi e informazioni su eventuali problemi incontrati e, se del caso, una valutazione della necessità di una proposta legislativa di modifica del presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i risultati conseguiti dall’ETIAS in relazione ai suoi obiettivi, al suo mandato e ai suoi compiti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’incidenza, l’efficacia e l’efficienza dell’ETIAS e delle sue prassi di lavoro alla luce dei suoi obiettivi, mandato e compiti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una valutazione della sicurezza dell’ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le regole di esame ETIAS usate ai fini della valutazione del rischio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’impatto dell’elenco di controllo ETIAS, incluso il numero delle domande di autorizzazione ai viaggi rifiutate per motivi che abbiano tenuto conto di un riscontro positivo con l’elenco di controllo ETIAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’eventuale necessità di modificare il mandato dell’unità centrale ETIAS e le implicazioni finanziarie di una tale modifica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’impatto sui diritti fondamentali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’impatto sulle relazioni diplomatiche tra l’Unione e i paesi terzi coinvolti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entrate generate dai diritti per l’autorizzazione ai viaggi, i costi sostenuti in relazione allo sviluppo dell’ETIAS, le spese per il funzionamento dell’ETIAS, i costi sostenuti da eu-LISA, da Europol e dall’Agenzia europea della guardia di frontiera e costiera in relazione alle loro funzioni a norma del presente regolamento, nonché le eventuali entrate assegnate a norma dell’articolo 86;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’uso dell’ETIAS a fini di contrasto sulla base delle informazioni di cui al paragrafo 8 del presente articolo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richiedenti convocati per un colloquio e la percentuale che tale numero rappresenta sul totale dei richiedenti, i motivi della richiesta di un colloquio, il numero di colloqui a distanza, il numero di decisioni a seguito delle quali l’autorizzazione ai viaggi è stata concessa, è stata concessa con l’apposizione di un indicatore o è stata rifiutata, il numero di richiedenti invitati a un colloquio che non si sono presentati nonché, se del caso, una valutazione della necessità di una proposta legislativa di modifica del presente regolamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La Commissione trasmette la relazione di valutazione al Parlamento europeo, al Consiglio, al Garante europeo della protezione dei dati e all’Agenzia dell’Unione europea per i diritti fondamentali.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Un anno dopo la fine del periodo di transizione di cui all’articolo 83, paragrafo 1, e successivamente ogni quattro anni, la Commissione valuta l’interrogazione di ECRIS-TCN attraverso il sistema centrale ETIAS. La Commissione trasmette tali valutazioni, unitamente al parere della commissione di orientamento sui diritti fondamentali dell’ETIAS e ad eventuali raccomandazioni necessarie, al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Al fine di valutare in che misura l’interrogazione del sistema ECRIS-TCN attraverso il sistema centrale ETIAS abbia contribuito al conseguimento dell’obiettivo dell’ETIAS, le valutazioni di cui al primo comma comprendono:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un confronto del numero di riscontri positivi simultanei, per la stessa domanda, in ECRIS-TCN relativi alle condanne per reati di terrorismo di cui all’allegato al presente regolamento e nel SIS relativamente alle segnalazioni ai fini del rifiuto d’ingresso e di soggiorno;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un confronto del numero di riscontri positivi simultanei, per la stessa domanda, in ECRIS-TCN relativi a qualsiasi altro reato di cui all’allegato al presente regolamento e nel SIS relativamente alle segnalazioni ai fini del rifiuto d’ingresso e di soggiorno;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le domande il cui unico riscontro positivo è in ECRIS-TCN, un confronto tra il numero di rifiuti di autorizzazioni di viaggio e il numero totale di riscontri positivi emersi dall’interrogazione di ECRIS-TCN.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">La commissione di orientamento sui diritti fondamentali dell’ETIAS esprime pareri in merito alle valutazioni di cui al presente paragrafo.</p>"], [null, "<p class=\"norm\">Le valutazioni possono, se necessario, essere corredate di proposte legislative.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli Stati membri ed Europol comunicano a eu-LISA, all’unità centrale ETIAS e alla Commissione le informazioni necessarie per redigere le relazioni di cui ai paragrafi 4 e 5. Tali informazioni non mettono a repentaglio i metodi di lavoro né comprendono indicazioni sulle fonti, sui membri del personale o sulle indagini delle autorità designate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">eu-LISA e l’unità centrale ETIAS comunicano alla Commissione le informazioni necessarie per redigere le valutazioni di cui al paragrafo 5.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel rispetto delle disposizioni del diritto nazionale relative alla pubblicazione di informazioni sensibili, ciascuno Stato membro ed Europol predispongono una relazione annuale sull’efficacia dell’accesso ai dati conservati nel sistema centrale ETIAS a fini di contrasto, in cui figurino informazioni e statistiche su:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo scopo esatto della consultazione, compreso il tipo di reato di terrorismo o altro reato grave;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i fondati motivi addotti per il sospetto fondato che l’autore presunto o effettivo oppure la vittima rientri nell’ambito di applicazione del presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero delle richieste di accesso al sistema centrale ETIAS a fini di contrasto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero e il tipo di casi in cui si è giunti a riscontri positivi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero e il tipo di casi in cui è stata utilizzata la procedura d’urgenza di cui all’articolo 51, paragrafo 4, compresi i casi in cui il punto di accesso centrale non ha confermato l’urgenza dopo la verifica a posteriori.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Una soluzione tecnica è messa a disposizione degli Stati membri per agevolare la raccolta di tali dati a norma del capo IX ai fini dell’elaborazione delle statistiche di cui al presente paragrafo. La Commissione, mediante atti di esecuzione, adotta le specifiche della soluzione tecnica. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 90, paragrafo 2.</p>"]]}, "93": {"label": "Articolo 93", "heading": "Manuale pratico", "anchor": "art_93", "frags": [[null, "<p class=\"norm\">La Commissione, in stretta cooperazione con gli Stati membri e le agenzie competenti dell’Unione, mette a disposizione un manuale pratico contenente orientamenti, raccomandazioni e buone prassi per l’attuazione del presente regolamento. Il manuale pratico tiene conto dei manuali pertinenti esistenti. La Commissione adotta il manuale pratico sotto forma di raccomandazione.</p>"]]}, "94": {"label": "Articolo 94", "heading": "Ceuta e Melilla", "anchor": "art_94", "frags": [[null, "<p class=\"norm\">Il presente regolamento non pregiudica il regime specifico che si applica alle città di Ceuta e Melilla, quale definito nella dichiarazione del Regno di Spagna relativa alle città di Ceuta e Melilla di cui all’atto finale dell’accordo di adesione del Regno di Spagna alla convenzione di applicazione dell’accordo di Schengen del 14 giugno 1985.</p>"]]}, "95": {"label": "Articolo 95", "heading": "Contributo finanziario dei paesi associati all’attuazione, all’applicazione e allo sviluppo dell ’acquis di Schengen", "anchor": "art_95", "frags": [[null, "<p class=\"norm\">In base alle pertinenti disposizioni dei rispettivi accordi di associazione, sono presi accordi relativi ai contributi finanziari dei paesi associati all’attuazione, all’applicazione e allo sviluppo dell’acquis di Schengen.</p>"]]}, "96": {"label": "Articolo 96", "heading": "Entrata in vigore e applicazione", "anchor": "art_96", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</p>"], [null, "<p class=\"norm\">Il presente regolamento si applica a decorrere dalla data stabilita dalla Commissione in conformità dell’articolo 88, ad eccezione degli articoli 6, 11, 12, 33, 34, 35, 59, 71, 72, 73, degli articoli da 75 a 79, degli articoli 82, 85, 87, 89, 90, 91, dell’articolo 92, paragrafi 1 e 2, degli articoli 93 e 95 nonché delle disposizioni relative alle misure di cui all’articolo 88, paragrafo 1, lettera d), che si applicano a decorrere dal 9 ottobre 2018.</p>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<p class=\"norm\">L’articolo 11 <span class=\"italics\">ter</span> si applica a decorrere dal 3 agosto 2021.</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p class=\"norm\">Le disposizioni relative alla consultazione dell’Eurodac sia applicano a decorrere dalla data in cui la rifusione del regolamento (UE) n. 603/2013 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">21</span>\n) diventa applicabile.</p>"]]}}, "recitals": {}};